-- Poems batch 172
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5f602908-84eb-48b3-aa9b-e8edcc106fb0','和聖俞唐書局後叢莽中得芸香一本之作用其韻','歐陽修','宋','宋诗','song-poetry','','[]','有芸黄其華，在彼眾草中。',108,'全唐诗/poet.song.17000.json','["有芸黄其華，在彼眾草中。", "清香濯曉露，秀色摇春風。", "幸依華堂陰，一顧曾不蒙。", "大雅彼君子，偶來從學宮。", "文章高一世，論議伏羣公。", "多識由博學，新篇匪雕蟲。", "唱酬爛眾作，當輝發幽叢。", "在物苟有用，得時寧久窮。", "可嗟凡草木，糞壤自青紅。"]'),
('d2cc622b-2687-4fcc-aab7-63328d68b853','答劉原父舍人見過後中夜酒定復追昨日所覽雜記并簡梅聖俞之作','歐陽修','宋','宋诗','song-poetry','','[]','君子忽我顧，貧家復何有。',72,'全唐诗/poet.song.17000.json','["君子忽我顧，貧家復何有。", "虛堂來清風，佳果薦燭酒。", "簡編記遺逸，論議相可否。", "欲知所書人，其骨多已朽。", "前者既已然，後來寧得久。", "所以昔人云，杯行莫停手。"]'),
('9a47ba05-7878-42f6-9740-964e38e9a872','有贈余以端谿綠石枕與蘄州竹簟皆佳物也余既喜睡而得此二者不勝其樂奉呈原父舍人聖俞直講','歐陽修','宋','宋诗','song-poetry','','[]','端谿琢出缺月樣，蘄州織成雙水紋。',288,'全唐诗/poet.song.17000.json','["端谿琢出缺月樣，蘄州織成雙水紋。", "呼兒置枕展方簟，赤日正午天無雲。", "黄琉璃光綠玉潤，瑩浄冷滑無埃塵。", "憶昨開封暫陳力，屢乞殘骸避煩劇。", "聖君哀憐大臣閔，察見衰病非虛飾。", "猶蒙不使如罪去，特許遷官還舊職。", "選材臨事不堪用，見利無慙惟苟得。", "一從僦舍居城南，官不坐曹門少客。", "自然唯與睡相宜，以懶遭閑何愜適。", "從來羸茶苦疲困，況此煩羣正炎赫。", "少壯喘息人莫聽，中年鼻鼾尤惡聲。", "癡兒掩耳謂雷作，竈婦驚窺疑釜鳴。", "蒼蠅蠛蠓任緣撲，蠹書懶架拋縱橫。", "神昏氣燭一如此，言語思慮何由清。", "嘗聞李白好飲酒，欲與鐺杓同生死。", "我今好睡又過之，身與二物爲三爾。", "江西得請在旦暮，收拾歸裝從此始。", "終當卷簟携枕去，筑室買田清潁尾。"]'),
('9f529e38-bd48-4a8c-a51d-a5ad110f571a','夜聞風聲有感奉呈原父舍人聖俞直講','歐陽修','宋','宋诗','song-poetry','','[]','夜半羣動息，有風生樹端。',168,'全唐诗/poet.song.17000.json','["夜半羣動息，有風生樹端。", "颯然飄我衣，起坐爲長歎。", "苦暑君勿厭，初凉君勿歡。", "暑在物猶盛，凉歸歲將寒。", "清霜忽以飛，零露亦漙漙。", "霜露本無情，豈肯私蕙蘭。", "不獨草木爾，君形安得完。", "櫛髮變新白，鑑容銷故丹。", "風埃共侵迫，心志亦摧殘。", "萬古一飛隼，兩曜雙跳丸。", "擾擾賢與愚，流沙逐驚湍。", "其來固如此，獨久知誠難。", "服食爲藥悞，此言真不刊。", "但當飲美酒，何必被輕紈。"]'),
('a6a76e90-69db-47cd-ac2d-a2493c0bf11f','答梅聖俞大雨見寄','歐陽修','宋','宋诗','song-poetry','','[]','夕雲若頹山，夜雨如决渠。',288,'全唐诗/poet.song.17000.json','["夕雲若頹山，夜雨如决渠。", "俄然見青天，燄燄升蟾蜍。", "倏忽陰氣生，四面如吹噓。", "狂雷走昏黑，驚電照夔魖。", "搜尋起龍蟄，下擊墓與墟。", "雷聲每軒轟，雨勢隨疾徐。", "初若浩莫止，俄收閴無餘。", "但掛千丈虹，紫翠橫空虛。", "頃刻百變態，晦明誰卷舒。", "豈知下土人，水潦沒襟裾。", "擾擾泥淖中，無異鴨與豬。", "嗟我來京師，庇身無弊廬。", "閑坊僦古屋，卑陋雜里閭。", "鄰注湧溝竇，街流溢庭除。", "出門愁浩渺，閉戶恐爲潴。", "牆壁豁四達，幸家無貯儲。", "蝦蟇鳴竈下，老婦但欷歔。", "九門絕來薪，朝爨欲毀車。", "壓溺委性命，焉能顧圖書。", "乃知生堯時，未免憂爲魚。", "梅子猶念我，寄聲憂我居。", "慰我以新篇，琅琅比瓊琚。", "官閑行能薄，補益愧空疎。", "歲月行晚矣，江湖盍歸歟。"]'),
('a7262a41-abd6-47a1-8b07-f119871a9f40','答聖俞白鸚鵡雜言','歐陽修','宋','宋诗','song-poetry','','[]','憶昨滁山之人贈我玉兔子，粵明年春玉兔死。',278,'全唐诗/poet.song.17000.json','["憶昨滁山之人贈我玉兔子，粵明年春玉兔死。", "日陽晝出月夜明，世言兔子望月生。", "謂此瑩然而白者，譬夫水之爲雪而爲冰，皆得一陰凝結之純精。", "常恨處非大荒窮北極寒之曠野，養違其性夭厥齡。", "豈知火維地荒絕，漲海連天沸天熱。", "黄冠黑距人語言，有鳥玉衣尤皎潔。", "乃知物生天地中，萬殊難以一理通。", "海中洲島窮人迹，來市廣州纔八國。", "其間注輦來最稀，此鳥何年隨海舶。", "誰能徧歷海上峯，萬怪千奇安可極。", "兔生明月月在天，玉兔不能久人間。", "況爾來從炎瘴地，豈識中州霜雪寒。", "渴雖有飲饑有啄，羈紲終知非爾樂。", "天高海闊路茫茫，嗟爾身微羽毛弱。", "爾能識路知所歸，吾欲開籠縱爾飛。", "俾爾歸詫宛陵詩，此老詩名聞四夷。"]'),
('50213512-d3ed-477b-9e1a-636bb2df0127','清明前一日韓子華以靖節斜川詩見招遊李園既歸遂苦風雨三日不能出窮坐一室家人輩倒殘壺得酒數杯泥深道路無人行去市又遠索於筐筥得枯魚乾蝦數種彊飲疾醉昏然便寐既覺索然因書所見奉呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','少年喜追隨，老大厭諠譁。',168,'全唐诗/poet.song.17000.json','["少年喜追隨，老大厭諠譁。", "慙愧二三子，邀我行看花。", "花開豈不好，時節亦云嘉。", "因病既不飲，眾歡獨成嗟。", "管絃暫過耳，風雨愁還家。", "三日不出門，堆豗類寒鴉。", "妻兒强我飲，飣餖果與瓜。", "濁酒傾殘壺，枯魚雜乾蝦。", "小婢立我前，赤脚兩髻丫。", "軋軋鳴雙絃，正如艣嘔啞。", "坐令江湖心，浩蕩思無涯。", "寵祿不知報，鬢毛今已華。", "有田清潁間，尚可事桑麻。", "安得一黄犢，幅巾駕柴車。"]'),
('366d21d5-ef6b-4f06-8905-b09bda16cc9a','奉答原甫見過寵示之作','歐陽修','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','不作流水聲，行將二十年。',218,'全唐诗/poet.song.17000.json','["不作流水聲，行將二十年。", "吾生少賤足憂患，憶昔有罪初南遷。", "飛帆洞庭入白浪，墮淚三峽聽流泉。", "援琴寫得入此曲，聊以自慰窮山間。", "中間永陽亦如此，醉卧幽谷聽潺湲。", "自從還朝戀榮祿，不覺鬢髮俱凋殘。", "耳衰聽重手漸顫，自惜指法將誰傳。", "偶欣日色曝書畫，試拂塵埃張斷絃。", "嬌兒癡女遶翁膝，爭欲彊翁聊一彈。", "紫微閣老適我過，愛我指下聲泠然。", "戲君此是伯牙曲，自古常歎知音難。", "君雖不能琴，能得琴意斯爲賢。", "自非樂道甘寂寞，誰肯顧我相留連。", "興闌束带索馬去，却鎖塵匣包青氈。"]'),
('c12396fe-c63e-4e12-b459-0b0c62ca8785','會飲聖俞家有作兼呈原父景仁聖從','歐陽修','宋','宋诗','song-poetry','','[]','憶昨九日訪君時，正見階前兩叢菊。',192,'全唐诗/poet.song.17000.json','["憶昨九日訪君時，正見階前兩叢菊。", "愛之欲繞行百匝，庭下不能容我足。", "折花却坐時嗅之，已醉還家手猶馥。", "今朝我復到君家，兩菊階前猶對束。", "枯莖槁葉苦風霜，無復滿叢金間綠。", "京師誰家不種花，碧砌朱欄敞華屋。", "奈何來對兩枯株，共坐窮簷何局促。", "詩翁文字發天葩，豈比青紅凡草木。", "凡草開花數日間，天葩無根長在目。", "遂令我每飲君家，不覺長缾卧牆曲。", "坐中年少皆賢豪，莫怪我今雙鬢禿。", "須知朱顔不可恃，有酒當歡且相屬。"]'),
('2d5c4bd9-3268-4a1f-bec1-4acaadb90b0b','依韻奉酬聖俞二十五兄見贈之作','歐陽修','宋','宋诗','song-poetry','','[]','與君結交遊，我最先眾人。',144,'全唐诗/poet.song.17000.json','["與君結交遊，我最先眾人。", "我少既多難，君家常苦貧。", "今爲兩衰翁，髮白面亦皴。", "念在懷中玉，不及市上珉。", "珉賤易爲價，玉棄久埋塵。", "惟能吐文章，白虹射星辰。", "幸同居京城，遠不隔重闉。", "朝罷二三公，隨我如魚鱗。", "君聞我來喜，置酒留逡巡。", "不待玉人請，自脫頭上巾。", "歡情雖漸鮮，老意益相親。", "窮達何足道，古來茲理均。"]'),
('af5190a6-8c3b-4281-bf50-9125b1352f8a','小飲坐中贈別祖擇之赴陜府','歐陽修','宋','宋诗','song-poetry','','[]','明日君當千里行，今朝始共一罇酒。',144,'全唐诗/poet.song.17000.json','["明日君當千里行，今朝始共一罇酒。", "豈惟明日難重持，試思此會何嘗有。", "京師九衢十二門，車馬煌煌事奔走。", "花開誰得屢相過，盞到莫辭頻舉手。", "驩情落寞酒量減，置我不須論老朽。", "奈何公等氣方豪，雲夢正當吞八九。", "擇之名聲重當世，少也多奇晚方偶。", "西州政事藹風謠，右掖文章煥星斗。", "待君歸日我何爲，手把鋤犂汝陰叟。"]'),
('a84354b6-e7b9-4f7f-8b04-39f656528c49','奉答聖俞達頭魚之作','歐陽修','宋','宋诗','song-poetry','','[]','吾聞海之大，物類無窮極。',204,'全唐诗/poet.song.17000.json','["吾聞海之大，物類無窮極。", "蟲蝦淺水間，蠃蜆如山積。", "毛魚與鹿角，一龠數千百。", "收藏各有時，嗜好無南北。", "其微既若斯，其大有莫測。", "波濤浩渺中，島嶼生頃刻。", "俄而沒不見，始悟出背脊。", "有時隨潮來，暴死疑遭謫。", "海人相呼集，刀鋸爭剖析。", "骨節駭專車，鬚芒侔劒戟。", "腥聞數十里，餘臭久乃息。", "始知百川歸，固有含容德。", "潛奇與祕寶，萬狀不一識。", "嗟彼達頭微，誰傳到京國。", "乾枯少滋味，治洗費炮炙。", "聊茲知異物，豈足薦佳客。", "一旦辱君詩，虛名從此得。"]'),
('5af78398-0c95-465f-b0a1-c0e56d4761d2','送刁紡推官歸潤州','歐陽修','宋','宋诗','song-poetry','','[]','翹翹名家子，自少能慷慨。',120,'全唐诗/poet.song.17000.json','["翹翹名家子，自少能慷慨。", "嘗從幕府辟，躍馬臨窮塞。", "是時西邊兵，屢戰輒奔潰。", "歸來買良田，俛首學秉耒。", "家爲白酒醇，門掩青山對。", "優游可以老，世利何足愛。", "奈何從所知，又欲向并代。", "主人忽南遷，此計亦中悔。", "彼在吾往從，彼去吾亦退。", "與人交若此，可以言節槩。"]'),
('069b3480-d8ee-4429-b9e7-2ebb07117040','夜坐彈琴有感二首呈聖俞  其一','歐陽修','宋','宋诗','song-poetry','','[]','吾愛陶靖節，有琴常自隨。',60,'全唐诗/poet.song.17000.json','["吾愛陶靖節，有琴常自隨。", "無絃人莫聽，此樂有誰知。", "君子篤自信，眾人喜隨時。", "其中苟有得，外物竟何爲。", "寄謝伯牙子，何須鍾子期。"]'),
('8d62a619-c7d9-4a12-a945-1ce9aa2e8a2e','夜坐彈琴有感二首呈聖俞  其二','歐陽修','宋','宋诗','song-poetry','','[]','鍾子忽已死，伯牙其已乎。',84,'全唐诗/poet.song.17000.json','["鍾子忽已死，伯牙其已乎。", "絕絃謝世人，知音從此無。", "瓠巴魚自躍，此事見於書。", "師曠嘗一鼓，羣鶴舞空虛。", "吾恐二三說，其言皆過歟。", "不然古今人，愚智邈已殊。", "奈何人有耳，不及鳥與魚。"]'),
('399d994b-e90f-4802-9692-211ce47e00c1','二月雪','歐陽修','宋','宋诗','song-poetry','','[]','寧傷桃李花，無損杞與菊。',64,'全唐诗/poet.song.17000.json','["寧傷桃李花，無損杞與菊。", "杞菊吾所嗜，惟恐食不足。", "花開少年事，不入老夫目。", "老夫無遠慮，所急在口腹。", "風晴日暖雪初銷，踏泥自採籬邊綠。"]'),
('f58106b9-a5ad-479d-879e-514b7204b772','歸田四時樂春夏二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','春風二月三月時，農夫在田居者稀。',96,'全唐诗/poet.song.17000.json','["春風二月三月時，農夫在田居者稀。", "新陽晴暖動膏脈，野水泛灧生光輝。", "鳴鳩聒聒屋上啄，布穀翩翩桑下飛。", "碧山遠映丹杏發，青草暖眠黄犢肥。", "田家此樂知者誰，吾獨知之胡不歸。", "吾已買田清潁上，更欲臨流作釣磯。"]'),
('0d18e2cc-0bfd-4d1c-a90e-731633d10bd5','歸田四時樂春夏二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','南風原頭吹百草，草木叢深茅舍小。',96,'全唐诗/poet.song.17000.json','["南風原頭吹百草，草木叢深茅舍小。", "麥穗初齊稚子嬌，桑葉正肥蠶食飽。", "老翁但喜歲年熟，餉婦安知時節好。", "野棠棃密啼晚鶯，海石榴紅囀山鳥。", "田家此樂知者誰，我獨知之歸不早。", "乞身當及彊健時，顧我蹉跎已衰老。"]'),
('4d4fa5cb-d556-49bc-8b2f-72f351433474','明妃曲和王介甫作','歐陽修','宋','宋诗','song-poetry','','[]','胡人以鞍馬爲家，射獵爲俗。',141,'全唐诗/poet.song.17000.json','["胡人以鞍馬爲家，射獵爲俗。", "泉甘草美無常處，鳥驚獸駭爭馳逐。", "誰將漢女嫁胡兒，風沙無情貌如玉。", "身行不遇中國人，馬上自作思歸曲。", "推手爲琵却手琶，胡人共聽亦咨嗟。", "玉顔流落死天涯，琵琶却傳來漢家。", "漢宮爭按新聲譜，遺恨已深聲更苦。", "纖纖女手生洞房，學得琵琶不下堂。", "不識黄雲出塞路，豈知此聲能斷腸。"]'),
('dd38e30c-7d3d-4eff-959f-040f21056444','盆池','歐陽修','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','西江之水何悠哉，經歷灨石險且回。',240,'全唐诗/poet.song.17000.json','["西江之水何悠哉，經歷灨石險且回。", "餘波拗怒猶涵澹，奔濤擊浪常喧豗。", "有時夜上滕王閣，月照浄練無纖埃。", "楊闌左里在其北，無風浪起傳古來。", "老蛟深處厭窟穴，蛇身微行見者猜。", "呼龍瀝酒未及祝，五色粲爛高崔嵬。", "忽然遠引千丈去，百里水面中分開。", "收蹤滅跡莫知處，但有雨雹隨風雷。", "千奇萬變聊一戲，豈顧溺死爲可哀。", "輕人之命若螻螘，不止山嶽將傾頹。", "此外魚蝦何足道，厭飫但覺腥盤杯。", "壯哉豈不快耳目，胡爲守此空牆隈。", "陶盆斗水仍下漏，四岸久雨生莓苔。", "遊魚撥撥不盈寸，泥潛日炙愁暴鰓。", "魚誠不幸此跼促，我能决去反徘徊。"]'),
('559a26f9-36f6-4515-941f-a2eaebb31dc0','再和明妃曲','歐陽修','宋','宋诗','song-poetry','','[]','漢宮有佳人，天子初未識。',116,'全唐诗/poet.song.17000.json','["漢宮有佳人，天子初未識。", "一朝隨漢使，遠嫁單于國。", "絕色天下無，一失難再得。", "雖能殺畫工，於事竟何益。", "耳目所及尚如此，萬里安能制夷狄。", "漢計誠已拙，女色難自誇。", "明妃去時淚，灑向枝上花。", "狂風日暮起，飄泊落誰家。", "紅顔勝人多薄命，莫怨春風當自嗟。"]'),
('08680462-1e48-4864-86c7-4ffe138a48e0','奉送原甫侍讀出守永興','歐陽修','宋','宋诗','song-poetry','','[]','酌君以荆州魚枕之蕉，贈君以宣城鼠須之管。',108,'全唐诗/poet.song.17000.json','["酌君以荆州魚枕之蕉，贈君以宣城鼠須之管。", "酒如長虹飲滄海，筆若駿馬馳平坂。", "愛君尚少力方豪，嗟我信衰歡漸鮮。", "文章驚世知名早，意氣論交相得晚。", "魚枕蕉，一舉十分當覆盞。", "鼠須管，爲物雖微情不淺。", "新詩醉墨時一揮，別後寄我無辭遠。"]'),
('6a54a0c9-a086-46e5-8705-0a85a59df627','哭聖俞','歐陽修','宋','宋诗','song-poetry','','[]','昔逢詩老伊水頭，青衫白馬渡伊流。',264,'全唐诗/poet.song.17000.json','["昔逢詩老伊水頭，青衫白馬渡伊流。", "灘聲八節響石樓，坐中辭氣凌清秋。", "一飲百盞不言休，酒酣思逸語更遒。", "河南丞相稱賢侯，後車日載枚與鄒。", "我年最少力方優，明珠白璧相報投。", "詩成希深擁鼻謳，師魯卷舌藏戈矛。", "三十年間如轉眸，屈指十九歸山丘，凋零所餘身百憂。", "晚登玉墀侍珠旒，詩老齏鹽太學愁。", "乖離會合謂無由，此會天幸非人謀。", "頷鬚已白齒根浮，子年加我貌則不。", "歡猶可彊閑屢偷，不覺歲月成淹留。", "文章落筆動九州，釜甑過午無饙餾。", "良時易失不早收，篋櫝瓦礫遺琳璆。", "薦賢轉石古所尤，此事有職非吾羞。", "命也難知理莫求，名聲赫赫掩諸幽。", "翩然素旐歸一舟，送子有淚流如溝。"]'),
('a7fa2cae-9965-49b0-a187-cafe476fecc1','寄題劉著作羲叟家園效聖俞體','歐陽修','宋','宋诗','song-poetry','','[]','嘉子治新園，乃在太行谷。',132,'全唐诗/poet.song.17000.json','["嘉子治新園，乃在太行谷。", "山高地苦寒，當樹所宜木。", "羣花媚春陽，開落一何速。", "凜凜心節奇，惟應松與竹。", "毋栽當暑槿，寧種深秋菊。", "菊死抱枯枝，槿豔隨昏旭。", "黄楊雖可愛，南土氣常燠。", "未知經雪霜，果自保其綠。", "顔色苟不衰，始知根性足。", "此外眾草花，徒能悅凡目。", "千金買姚黄，慎勿同流俗。"]'),
('72114aa2-1a0a-41ac-b200-4d4bb2283b9f','西齋小飲贈別陜州沖卿學士','歐陽修','宋','宋诗','song-poetry','','[]','今日胡不樂，眾賓會高堂。',108,'全唐诗/poet.song.17000.json','["今日胡不樂，眾賓會高堂。", "坐中瀛洲客，新佩太守章。", "豈無芳罇酒，笑語共一觴。", "亦有嘉菊叢，新苞弄微黄。", "所嗟時易晚，節物已凄凉。", "羣鷺方盛集，離鴻獨高翔。", "山川正摇落，行李怯風霜。", "君子樂爲政，朝廷須儁良。", "歸來紫微閣，遺愛在甘棠。"]'),
('599ac9cb-5964-401f-bbd5-9ad84cf997b0','奉答原甫九月八日見過會飲之作','歐陽修','宋','宋诗','song-poetry','','[]','老大惜時節，少年輕別離。',132,'全唐诗/poet.song.17000.json','["老大惜時節，少年輕別離。", "我歌君當和，我酌君勿辭。", "豔豔庭下菊，與君吟繞之。", "擷其黄金蕊，泛此白玉巵。", "君勿愛此花，問君此何時。", "秋風日益高，霜露漸離披。", "芳歲忽已晚，朱顔從此衰。", "念君將捨我，車馬去有期。", "君行一何樂，我意獨不怡。", "飛兔不戀羣，奔風誰能追。", "老驥但伏櫪，壯心良可悲。"]'),
('bc636bee-61f4-4d70-88f0-2cc163f1da2e','予作歸鴈亭於滑州後十有五年梅公儀來守是邦因取余詩刻于石又以長韻見寄因以答之','歐陽修','宋','宋诗','song-poetry','','[]','風吹城頭秋草黄，仰見鳴鴈初南翔。',176,'全唐诗/poet.song.17000.json','["風吹城頭秋草黄，仰見鳴鴈初南翔。", "秋草風吹春復綠，南鴈北飛聲肅肅。", "城下臺邊桃李蹊，憶初披荒手植之。", "雪消冰解草木動，因記鴻鴈將歸時。", "爾來十載空遺迹，飛鴈年年自南北。", "臺傾餘址草荒凉，樹老無花春寂歷。", "東州太守詩尤美，組織文章爛如綺。", "長篇大句琢方石，一日都城傳百紙。", "我思古人無不然，慷慨功名垂百年。", "沉碑身後念陵谷，把酒泣下悲山川。", "一時留賞雖邂逅，後世傳之因不朽。"]'),
('3612fda0-0b9d-48a7-8e3c-9f3cc70bb693','寄題洛陽致政第少卿靜居堂','歐陽修','宋','宋诗','song-poetry','','[]','洛人皆種花，花發有時闌。',108,'全唐诗/poet.song.17000.json','["洛人皆種花，花發有時闌。", "君家獨種玉，種玉產琅玕。", "子弟守家法，名聲聳朝端。", "歲時歸拜慶，閭里亦相歡。", "西臺有道氣，自少服靈丸。", "春酒養眉壽，童顔如渥丹。", "清談不倦客，妙思喜揮翰。", "壯也已吏隱，興餘方掛冠。", "臨風想高誼，懷祿愧盤桓。"]'),
('bc437ac1-67f5-4355-9077-ef7bc84afc95','鬼車','歐陽修','宋','宋诗','song-poetry','','[]','嘉祐六年秋，九月二十有八日，天愁無光月不出。',372,'全唐诗/poet.song.17000.json','["嘉祐六年秋，九月二十有八日，天愁無光月不出。", "浮雲蔽天眾星沒，舉手嚮空如抹漆。", "天昏地黑有一物，不見其形，但聞其聲。", "其初切切凄凄，或高或低。", "乍似玉女調玉笙，眾管參差而不齊。", "既而咿咿呦呦，若軋若抽。", "又如百兩江州車，回輪轉軸聲啞嘔。", "鳴機夜織錦江上，羣鴈驚起蘆花洲。", "吾謂此何聲，初莫窮端由。", "老婢撲燈呼兒曹，云此怪鳥無匹儔。", "其名爲鬼車，夜載百鬼凌空遊。", "其聲雖小身甚大，翅如車輪排十頭。", "凡鳥有一口，其鳴已啾啾。", "此鳥十頭有十口，口插一舌連一喉。", "一口出一聲，千聲百響更相酬。", "昔時周公居東周，厭聞此鳥憎若讎。", "夜呼庭氏率其屬，彎弧俾逐出九州。", "射之三發不能中，天遣天狗從空投。", "自從狗嚙一頭落，斷頸至今青血流。", "爾來相距三千秋，晝藏夜出如鵂鶹。", "每逢陰黑天外過，乍見火光驚輒墮。", "有時餘血下點污，所遭之家家必破。", "我聞此語驚且疑，反祝疾飛無我禍。", "我思天地何茫茫，百物巨細理莫詳。"]'),
('85919a2c-1ca0-4b3a-8eb4-a155c488508f','感二子','歐陽修','宋','宋诗','song-poetry','','[]','黄河一千年一清，岐山鳴鳳不再鳴。',208,'全唐诗/poet.song.17000.json','["黄河一千年一清，岐山鳴鳳不再鳴。", "自從蘇梅二子死，天地寂默收雷聲。", "百蟲壞戶不啟蟄，萬木逢春不發萌。", "豈無百鳥解言語，喧啾終日無人聽。", "二子精思極搜抉，天地鬼神無遁情。", "及其放筆騁豪俊，筆下萬物生光榮。", "古人謂此覷天巧，命短疑爲天公憎。", "昔時李杜爭橫行，麒麟鳳凰世所驚。", "二物非能致太平，須時太平然後生。", "開元天寶物盛極，自此中原疲戰爭。", "英雄白骨化黄土，富貴何止浮雲輕。", "唯有文章爛日星，氣凌山岳常崢嶸。", "賢愚自古皆共盡，突兀空留後世名。"]'),
('d664d5be-e44d-4085-aef6-bb214a5c0cef','讀書','歐陽修','宋','宋诗','song-poetry','','[]','吾生本寒儒，老尚把書卷。',288,'全唐诗/poet.song.17000.json','["吾生本寒儒，老尚把書卷。", "眼力雖已疲，心意殊未倦。", "正經首唐虞，僞說起秦漢。", "篇章異句讀，解詁及箋傳。", "是非自相攻，去取在勇斷。", "初如兩軍交，乘勝方酣戰。", "當其旗鼓催，不覺人馬汗。", "至哉天下樂，終日在几案。", "念昔始從師，力學希仕宦。", "豈敢取聲名，惟期脫貧賤。", "忘食日已晡，燃薪夜侵旦。", "謂言得志後，便可焚筆硯。", "少償辛苦時，惟事寢與飯。", "歲月不我留，一生今過半。", "中間嘗忝竊，內外職文翰。", "官榮日清近，廩給亦豐羨。", "人情慎所習，酖毒比安宴。", "漸追時俗流，稍稍學營辦。", "盃盤窮水陸，賓客羅俊彥。", "自從中年來，人事攻百箭。", "非惟職有憂，亦自老可歎。", "形骸苦衰病，心志迹退懦。", "前時可喜事，閉眼不欲見。", "惟尋舊讀書，簡編多朽斷。"]'),
('8b5452e2-371c-460d-8adb-9189bb0bbcb6','鵯鵊詞','歐陽修','宋','宋诗','song-poetry','','[]','龍樓鳳闕鬰崢嶸，深宮不聞更漏聲。',163,'全唐诗/poet.song.17000.json','["龍樓鳳闕鬰崢嶸，深宮不聞更漏聲。", "紅紗蠟燭愁夜短，綠窗鵯鵊催天明。", "一聲兩聲人漸起，金井轆轤聞汲水。", "三聲四聲促嚴粧，紅靴玉带奉君王。", "萬年枝軟風露濕，上下枝間聲轉急。", "南衙促仗三衛列，九門放鑰千官入。", "重城禁籞鎖池臺，此鳥飛從何處來。", "君不見潁河東岸村陂闊，山禽野鳥常嘲哳。", "田家惟聽夏雞聲，夜夜垅頭耕曉月。", "可憐此樂獨吾知，眷戀君恩今白髮。"]'),
('b2b8d67c-3c72-459b-a707-e25a4f7f5919','初食雞頭有感','歐陽修','宋','宋诗','song-poetry','','[]','六月京師暑雨多，夜夜南風吹芡嘴。',160,'全唐诗/poet.song.17000.json','["六月京師暑雨多，夜夜南風吹芡嘴。", "凝祥池鎖會靈園，僕射荒陂安可擬。", "爭先園客採新苞，剖蚌得珠從海底。", "都城百物貴新鮮，厥價難酬與珠比。", "金盤磊落何所薦，滑臺撥醅如玉醴。", "自慙竊食萬錢厨，滿口飄浮嗟病齒。", "却思年少在江湖，野艇高歌菱荇裏。", "香新味全手自摘，玉潔沙磨軟還美。", "一瓢固不羨玉鼎，萬事適情爲可喜。", "何時遂買潁東田，歸去結茅臨野水。"]'),
('c7f2d4ea-869d-4c60-978a-0c1b5044d854','雙井茶','歐陽修','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西江水清江石老，石上生茶如鳳爪。',113,'全唐诗/poet.song.17000.json','["西江水清江石老，石上生茶如鳳爪。", "窮臘不寒春氣早，雙井芽生先百草。", "白毛囊以紅碧紗，十斤茶養一兩芽。", "長安富貴五侯家，一啜猶須三日誇。", "寶雲日注非不精，爭新棄舊世人情。", "豈知君子有常德，至寶不隨時變易。", "君不見建溪龍鳳團，不改舊時香味色。"]'),
('601e7be0-8ff1-478d-881e-97df752159a1','贈李士寧','歐陽修','宋','宋诗','song-poetry','','[]','蜀狂士寧者，不邪亦不正。',217,'全唐诗/poet.song.17000.json','["蜀狂士寧者，不邪亦不正。", "混世使人疑，詭譎非一行。", "平生不把筆，對酒時高詠。", "初如不著意，語出多奇勁。", "傾財解人難，去不道名姓。", "金錢買酒醉高樓，明月空床眠不醒。", "一身四海即爲家，獨行萬里聊乘興。", "既不採藥賣都市，又不點石化黄金。", "進不干公卿，退不隱山林。", "與之游者但愛其人而莫見其術，安知其心。", "吾聞有道之士游心太虛，逍遥出入，常與道俱。", "故能入火不熱，入水不濡。", "嘗聞其語，而未見其人也，豈斯人之徒歟。", "不然言不純師，行不純德。", "而滑稽玩世，其東方朔之流乎。"]'),
('b98bd432-65ed-4a73-a2ea-263f7603608a','明妃小引','歐陽修','宋','宋诗','song-poetry','','[]','漢宮諸女嚴粧罷，共送明妃溝水頭。',48,'全唐诗/poet.song.17000.json','["漢宮諸女嚴粧罷，共送明妃溝水頭。", "溝上水聲來不斷，花隨水去不回流。", "上馬即知無返日，不須出塞始堪愁。"]'),
('5816bf76-cbdb-4cbc-9c68-4428234288b2','感事四首  其一','歐陽修','宋','宋诗','song-poetry','','[]','老者覺時速，閑人知日長。',60,'全唐诗/poet.song.17000.json','["老者覺時速，閑人知日長。", "日月本無情，人心有閑忙。", "努力取功名，斷碑埋路傍。", "逍遥林下士，丘垅亦相望。", "長生既無藥，濁酒且盈觴。"]'),
('9dfe05aa-709b-4a93-b641-9ad31734d199','感事四首  其二','歐陽修','宋','宋诗','song-poetry','','[]','空山一道士，辛苦學延齡。',60,'全唐诗/poet.song.17000.json','["空山一道士，辛苦學延齡。", "一旦隨物化，反言仙已成。", "開墳見空棺，謂已超青冥。", "尸解如蛇蟬，換骨蛻其形。", "既云須變化，何不任死生。"]'),
('618fcd24-da0e-4864-a34f-08ebf684bce5','感事四首  其三','歐陽修','宋','宋诗','song-poetry','','[]','仙境不可到，誰知仙有無。',132,'全唐诗/poet.song.17000.json','["仙境不可到，誰知仙有無。", "或乘九斑虬，或駕五雲車。", "朝倚扶桑枝，暮遊崑崙墟。", "往來幾萬里，誰復遇諸涂。", "富貴不還鄉，安事富貴歟。", "神仙人不見，魑魅與爲徒。", "人生不免死，魂魄入幽都。", "仙者得長生，又云超太虛。", "等爲不在世，與鬼亦何殊。", "得仙猶若此，何況不得乎。", "寄謝山中人，辛勤一何愚。"]'),
('ccf32328-edd2-413d-8871-0c341e9494ad','感事四首  其四','歐陽修','宋','宋诗','song-poetry','','[]','莫笑學仙人，山中苦岑寂。',108,'全唐诗/poet.song.17000.json','["莫笑學仙人，山中苦岑寂。", "試看青松鶴，何似朱門客。", "朱門炙手熱，來者無時息。", "何嘗問寒暑，豈暇謀寢食。", "彊顔悅憎怨，擇語防仇敵。", "眾欲苦無厭，有求期必獲。", "敢辭一身勞，豈塞天下責。", "風波卒然起，禍患藏不測。", "神仙雖杳茫，富貴意何得。"]'),
('9275adee-d087-40a0-bd49-a9ac644644a3','新春有感寄常夷埔','歐陽修','宋','宋诗','song-poetry','','[]','余生本羈孤，自少已非壯。',152,'全唐诗/poet.song.17000.json','["余生本羈孤，自少已非壯。", "今而老且病，何用苦惆悵。", "誤蒙三聖知，貪得過其量。", "恩私未知報，心志已凋喪。", "軒裳德不稱，徒自取譏謗。", "豈若常夫子，一瓢安陋巷。", "身雖草莽間，名在朝廷上。", "惟余服德義，久已慕恬曠。", "矧亦有吾廬，東西正相望。", "不須駕柴車，自可策蔾杖。", "坐驚顔鬢日摧頹，及取新春歸去來。", "共載一舟浮野水，焦陂四面百花開。"]'),
('e7dbcd76-0542-44b4-8187-fc07e84dd65e','昇天檜','歐陽修','宋','宋诗','song-poetry','','[]','青牛西出關，老聃始著五千言。',136,'全唐诗/poet.song.17000.json','["青牛西出關，老聃始著五千言。", "白鹿去昇天，爾來忽已三千年。", "當時遺迹至今在，隱起蒼檜猶依然。", "惟能乘變化，所以爲神仙。", "驅鸞駕鶴須臾間，飄忽不見如雲煙。", "奈何此鹿起平地，更假草木相攀緣。", "乃知神仙事茫昧，真僞莫究徒自傳。", "雪霜不改終古色，風雨有聲當夏寒。", "境清物老自可愛，何必詭怪窮根源。"]'),
('20d457a2-3722-4e8b-a372-85ae40662c3f','憶焦陂','歐陽修','宋','宋诗','song-poetry','','[]','焦陂荷花照水光，未到十里聞花香。',80,'全唐诗/poet.song.17000.json','["焦陂荷花照水光，未到十里聞花香。", "焦陂八月新酒熟，秋水魚肥鱠如玉。", "清河兩岸柳鳴蟬，直到焦陂不下船。", "笑向漁翁酒家保，金龜可解不須錢。", "明日君恩許歸去，白頭酣詠太平年。"]'),
('33afdd2d-3eff-41c8-84a1-664eaed1aaa5','贈許道人','歐陽修','宋','宋诗','song-poetry','','[]','洛城三月亂鸎飛，潁陽山中花發時。',128,'全唐诗/poet.song.17000.json','["洛城三月亂鸎飛，潁陽山中花發時。", "徃來車馬遊山客，貪看山花踏山石。", "紫雲仙洞鎖雲深，洞中有人人不識。", "飄飄許子旌陽後，道骨仙風本仙胄。", "多年洗耳避世喧，獨卧寒巖聽山溜。", "至人無心不算心，無心自得無窮壽。", "忽來顧我何慇懃，笑我白髮老紅塵。", "子歸爲筑巖前室，待我明年乞得身。"]'),
('8716e40a-8d49-43ce-b280-611cb4f84f18','送龍茶與許道人','歐陽修','宋','宋诗','song-poetry','','[]','潁陽道士青霞客，來似浮雲去無迹。',64,'全唐诗/poet.song.17000.json','["潁陽道士青霞客，來似浮雲去無迹。", "夜朝北斗太清壇，不道姓名人不識。", "我有龍團古蒼璧，九龍泉深一百尺。", "憑君汲井試烹之，不是人間香味色。"]'),
('604cf244-b22e-41f9-9490-257d602bea41','馴鹿','歐陽修','宋','宋诗','song-poetry','','[]','朝渴飲清池，暮飽眠深柵。',90,'全唐诗/poet.song.17000.json','["朝渴飲清池，暮飽眠深柵。", "慙媿主人恩，自非殺身難報德。", "主人施恩不待報，哀爾胡爲網羅獲。", "南山藹藹動春陽，吾欲縱爾山之傍。", "巖崖雪盡飛泉溜，澗谷風吹百草香。", "飲泉齧草當遠去，山後山前射生戶。"]'),
('906fe72d-a66a-4b30-bea2-84ddaac98d35','留題齊州舜泉','歐陽修','宋','宋诗','song-poetry','','[]','岸有時而爲谷，海有時而爲田，虞舜已歿三千年。',150,'全唐诗/poet.song.17000.json','["岸有時而爲谷，海有時而爲田，虞舜已歿三千年。", "耕田浚井雖鄙事，至今遺迹存依然。", "歷山之下有寒泉，向此號泣于旻天。", "無情草木亦改色，山川慘淡生雲煙。", "一朝垂衣正南面，臯夔稷契來聯翩。", "功高德大被萬世，今人過此猶留連。", "齊州太守政之暇，鑿渠開沼疏清漣。", "遊車擊轂惟恐後，眾卉亂發如爭先。", "豈徒邦人知樂此，行客亦爲留征軒。"]'),
('2feab519-b1e5-47e8-952d-8345d910ef58','山齋戲書絕句二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','密脾未滿蜂採花，麥垅已深鳩喚雨。',32,'全唐诗/poet.song.17000.json','["密脾未滿蜂採花，麥垅已深鳩喚雨。", "正是山齋睡足時，不覺花間日亭午。"]'),
('54d24536-2743-434f-ac44-b997b6f97790','山齋戲書絕句二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','經春老病不出門，坐見羣芳爛如雪。',32,'全唐诗/poet.song.17000.json','["經春老病不出門，坐見羣芳爛如雪。", "正當年少惜花時，日日春風吹石裂。"]'),
('ab670f4f-9f16-4674-b91c-4a4efb5a6faf','嘲少年惜花','歐陽修','宋','宋诗','song-poetry','','[]','紛紛紅蕊落泥沙，少年何用苦咨嗟。',72,'全唐诗/poet.song.17000.json','["紛紛紅蕊落泥沙，少年何用苦咨嗟。", "春風自是無情物，肯爲汝惜無情花。", "今年花落明年好，但見花開人自老。", "人老不復少，花開還更新。", "使花如解語，應笑惜花人。"]'),
('2e939193-8aa4-4b31-b432-bc2354f4cf86','出郊見田家蠶麥已成慨然有感','歐陽修','宋','宋诗','song-poetry','','[]','誰謂田家苦，田家樂有時。',72,'全唐诗/poet.song.17000.json','["誰謂田家苦，田家樂有時。", "車鳴繅白繭，麥熟囀黄鸝。", "田家此樂幾人知，幸獨知之未許歸。", "逢時得寵已逾分，報國無能徒爾爲。", "收取玉堂揮翰手，却尋南畝把鋤犁。"]'),
('0b437c1b-2641-4698-8c56-c71e5068a68b','射生戶','歐陽修','宋','宋诗','song-poetry','','[]','射生戶，前日獻一豹，今日獻一狼。',84,'全唐诗/poet.song.17000.json','["射生戶，前日獻一豹，今日獻一狼。", "豹因傷我牛，狼因食我羊。", "狼豹誠爲害人物，縣官賞之縑五匹。", "射生戶，持縑歸。", "爲人除害固可賞，貪功趨利爾勿爲。", "弦弓毒矢無妄發，恐爾不識麒麟兒。"]'),
('129ec025-06be-44ad-a183-af5c43cfa3eb','戲石唐山隱者','歐陽修','宋','宋诗','song-poetry','','[]','石唐仙室紫雲深，潁陽真人此算心。',80,'全唐诗/poet.song.17000.json','["石唐仙室紫雲深，潁陽真人此算心。", "真人已去升寥廓，歲歲巖花自開落。", "我昔曾爲洛陽客，偶賂巖前坐盤石。", "四字丹書萬仞崖，神清之洞鎖樓臺。", "雲深路絕無人到，鸞鶴今應待我來。"]'),
('5a7e64d0-70e7-42ef-a6ff-a55b34bb705a','送王汲宰藍田','歐陽修','宋','宋诗','song-poetry','','[]','喧喧動車馬，共出古都門。',48,'全唐诗/poet.song.17000.json','["喧喧動車馬，共出古都門。", "落日催行客，東風吹酒罇。", "樹摇秦甸綠，花入輞川繁。", "若遇西來旅，時應問故園。"]'),
('7ba75886-1b84-4677-91ec-97627e41edec','徽安門曉望','歐陽修','宋','宋诗','song-poetry','','[]','都門收宿霧，佳氣鬰葱葱。',48,'全唐诗/poet.song.17000.json','["都門收宿霧，佳氣鬰葱葱。", "曉日寒川上，青山白霧中。", "樓臺萬瓦合，車馬九衢通。", "恨乏登高賦，徒知京邑雄。"]'),
('1b01c06b-6b76-4128-a7fa-55568d87d947','送孟都官知蜀州','歐陽修','宋','宋诗','song-poetry','','[]','名郎出粉闈，佳郡古關西。',48,'全唐诗/poet.song.17000.json','["名郎出粉闈，佳郡古關西。", "幾驛秦亭盡，千山蜀鳥啼。", "朱輪照耕野，綠芋覆秋畦。", "向闕應東望，雲深隴樹迷。"]'),
('bd07536d-f0fc-4a34-a6c2-07e9f4637cbd','南征回京至界上驛先呈城中諸友','歐陽修','宋','宋诗','song-poetry','','[]','朝雲來少室，日暮向箕山。',48,'全唐诗/poet.song.17000.json','["朝雲來少室，日暮向箕山。", "本以無心出，寧隨倦客還。", "春歸伊水綠，花晚洛橋閑。", "誰有餘罇酒，相期一解顔。"]'),
('382100ca-13f2-4cf1-98d1-4e4ef72a7618','逸老亭','歐陽修','宋','宋诗','song-poetry','','[]','上相此忘榮，怡然物外情。',72,'全唐诗/poet.song.17000.json','["上相此忘榮，怡然物外情。", "池光開小幌，山翠入重城。", "野鳥窺華衮，春壺勞耦耕。", "枕前雙鴈沒，雨外一川晴。", "解組金龜重，調琴赤鯉驚。", "雖懷安石趣，豈不爲蒼生。"]'),
('4ab26099-70cd-4f54-9e53-be60f18d91db','慶愛寺','歐陽修','宋','宋诗','song-poetry','','[]','都人布金地，紺宇巋然存。',48,'全唐诗/poet.song.17000.json','["都人布金地，紺宇巋然存。", "山氣蒸經閣，鍾聲出國門。", "老杉春自綠，古壁雨先昏。", "應有幽人屐，來留石蘚痕。"]'),
('0dbf7671-8878-482d-9767-b69cdc0626b3','弔黄學士三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','麗正讎書久，蘭臺約史成。',48,'全唐诗/poet.song.17000.json','["麗正讎書久，蘭臺約史成。", "迎親就江水，厭直出承明。", "世德無雙譽，詩豪第一評。", "風流今頓盡，響像憶平生。"]'),
('fbf08eb3-5e34-4be6-9827-b40c3d1ed147','弔黄學士三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','沈約多清瘦，文園仍病痟。',48,'全唐诗/poet.song.17000.json','["沈約多清瘦，文園仍病痟。", "共疑天上召，更欲水邊招。", "金馬人相弔，長沙物易妖。", "秋風吹越樹，歸旐自飄飄。"]'),
('9b459ba9-9942-4bc9-ae55-f3370afbe521','弔黄學士三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','自古蘭衰早，因令蕙歎深。',48,'全唐诗/poet.song.17000.json','["自古蘭衰早，因令蕙歎深。", "書遺茂陵藁，病作越鄉吟。", "蒿里無春色，閩山蔽夕陰。", "空嗟埋玉樹，赍志永沉沉。"]'),
('cb463b73-de84-47a5-9cb1-413aa8c93b63','雨後獨行洛北','歐陽修','宋','宋诗','song-poetry','','[]','北闕望南山，明嵐雜紫煙。',48,'全唐诗/poet.song.17000.json','["北闕望南山，明嵐雜紫煙。", "歸雲向嵩嶺，殘雨過伊川。", "樹繞芳隄外，橋橫落照前。", "依依半荒苑，行處獨聞蟬。"]'),
('9a64edac-a4b5-4b85-a934-fd737b54bd17','陪府中諸官遊城南','歐陽修','宋','宋诗','song-poetry','','[]','一雨郊圻迥，新秋榆棗繁。',48,'全唐诗/poet.song.17000.json','["一雨郊圻迥，新秋榆棗繁。", "田荒溪溜入，禾熟雀聲喧。", "燒出空槎腹，人耕廢廟垣。", "閑追向城客，落日隱高原。"]'),
('2dbe9fbf-3af2-42b7-8089-a02dc64161e2','智蟾上人遊南岳','歐陽修','宋','宋诗','song-poetry','','[]','終日念雲壑，南歸心浩然。',48,'全唐诗/poet.song.17000.json','["終日念雲壑，南歸心浩然。", "青山入楚路，白水望湖田。", "野渡惟浮鉢，山家少施錢。", "到時春尚早，收茗綠巖前。"]'),
('e3dc72f4-0b99-4f3c-b947-25864a485f1d','送左殿丞入蜀','歐陽修','宋','宋诗','song-poetry','','[]','傳聞蜀道難，行客若登天。',48,'全唐诗/poet.song.17000.json','["傳聞蜀道難，行客若登天。", "紫竹深無路，黄花忽見川。", "聞禽嗟異域，問俗訪耆年。", "欲識京都遠，惟應望日邊。"]'),
('78f9caa7-38f0-466d-b22d-0996540e636d','秋郊曉行','歐陽修','宋','宋诗','song-poetry','','[]','寒郊桑柘稀，秋色曉依依。',48,'全唐诗/poet.song.17000.json','["寒郊桑柘稀，秋色曉依依。", "野燒侵河斷，山鴉向日飛。", "行歌採樵去，荷鍤刈田歸。", "秫酒家家熟，相邀白竹扉。"]'),
('90089bfc-a118-4712-a319-9c3c8bff235b','被牒行縣因書所見呈寮友','歐陽修','宋','宋诗','song-poetry','','[]','周禮恤兇荒，軺車出四方。',96,'全唐诗/poet.song.17000.json','["周禮恤兇荒，軺車出四方。", "土龍朝祀雨，田火夜驅蝗。", "木落孤村迥，原高百草黄。", "亂鵶鳴古堞，寒雀聚空蒼。", "桑野人行饁，魚陂鳥下梁。", "晚煙茅店月，初日棗林霜。", "墐戶催寒候，叢祠禱歲穰。", "不妨行覽物，山水正蒼茫。"]'),
('0be1f2ea-47fa-4858-a2b4-7cc3c7637d66','緱氏縣作','歐陽修','宋','宋诗','song-poetry','','[]','亭候徹郊畿，人家嶺坂西。',48,'全唐诗/poet.song.17000.json','["亭候徹郊畿，人家嶺坂西。", "青山臨古縣，綠竹繞寒溪。", "道上行收穗，桑間晚溉畦。", "東臯有深趣，便擬卜幽棲。"]'),
('5bed3bc2-4456-4123-90ef-b52bd13879df','又行次作','歐陽修','宋','宋诗','song-poetry','','[]','秋色滿郊原，人行禾黍間。',48,'全唐诗/poet.song.17000.json','["秋色滿郊原，人行禾黍間。", "雉飛橫斷澗，燒響入空山。", "野水蒼煙起，平林夕鳥還。", "嵩嵐久不見，寒碧更孱顔。"]'),
('64f4f670-02e6-48be-afc7-0d605644ae57','送梅秀才歸宣城','歐陽修','宋','宋诗','song-poetry','','[]','從學方年少，還家罄橐金。',48,'全唐诗/poet.song.17000.json','["從學方年少，還家罄橐金。", "久爲江北客，能作洛生吟。", "罷亞霜前稻，鉤輈竹上禽。", "歸帆何處落，應拂野梅林。"]'),
('344e0038-024a-495a-aaca-f93fa6016a58','鞏縣陪祭獻懿二后回孝義橋道中作','歐陽修','宋','宋诗','song-poetry','','[]','落日漢陵道，初寒慘暮飆。',48,'全唐诗/poet.song.17000.json','["落日漢陵道，初寒慘暮飆。", "遥看山口火，暗渡洛川橋。", "不見新園樹，空聞引葬簫。", "林鵶棲已定，猶此倦征鑣。"]'),
('089872d3-c8d8-474d-8bd9-11f9cd8249f5','送謝學士歸闕','歐陽修','宋','宋诗','song-poetry','','[]','供帳拂朝煙，征鞍去莫攀。',48,'全唐诗/poet.song.17000.json','["供帳拂朝煙，征鞍去莫攀。", "人醒風外酒，馬度雪中關。", "舊府誰同在，新年獨未還。", "遥應行路者，偏識綵衣斑。"]'),
('7df36075-ec1c-4d63-a93f-0cd765f306f6','河南王慰西齋','歐陽修','宋','宋诗','song-poetry','','[]','寒齋日蕭索，天外敞簷楹。',48,'全唐诗/poet.song.17000.json','["寒齋日蕭索，天外敞簷楹。", "竹雪晴猶覆，山窗夜自明。", "禽歸窺野客，雲去入重城。", "欲就陶潛飲，應須載酒行。"]'),
('f4451c7a-14f5-48c4-a063-d98eb1e1b2e7','第主簿東齋','歐陽修','宋','宋诗','song-poetry','','[]','官舍掩寒扉，聊同隱者棲。',48,'全唐诗/poet.song.17000.json','["官舍掩寒扉，聊同隱者棲。", "溪流穿竹過，山鳥入城啼。", "賓主高談勝，心冥外物齊。", "惟應朝枕夢，長厭隔鄰雞。"]'),
('7eebb53f-7601-4d65-808e-d8a4f83e528e','留守相公禱雨九龍祠應時獲澍呈府中同寮','歐陽修','宋','宋诗','song-poetry','','[]','古木鬰沉沉，祠亭相衮臨。',120,'全唐诗/poet.song.17000.json','["古木鬰沉沉，祠亭相衮臨。", "雷驅山外響，雲結日邊陰。", "霢霂來初合，依微勢稍深。", "土膏潛動脈，野氣欲成霖。", "隴上連雲色，田間擊壤音。", "明光應奏瑞，黄屋正焦心。", "帝邑三川美，離宮萬瓦森。", "廢溝鳴故苑，紅蘤發青林。", "南畝猶須勸，餘春尚可尋。", "應容後車客，時作洛生吟。"]'),
('49c18334-60e4-4c0c-8f08-fdfd9143d547','春日獨遊上林院後亭見櫻桃花奉寄希深聖俞仍酬遞中見寄之什','歐陽修','宋','宋诗','song-poetry','','[]','昔日尋春地，今來感歲華。',48,'全唐诗/poet.song.17000.json','["昔日尋春地，今來感歲華。", "人行已荒徑，花發半枯槎。", "高榭林端出，殘陽水外斜。", "聊持一罇酒，徙倚憶天涯。"]'),
('7a89fad9-da36-496e-a16a-800dd81515a6','獨至香山憶謝學士','歐陽修','宋','宋诗','song-poetry','','[]','伊水弄春沙，山臨水上斜。',48,'全唐诗/poet.song.17000.json','["伊水弄春沙，山臨水上斜。", "曾爲謝公客，徧入梵王家。", "陰澗初生草，春巖自落花。", "却尋題石處，歲月已堪嗟。"]'),
('9c884d03-317a-4817-900b-d4f5d03e124e','春晚同應之偶至普明寺小飲作','歐陽修','宋','宋诗','song-poetry','','[]','偶來林下逕，共酌竹間亭。',48,'全唐诗/poet.song.17000.json','["偶來林下逕，共酌竹間亭。", "積雨添方沼，殘花點綠萍。", "野陰侵席潤，芳氣襲人醒。", "禽鳥休驚顧，都忘兀爾形。"]'),
('5e0a9a04-fb3b-4890-be40-6db715265160','黄河八韻寄呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','河水激箭險，誰言航葦遊。',96,'全唐诗/poet.song.17000.json','["河水激箭險，誰言航葦遊。", "堅冰馳馬渡，伏浪卷沙流。", "樹落新摧岸，湍驚忽改洲。", "鑿龍時退鯉，漲潦不分牛。", "萬里通槎漢，千帆下漕舟。", "怨歌今罷筑，故道失難求。", "灘急風逾響，川寒霧不收。", "詎能窮禹迹，空欲問張侯。"]'),
('f2f06077-e6de-443d-9a01-3841f57c6883','和應之同年兄秋日雨中登廣愛寺閣寄梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','經年都洛與君交，共許詩中思最豪。',64,'全唐诗/poet.song.17000.json','["經年都洛與君交，共許詩中思最豪。", "舊社更誰能擁鼻，新秋有客獨登高。", "徑蘭欲謝悲零露，籬菊空開乏凍醪。", "縱使河陽花滿縣，亦應留滯感潘毛。"]'),
('78ceb5c0-16b8-4b84-930f-de9aedb4c904','晚過水北','歐陽修','宋','宋诗','song-poetry','','[]','寒川消積雪，凍浦漸通流。',24,'全唐诗/poet.song.17000.json','["寒川消積雪，凍浦漸通流。", "日暮人歸盡，沙禽上釣舟。"]'),
('91ad7ba5-fad6-46a6-a53b-8ca7963d68bf','罷官西京回寄河南張主簿','歐陽修','宋','宋诗','song-poetry','','[]','歸客下三川，孤郵暫解鞍。',48,'全唐诗/poet.song.17000.json','["歸客下三川，孤郵暫解鞍。", "鳥聲催暮急，山氣欲晴寒。", "已作愁霖詠，猶懷祖帳歡。", "更聞溪溜響，疑是石樓灘。"]'),
('b14a738e-250d-4d56-8ecc-24e72af4ed8e','寄西京張法曹','歐陽修','宋','宋诗','song-poetry','','[]','幕府三年客，羣居幾日親。',48,'全唐诗/poet.song.17000.json','["幕府三年客，羣居幾日親。", "初分闕口路，猶見洛陽人。", "垅麥晴將秀，田花晚自介。", "向家行漸近，豈復倦征輪。"]'),
('9679fdae-3baf-4db2-b897-573efc849a98','離彭婆值雨投臨汝驛回寄張九屯田司錄','歐陽修','宋','宋诗','song-poetry','','[]','投館野花邊，羸驂晚不前。',48,'全唐诗/poet.song.17000.json','["投館野花邊，羸驂晚不前。", "山橋斷行路，溪雨漲春田。", "樹冷無棲鳥，村深起暮煙。", "洛陽山已盡，休更望伊川。"]'),
('801f80b3-e8ce-4491-9bc5-5c897f1a55dc','朱家曲','歐陽修','宋','宋诗','song-poetry','','[]','行人傍衰柳，路向古河窮。',72,'全唐诗/poet.song.17000.json','["行人傍衰柳，路向古河窮。", "桑柘田疇美，漁商市井通。", "薪歌晚入浦，舟子夜乘風。", "旅舍孤煙外，天京王氣中。", "山川許國近，風俗楚鄉同。", "宿客雞鳴起，驅車猶更東。"]'),
('499cb206-6428-4095-adcd-9f06de068fa6','行至椹澗作','歐陽修','宋','宋诗','song-poetry','','[]','霜後葉初鳴，羸驂遶澗行。',48,'全唐诗/poet.song.17000.json','["霜後葉初鳴，羸驂遶澗行。", "川原人遠近，禾黍日晴明。", "病質驚殘歲，歸塗厭暮程。", "空林聚寒雀，疑已作春聲。"]'),
('489d6211-5ddb-4c31-b0ac-772ed494f05e','送謝希深學士北使','歐陽修','宋','宋诗','song-poetry','','[]','漢使入幽燕，風煙兩國間。',96,'全唐诗/poet.song.17000.json','["漢使入幽燕，風煙兩國間。", "山河持節遠，亭障出疆閑。", "征馬聞笳躍，雕弓向月彎。", "禦寒低便面，贈客解刀環。", "鼓角雲中壘，牛羊雪外山。", "穹廬鳴朔吹，凍酒發朱顔。", "寒草生侵磧，春榆綠滿關。", "應須鴈北嚮，方值使南還。"]'),
('3bb64c36-fef7-4d31-a5e1-bde5dacab3c6','送賈推官赴絳州','歐陽修','宋','宋诗','song-poetry','','[]','白雲汾水上，人北鴈南飛。',48,'全唐诗/poet.song.17000.json','["白雲汾水上，人北鴈南飛。", "行李山川遠，風霜草木腓。", "郡齋賓榻掛，幕府羽書稀。", "最有題輿客，偏思玉麈揮。"]'),
('703a2c06-b27c-4716-b28e-82fba9add222','送張如京知安肅軍','歐陽修','宋','宋诗','song-poetry','','[]','相逢舊從事，新命忽臨戎。',48,'全唐诗/poet.song.17000.json','["相逢舊從事，新命忽臨戎。", "界上山河壯，軍中彭角雄。", "朔風馳駿馬，塞雪射驚鴻。", "試取封侯印，何如筆硯功。"]'),
('a7b9a16e-57d3-4f93-9cca-78fd220858b7','送威勝軍張判官','歐陽修','宋','宋诗','song-poetry','','[]','北地不知春，惟看榆葉新。',48,'全唐诗/poet.song.17000.json','["北地不知春，惟看榆葉新。", "岑牟多武士，玉麈重嘉賓。", "野燐驚行客，烽煙入遠塵。", "繫書沙上鴈，時寄日邊人。"]'),
('f92c2496-0470-4750-9a2d-89966a599907','送同年史褒之武功尉','歐陽修','宋','宋诗','song-poetry','','[]','久作遊邊客，常悲入塞笳。',48,'全唐诗/poet.song.17000.json','["久作遊邊客，常悲入塞笳。", "今茲一尉遠，猶困折腰嗟。", "白馬關中道，青天棧外家。", "過秦應弔古，惟有故山斜。"]'),
('026eb585-6bca-4763-94cf-4dc8531f07b1','送祝熙載之東陽主簿','歐陽修','宋','宋诗','song-poetry','','[]','吳江通海浦，畫舸候潮歸。',48,'全唐诗/poet.song.17000.json','["吳江通海浦，畫舸候潮歸。", "疊鼓山間響，高帆鳥外飛。", "孤城秋枕水，千室夜鳴機。", "試問還家客，遼東今是非。"]'),
('f03b1f36-62f5-450d-82a0-e1e231000a77','鄭十一先輩赴四明幕','歐陽修','宋','宋诗','song-poetry','','[]','梁漢褒斜險，夫君畏遠遊。',48,'全唐诗/poet.song.17000.json','["梁漢褒斜險，夫君畏遠遊。", "家臨越山下，帆入海潮頭。", "岸柳行稍盡，江蓴歸漸秋。", "故鄉看衣錦，寧羨李膺舟。"]'),
('43c92c82-ae55-4286-b894-0b678ba26b49','送丁元珍峽州判官','歐陽修','宋','宋诗','song-poetry','','[]','爲客久南方，西游更異鄉。',48,'全唐诗/poet.song.17000.json','["爲客久南方，西游更異鄉。", "江通蜀國遠，山閉楚祠荒。", "油幕無軍事，清猿斷客腸。", "惟應陪主諾，不費日飛觴。"]'),
('2f069d82-a371-475b-830e-d8617e604d8b','送楚建中潁州法曹','歐陽修','宋','宋诗','song-poetry','','[]','冠蓋盛西京，當年相府榮。',48,'全唐诗/poet.song.17000.json','["冠蓋盛西京，當年相府榮。", "曾陪鹿鳴宴，徧識洛陽生。", "共歎長沙讁，空存許劭評。", "堪嗟桃李樹，何日見陰成。"]'),
('38d3a250-a72b-436c-bb46-93b27cf4a93c','送王尚恭隰州幕','歐陽修','宋','宋诗','song-poetry','','[]','去國初游宦，從軍苦寂寥。',48,'全唐诗/poet.song.17000.json','["去國初游宦，從軍苦寂寥。", "愁雲带城起，畫角向山飄。", "秋勁方馳馬，春寒正襲貂。", "遥知爲客恨，應賴酒盃消。"]'),
('17494a26-b51c-4c47-a329-a565ba1342ae','送王尚喆三原尉','歐陽修','宋','宋诗','song-poetry','','[]','初仕便西轅，驪駒兩佩環。',48,'全唐诗/poet.song.17000.json','["初仕便西轅，驪駒兩佩環。", "山河識天府，風雨度函關。", "桑柘千疇富，人煙萬井閑。", "欲爲京洛詠，應苦簿書間。"]'),
('72d29838-4088-41a9-a9cd-f72ecbc58e09','送餘姚陳寺丞','歐陽修','宋','宋诗','song-poetry','','[]','銅墨佩腰間，中流望若仙。',48,'全唐诗/poet.song.17000.json','["銅墨佩腰間，中流望若仙。", "鳴蟬汴河柳，畫鷁越鄉船。", "下瀨逢江鴈，瞻氛落海鳶。", "山川仍客思，盡入隱侯篇。"]'),
('be078a04-79b5-4695-8695-d98182dec33f','送廖八下第歸衡山','歐陽修','宋','宋诗','song-poetry','','["\u8861\u5c71"]','曾作關中客，嘗窺百二疆。',48,'全唐诗/poet.song.17000.json','["曾作關中客，嘗窺百二疆。", "自言秦隴水，能斷楚人腸。", "失意倦京國，羈愁成鬢霜。", "何如伴征鴈，日日向衡陽。"]'),
('e126203a-916c-475b-a25f-044a8cd8645d','夏侯彥濟武陟尉','歐陽修','宋','宋诗','song-poetry','','[]','風煙地接懷，井邑富田垓。',48,'全唐诗/poet.song.17000.json','["風煙地接懷，井邑富田垓。", "河近聞冰坼，山高見雨來。", "官閑同小隱，酒美足銜盃。", "好去東籬菊，迎霜正欲開。"]'),
('b0252a02-6793-428a-8f31-339f2be2f43d','遠山','歐陽修','宋','宋诗','song-poetry','','[]','山色無還近，看山終日行。',24,'全唐诗/poet.song.17000.json','["山色無還近，看山終日行。", "峯巒隨處改，行客不知名。"]'),
('d68c59b5-d4b0-4cec-a02c-c532b413dc49','宋宣獻公挽詞三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','望繫朝廷重，文推天下工。',48,'全唐诗/poet.song.17000.json','["望繫朝廷重，文推天下工。", "清名畏楊綰，故事問胡公。", "物議垂爲相，風流頓已窮。", "仁言博哉利，獻替有遺忠。"]'),
('79422c8a-ba4f-4817-863c-b88088e9727b','宋宣獻公挽詞三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','識度推明哲，風猷藹縉紳。',48,'全唐诗/poet.song.17000.json','["識度推明哲，風猷藹縉紳。", "何言止中壽，遂不秉洪鈞。", "翰墨時爭寶，詞章晚愈新。", "哭哀文伯母，悲感路傍人。"]'),
('55cf99ec-0d65-42c0-8365-9e473e3a90b8','宋宣獻公挽詞三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','結髮逢明主，馳聲著兩朝。',48,'全唐诗/poet.song.17000.json','["結髮逢明主，馳聲著兩朝。", "奠楹先有夢，升屋豈能招。", "贈服三公衮，兼榮七葉貂。", "春風笳鼓咽，松栢助蕭蕭。"]'),
('998e4124-d975-4a75-bf28-2c1c50f5d590','初出真州泛大江作','歐陽修','宋','宋诗','song-poetry','','[]','孤舟日日去無窮，行色蒼茫杳靄中。',64,'全唐诗/poet.song.17000.json','["孤舟日日去無窮，行色蒼茫杳靄中。", "山浦轉帆迷向背，夜江看斗辨西東。", "滮田漸下雲間鴈，霜日初丹水上楓。", "蓴菜鱸魚方有味，遠來猶喜及秋風。"]'),
('3c852d5e-75ae-4e42-ae42-e7fe5dc078a9','江行贈鴈','歐陽修','宋','宋诗','song-poetry','','[]','雲間征鴈水間棲，矰繳方多羽翼微。',32,'全唐诗/poet.song.17000.json','["雲間征鴈水間棲，矰繳方多羽翼微。", "歲晚江湖同是客，莫辭伴我更南飛。"]'),
('3233e38e-5a79-458c-bd90-f8177f67e78d','松門','歐陽修','宋','宋诗','song-poetry','','[]','島嶼松門數里長，懸崖對起碧峯雙。',64,'全唐诗/poet.song.17000.json','["島嶼松門數里長，懸崖對起碧峯雙。", "可憐勝境當窮塞，翻使留人戀此邦。", "亂石驚灘喧醉枕，淺沙明月入船窗。", "因遊始覺南來遠，行盡荆江見蜀江。"]'),
('92150291-205e-4acd-b0ef-7dcc201328a8','下牢津','歐陽修','宋','宋诗','song-poetry','','[]','依依下牢口，古戍鬰嵯峨。',48,'全唐诗/poet.song.17000.json','["依依下牢口，古戍鬰嵯峨。", "入峽江漸曲，轉灘山更多。", "白沙飛白鳥，青障合青蘿。", "遷客初經此，愁詞作楚歌。"]'),
('be4a15b3-e5fb-4c7e-b2af-f9a354d297b0','龍溪','歐陽修','宋','宋诗','song-poetry','','[]','潺潺出亂峯，演漾綠蘿風。',48,'全唐诗/poet.song.17000.json','["潺潺出亂峯，演漾綠蘿風。", "淺瀨寒難涉，危槎路不通。", "朝雲起潭側，飛雨徧江中。", "更欲尋源去，山深不可窮。"]'),
('d7f0306c-2fa3-4cb4-abc9-b6c4988936eb','勞停驛','歐陽修','宋','宋诗','song-poetry','','[]','孤舟轉山曲，豁爾見平川。',48,'全唐诗/poet.song.17000.json','["孤舟轉山曲，豁爾見平川。", "樹杪帆初落，峯頭月正圓。", "荒煙幾家聚，瘦野一刀田。", "行客愁明發，驚灘鳥道前。"]'),
('0ae3274d-aafc-4bed-bdd7-7b7f5d2ae0b4','黄溪夜泊','歐陽修','宋','宋诗','song-poetry','','[]','楚人自古登臨恨，暫到愁腸已九回。',64,'全唐诗/poet.song.17000.json','["楚人自古登臨恨，暫到愁腸已九回。", "萬樹蒼煙三峽暗，滿川明月一猿哀。", "非鄉況復驚殘歲，慰客偏宜把酒盃。", "行見江山且吟詠，不因遷謫豈能來。"]'),
('1053e4b0-b61f-4f68-9c1d-3683d25ca6de','望州坡','歐陽修','宋','宋诗','song-poetry','','[]','聞說夷陵人爲愁，共言遷客不堪遊。',32,'全唐诗/poet.song.17000.json','["聞說夷陵人爲愁，共言遷客不堪遊。", "崎嶇幾日山行倦，却喜坡頭見峽州。"]'),
('39cd842d-b816-4f8d-bf33-5a89e703c6f1','初至夷陵答蘇子美見寄','歐陽修','宋','宋诗','song-poetry','','[]','三峽倚岧嶢，同遷地最遥。',192,'全唐诗/poet.song.17000.json','["三峽倚岧嶢，同遷地最遥。", "物華雖可愛，鄉思獨無聊。", "江水流青嶂，猿聲在碧霄。", "野篁抽夏笋，叢橘長春條。", "未臘梅先發，經霜葉不凋。", "江雲愁蔽日，山霧晦連朝。", "斫谷爭收漆，梯林鬭摘椒。", "巴賨船賈集，蠻市酒旗招。", "時節同荆俗，民風載楚謠。", "俚歌成調笑，摖鬼聚喧囂。", "得罪宜投裔，包羞分折腰。", "光陰催晏歲，牢落慘驚飆。", "白髮新年出，朱顔異域銷。", "縣樓朝見虎，官舍夜聞鴞。", "寄信無秋鴈，思歸望斗杓。", "須知千里夢，長繞洛川橋。"]'),
('e92e319a-ef15-4e70-99ad-37bd1833e435','冬後三日陪丁元珍遊東山寺','歐陽修','宋','宋诗','song-poetry','','[]','幕府文書日已稀，清罇歲晏喜相携。',64,'全唐诗/poet.song.17000.json','["幕府文書日已稀，清罇歲晏喜相携。", "寒山带郭穿松路，瘦馬尋春踏雪泥。", "翠蘚蒼崖森古木，綠蘿盤石暗深溪。", "爲貪賞物來猶早，迎臘梅花吐未齊。"]'),
('582138d9-5abd-49a5-9cfb-37e79e8d1508','送前巫山宰吳殿丞','歐陽修','宋','宋诗','song-poetry','','[]','俊域當年仰下風，天涯今日一罇同。',64,'全唐诗/poet.song.17000.json','["俊域當年仰下風，天涯今日一罇同。", "高文落筆妙天下，清論揮犀服坐中。", "江上掛帆明月峽，雲間謁帝紫微宮。", "山城寂寞少嘉客，喜見瓊枝慰病翁。"]'),
('b3b430f6-d894-4564-b3a9-dc0634e1bb25','龍興寺小飲呈表臣元珍','歐陽修','宋','宋诗','song-poetry','','[]','平日相從樂會文，博梟壺馬占朋分。',64,'全唐诗/poet.song.17000.json','["平日相從樂會文，博梟壺馬占朋分。", "罰籌多似昆陽矢，酒令嚴於細柳軍。", "蔽日雪雲猶靉靆，欲晴花氣漸氛氳。", "一罇萬事皆毫末，蜾蠃螟蛉豈足云。"]'),
('a95957cc-1355-4ff6-a7e2-6f48254f5365','縣舍不種花惟載楠木冬青茶竹之類因戲書七言四韻','歐陽修','宋','宋诗','song-poetry','','[]','結綬當年仕兩京，自憐年少體猶輕。',64,'全唐诗/poet.song.17000.json','["結綬當年仕兩京，自憐年少體猶輕。", "伊川洛浦尋芳徧，魏紫姚黄照眼明。", "客思病來生白髮，山城春至少紅英。", "芳叢密葉聊須種，猶得蕭蕭聽雨聲。"]'),
('75d74c73-6796-494c-9df6-06790d5d75d4','至喜堂新開北軒手植楠木兩株走筆呈元珍表臣','歐陽修','宋','宋诗','song-poetry','','[]','爲憐碧砌宜佳樹，自斸蒼苔選綠叢。',64,'全唐诗/poet.song.17000.json','["爲憐碧砌宜佳樹，自斸蒼苔選綠叢。", "不向芳菲趁開落，直須霜雪見青葱。", "披條泫轉清晨露，響葉蕭騷半夜風。", "時掃濃陰北窗下，一枰閑且伴衰弱。"]'),
('758931be-33c0-4b78-b796-3bed54fa3900','戲答元珍','歐陽修','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','春風疑不到天涯，二月山城未見花。',64,'全唐诗/poet.song.17000.json','["春風疑不到天涯，二月山城未見花。", "殘雪壓枝猶有橘，凍雷驚筍欲抽芽。", "夜聞歸鴈生鄉思，病入新年感物華。", "曾是洛陽花下客，野芳雖晚不須嗟。"]'),
('210faa81-7592-4625-8b10-bd502e9c9722','初晴獨遊東山寺五言六韻','歐陽修','宋','宋诗','song-poetry','','[]','日暖東山去，松門數里斜。',72,'全唐诗/poet.song.17000.json','["日暖東山去，松門數里斜。", "山林隱者趣，鍾鼓梵王家。", "地僻遲春節，風晴變物華。", "雲光漸容與，鳥哢已交加。", "冰下泉初動，煙中茗未芽。", "自憐多病客，來探欲開花。"]'),
('94b9ad4c-4fc7-48db-b052-858a175fe0d6','夷陵歲暮書事呈元珍表臣','歐陽修','宋','宋诗','song-poetry','','[]','蕭條雞犬亂山中，時節崢嶸忽已窮。',64,'全唐诗/poet.song.17000.json','["蕭條雞犬亂山中，時節崢嶸忽已窮。", "遊女髻鬟風俗古，野巫歌舞歲年豐。", "平時都邑今爲陋，敵國江山昔最雄。", "荆楚先賢多勝迹，不辭携酒問鄰翁。"]'),
('6022ddbc-2345-416c-a27f-28930ebf10c4','夷陵書事寄謝三舍人','歐陽修','宋','宋诗','song-poetry','','[]','春秋楚國西偏境，陸羽茶經第一州。',128,'全唐诗/poet.song.17000.json','["春秋楚國西偏境，陸羽茶經第一州。", "紫籜青林長蔽日，綠叢紅橘最宜秋。", "道塗處險人多負，邑屋臨江俗善泅。", "臘市漁鹽朝暫合，淫祠簫鼓歲無休。", "風鳴燒入空城響，雨惡江崩斷岸流。", "月出行歌聞調笑，花開啼鳥亂鉤輈。", "黄牛峽口經新歲，白玉京中夢舊遊。", "曾是洛陽花下客，欲誇風物向君羞。"]'),
('9ab68c04-3f08-42fa-8719-7c2b0df10c31','戲贈丁判官','歐陽修','宋','宋诗','song-poetry','','[]','西陵江口折寒梅，爭勸行人把一盃。',32,'全唐诗/poet.song.17000.json','["西陵江口折寒梅，爭勸行人把一盃。", "須信春風無遠近，維舟處處有花開。"]'),
('6df2e487-9dea-47f4-a920-a08a459c2bc1','寄梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','青山四顧亂無涯，雞犬蕭條數百家。',96,'全唐诗/poet.song.17000.json','["青山四顧亂無涯，雞犬蕭條數百家。", "楚俗歲時多雜鬼，蠻鄉言語不通華。", "繞城江急舟難泊，當縣山高日易斜。", "擊鼓踏歌成夜市，邀龜卜雨趁燒畬。", "叢林白晝飛妖鳥，庭砌非時見異花。", "惟有山川爲勝絕，寄人堪作畫圖誇。"]'),
('f9219624-4744-4875-9e74-7c2b03a55f03','離峽州後回寄元珍表臣','歐陽修','宋','宋诗','song-poetry','','[]','經年遷謫厭荆蠻，惟有江山興未闌。',64,'全唐诗/poet.song.17000.json','["經年遷謫厭荆蠻，惟有江山興未闌。", "醉裏人歸青草渡，夢中船下武牙灘。", "野花零落風前亂，飛雨蕭條江上寒。", "荻笋時魚方有味，恨無佳客共盃盤。"]'),
('897cca18-60fa-47fe-b24e-51f4081ffb0c','再至西都','歐陽修','宋','宋诗','song-poetry','','[]','伊川不到十年間，魚鳥今應怪我還。',64,'全唐诗/poet.song.17000.json','["伊川不到十年間，魚鳥今應怪我還。", "浪得浮名銷壯節，羞將白髮見青山。", "野花向客開如笑，芳草留人意自閑。", "却到謝公題壁處，向風清淚獨潺潺。"]'),
('04b759a6-7754-4e60-b6dc-be895ff22caa','過錢文僖公白蓮莊','歐陽修','宋','宋诗','song-poetry','','[]','城南車馬地，行客過徘徊。',48,'全唐诗/poet.song.17000.json','["城南車馬地，行客過徘徊。", "野水寒猶入，餘花晚自開。", "命賓曾授簡，開府最多才。", "今日西州路，何人更獨來。"]'),
('7c5be1ee-79c7-4029-892b-86388f5317d6','謝公挽詞三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','始見行春旆，俄聞引葬簫。',48,'全唐诗/poet.song.17000.json','["始見行春旆，俄聞引葬簫。", "笑言猶在耳，魂魄遂難招。", "天象奎星暗，辭林玉樹凋。", "朔風吹霰雪，銘旐共飄飄。"]'),
('509dc0e6-6092-46e1-933a-c429c67a80e5','謝公挽詞三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','前日賓齋宴，今晨奠柩觴。',48,'全唐诗/poet.song.17000.json','["前日賓齋宴，今晨奠柩觴。", "死生公自達，存沒世徒傷。", "舊國難歸葬，餘貲不給喪。", "平生公輔志，所得在文章。"]'),
('2723de28-fac4-4f9b-95ab-6f6547876b4f','謝公挽詞三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','樂事與良辰，平生愛洛濱。',48,'全唐诗/poet.song.17000.json','["樂事與良辰，平生愛洛濱。", "皇臺一閉夜，蒿里不知春。", "翰墨猶新澤，圖書已素塵。", "堪憐寢門哭，猶有舊時賓。"]'),
('47484d54-221b-4f9d-a965-e60c8f7ed440','愁牛嶺','歐陽修','宋','宋诗','song-poetry','','[]','邦人盡說畏愁牛，不獨牛愁我亦愁。',32,'全唐诗/poet.song.17000.json','["邦人盡說畏愁牛，不獨牛愁我亦愁。", "終日下山行百轉，却從山脚望山頭。"]'),
('f16fe524-0982-4254-9840-0326a83b45dc','寄子山待制二絕  其一','歐陽修','宋','宋诗','song-poetry','','[]','留滯西山獨可嗟，殘春過盡始還家。',32,'全唐诗/poet.song.17000.json','["留滯西山獨可嗟，殘春過盡始還家。", "落花縱有那堪醉，何況歸時無落花。"]'),
('08bd8f38-8c6b-44a5-be0f-5d87c48377d0','寄子山待制二絕  其二','歐陽修','宋','宋诗','song-poetry','','[]','聞君屢醉賞紅英，落盡殘花酒未醒。',32,'全唐诗/poet.song.17000.json','["聞君屢醉賞紅英，落盡殘花酒未醒。", "嗟我落花無分看，莫嫌狼藉掃中庭。"]'),
('25c866ce-6a57-4744-8387-02139c3c904c','寄秦州田元均','歐陽修','宋','宋诗','song-poetry','','[]','由來邊將用儒臣，坐以威名撫漢軍。',64,'全唐诗/poet.song.17000.json','["由來邊將用儒臣，坐以威名撫漢軍。", "萬馬不嘶聽號令，諸蕃無事著耕耘。", "夢回夜帳聞羌笛，詩就高樓對隴雲。", "莫忘鎮陽遺愛在，北潭桃李正氛氳。"]'),
('c9c9114d-7bda-4df4-ba0e-4f8d4dd18ede','送沈待制陜西都運','歐陽修','宋','宋诗','song-poetry','','[]','幾歲瘡痍近息兵，經營方喜得時英。',64,'全唐诗/poet.song.17000.json','["幾歲瘡痍近息兵，經營方喜得時英。", "從來漢粟勞飛輓，當使秦人自戰耕。", "道左旌旗諸將列，馬前弓劒六蕃迎。", "知君材力多閑暇，剩聽陽關醉後聲。"]'),
('2f7845eb-66ec-441e-a3b3-87d77b9fe50f','欒城遇風效韓孟聯句體','歐陽修','宋','宋诗','song-poetry','','[]','歲暮氛霾惡，冬餘氣候爭。',240,'全唐诗/poet.song.17000.json','["歲暮氛霾惡，冬餘氣候爭。", "吹噓回暖律，號令發新正。", "遠響來猶漸，狂奔勢益橫。", "頹城鏖戰鼓，掠野過陰兵。", "掃蕩無餘靄，顛摧鮮立莖。", "五山摇岌嶪，九鼎沸煎烹。", "玉石焚岡裂，波濤卷海傾。", "遥聽午合市，爭呼夜驚營。", "慘極雲無色，陰窮火自生。", "電鞭時砉劃，雷軸助喧轟。", "孔竅千聲出，陰幽百怪呈。", "狐妖憑莽蒼，鬼焰走青熒。", "奮怒神增悚，中休耳暫清。", "胡兵占月暈，江客候鼉鳴。", "飄葉千艘失，飛空萬瓦輕。", "獵豪添馬健，舶穩想帆征。", "畏壓頻移席，陰祈屢整纓。", "凍消初醒蟄，枯活欲抽萌。", "病體愁山館，春寒賴酒鐺。", "雞號天地白，登垅看晴明。"]'),
('43d97f58-b220-4e9d-ad31-6c2478d284f5','過中渡二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','中渡橋邊十里堤，寒蟬落盡柳條衰。',32,'全唐诗/poet.song.17000.json','["中渡橋邊十里堤，寒蟬落盡柳條衰。", "年年塞下春風晚，誰見輕黄弄色時。"]'),
('b79f6734-b782-4760-91ee-41e932b24a40','過中渡二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','得歸還自歎淹留，中渡橋邊柳拂頭。',32,'全唐诗/poet.song.17000.json','["得歸還自歎淹留，中渡橋邊柳拂頭。", "記得來時橋上過，斷冰殘雪滿河流。"]'),
('68d8b72c-3b79-420b-baee-d2f260d5fc71','自河北貶滁州初入汴河聞鴈','歐陽修','宋','宋诗','song-poetry','','[]','陽城淀裏新來鴈，趁伴南飛逐越船。',32,'全唐诗/poet.song.17000.json','["陽城淀裏新來鴈，趁伴南飛逐越船。", "野岸柳黄霜正白，五更驚破客愁眠。"]'),
('588d1d9f-01af-48fb-b014-e1112320cfbc','自勉','歐陽修','宋','宋诗','song-poetry','','[]','引水澆花不厭勤，便須已有鎮陽春。',32,'全唐诗/poet.song.17000.json','["引水澆花不厭勤，便須已有鎮陽春。", "官居處處如郵傳，誰得三年作主人。"]'),
('e7c47e84-0935-43e1-9439-5d33a12f6563','席上送劉都官','歐陽修','宋','宋诗','song-poetry','','[]','都城車馬日喧喧，雖有離歌不慘顔。',64,'全唐诗/poet.song.17000.json','["都城車馬日喧喧，雖有離歌不慘顔。", "豈似客亭臨野岸，暫留罇酒對青山。", "天街樹綠騰歸騎，玉殿霜清綴曉班。", "莫忘西亭曾醉處，月明風溜響潺潺。"]'),
('15489c78-1970-487e-9e80-2541822c135e','寄劉都官','歐陽修','宋','宋诗','song-poetry','','[]','別後山光寒更綠，秋深酒美色仍清。',32,'全唐诗/poet.song.17000.json','["別後山光寒更綠，秋深酒美色仍清。", "繞亭黄菊同君種，獨對殘芳醉不成。"]'),
('9432b760-5f84-453c-b809-92409c589b2d','書王元之畫像側','歐陽修','宋','宋诗','song-poetry','','[]','偶然來繼前賢迹，信矣皆如昔日言。',64,'全唐诗/poet.song.17000.json','["偶然來繼前賢迹，信矣皆如昔日言。", "諸縣豐登少公事，一家飽暖荷君恩。", "想公風采常如在，顧我文章不足論。", "名姓已光青史上，壁間容貌任塵昏。"]'),
('89db42fe-e04c-4dc2-87a3-ad82c9ac724a','送京西提刑趙學士','歐陽修','宋','宋诗','song-poetry','','[]','題輿嘗屈佐留京，攬轡今行按屬城。',64,'全唐诗/poet.song.17000.json','["題輿嘗屈佐留京，攬轡今行按屬城。", "楚館尚看淮月色，嵩雲應虎過關迎。", "春寒酒力風中醒，日暖梅香雪後清。", "野俗經年留惠愛，莫辭臨別醉冠傾。"]'),
('56b8474e-e8bc-42af-8ee9-1aec879e79e8','寄題宜城縣射亭','歐陽修','宋','宋诗','song-poetry','','[]','作邑三年事事勤，宜城風物自君新。',64,'全唐诗/poet.song.17000.json','["作邑三年事事勤，宜城風物自君新。", "已能爲政留遺愛，何必栽花遺後人。", "藹若芝蘭芳可襲，溫如金玉粹而純。", "友朋欣慕自如此，何況斯民父母親。"]'),
('3b1cfe21-c8d7-4407-b0ac-24dd0be1330c','豐樂亭遊春三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','綠樹交加山鳥啼，晴風蕩落花飛。',31,'全唐诗/poet.song.17000.json','["綠樹交加山鳥啼，晴風蕩落花飛。", "鳥歌花舞太守醉，明日酒醒春已歸。"]'),
('7e99d773-cbbf-4879-a583-209ba47d23c3','豐樂亭遊春三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','春雲淡淡日輝輝，草惹行襟絮拂衣。',32,'全唐诗/poet.song.17000.json','["春雲淡淡日輝輝，草惹行襟絮拂衣。", "行到亭西逢太守，籃輿酩酊插花歸。"]'),
('a562d6f7-c005-4c73-8c13-b30471688706','豐樂亭遊春三首  其三','歐陽修','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u5b8b\u8bd7", "\u5199\u666f"]','紅樹青山日欲斜，長郊草色綠無涯。',32,'全唐诗/poet.song.17000.json','["紅樹青山日欲斜，長郊草色綠無涯。", "遊人不管春將老，來往亭前踏落花。"]'),
('33c2da2c-edb8-4a9f-b28b-72f2b5e932e3','謝判官幽谷種花','歐陽修','宋','宋诗','song-poetry','','[]','淺深紅日宜相間，先後仍須次第栽。',32,'全唐诗/poet.song.17000.json','["淺深紅日宜相間，先後仍須次第栽。", "我欲四時携酒去，莫教一日不花開。"]'),
('344d8ae2-4fbd-40fd-854a-1c48aa7b700e','畫眉鳥','歐陽修','宋','宋诗','song-poetry','','["\u5bd3\u4eba", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u9e1f", "\u9e1f"]','百囀千聲隨意移，山花紅紫樹高低。',32,'全唐诗/poet.song.17000.json','["百囀千聲隨意移，山花紅紫樹高低。", "始知鎖向金籠聽，不及林間自在啼。"]'),
('c013be2d-7688-45d0-8fb2-94bc5258d1a3','懷嵩樓新開南軒與郡僚小飲','歐陽修','宋','宋诗','song-poetry','','[]','繞郭雲煙匝幾重，昔人曾此感懷嵩。',64,'全唐诗/poet.song.17000.json','["繞郭雲煙匝幾重，昔人曾此感懷嵩。", "霜林落後山爭出，野菊開時酒正濃。", "解带西風飄畫角，倚欄斜日照青松。", "會須乘醉携嘉客，踏雪來看羣玉峯。"]'),
('d17915ab-0a33-48a4-9456-5d9a423b1d3f','送張生','歐陽修','宋','宋诗','song-poetry','','[]','一別相逢十七百，頹顔衰髮互相詢。',64,'全唐诗/poet.song.17000.json','["一別相逢十七百，頹顔衰髮互相詢。", "江湖我再爲遷客，道路君猶困旅人。", "老驥骨奇心尚壯，青松歲久色逾新。", "山城寂寞難爲禮，濁酒無辭舉爵頻。"]'),
('d05179c6-40da-4ef9-bf70-9959fa97f04e','田家','歐陽修','宋','宋诗','song-poetry','','[]','綠桑高下映平川，賽罷田神笑語喧。',32,'全唐诗/poet.song.17000.json','["綠桑高下映平川，賽罷田神笑語喧。", "林外鳴鳩春雨歇，屋頭初日杏花繁。"]'),
('37125c12-4e30-427a-bddf-cc98902e7e84','別滁','歐陽修','宋','宋诗','song-poetry','','["\u53d9\u4e8b", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u79bb\u522b"]','花光濃爛柳輕明，酌酒花前送我行。',32,'全唐诗/poet.song.17000.json','["花光濃爛柳輕明，酌酒花前送我行。", "我亦且如常日醉，莫教絃管作離聲。"]'),
('6459ae3f-4c58-409b-9bd8-876738a40d6f','答謝判官獨遊幽谷見寄','歐陽修','宋','宋诗','song-poetry','','[]','聞道西亭偶獨登，悵然懷我未忘情。',64,'全唐诗/poet.song.17000.json','["聞道西亭偶獨登，悵然懷我未忘情。", "新花自向遊人笑，啼鳥猶爲舊日聲。", "因拂醉題詩句在，應憐手種樹陰成。", "須知別後無由到，莫厭頻携野客行。"]'),
('0781d6ef-2548-4763-9a73-c663a3b2e805','招許主客','歐陽修','宋','宋诗','song-poetry','','[]','欲將何物招嘉客，惟有新秋一味凉。',65,'全唐诗/poet.song.17000.json','["欲將何物招嘉客，惟有新秋一味凉。", "更掃廣庭許寬百畝，少容明月放清光。", "樓頭破鑑看將滿，甕面浮蛆撥已香。", "仍約多爲詩準備，共防梅老敵難當。"]'),
('052b8594-96fa-4d57-b4ed-f078f3add211','金鳳花','歐陽修','宋','宋诗','song-poetry','','[]','憶繞朱欄手自栽，綠叢高下幾番開。',32,'全唐诗/poet.song.17000.json','["憶繞朱欄手自栽，綠叢高下幾番開。", "中庭雨過無人迹，狼籍深紅點綠苔。"]'),
('140718e6-8096-4502-bf47-0750c90c71fe','鷺鷥','歐陽修','宋','宋诗','song-poetry','','[]','風格孤高塵外物，性情閑暇水邊身。',32,'全唐诗/poet.song.17000.json','["風格孤高塵外物，性情閑暇水邊身。", "盡日獨行溪淺處，青苔白石見纖鱗。"]'),
('e81c8c17-76a5-49e7-aabf-c6fd70cfc00b','野鵲','歐陽修','宋','宋诗','song-poetry','','[]','鮮鮮毛羽耀朝輝，紅粉牆頭綠樹枝。',32,'全唐诗/poet.song.17000.json','["鮮鮮毛羽耀朝輝，紅粉牆頭綠樹枝。", "日暖風輕言語軟，應將喜報主人知。"]'),
('abda8f47-2a89-4116-bb3a-2e24b52adb5a','木芙蓉','歐陽修','宋','宋诗','song-poetry','','[]','種處雪消春始動，開時霜落鴈初過。',32,'全唐诗/poet.song.17000.json','["種處雪消春始動，開時霜落鴈初過。", "誰栽金菊叢相近，織出新番蜀錦窠。"]'),
('b6e16143-28d9-48e5-ac18-97d22b7ee8c5','樵者','歐陽修','宋','宋诗','song-poetry','','[]','雲際依依認舊林，斷崖荒磴路難尋。',32,'全唐诗/poet.song.17000.json','["雲際依依認舊林，斷崖荒磴路難尋。", "西山望見朝來雨，南澗歸時渡處深。"]'),
('69677e17-3192-4e8c-9644-e8534e3a2220','詠雪','歐陽修','宋','宋诗','song-poetry','','[]','至日陽初復，豐年瑞遽臻。',144,'全唐诗/poet.song.17000.json','["至日陽初復，豐年瑞遽臻。", "飄颻初未積，散漫忽無垠。", "萬木青煙滅，千門白晝新。", "往來衝更合，高下著何勻。", "望好登長榭，平堪走畫輪。", "馬寒毛縮蝟，弓勁力添鈞。", "客醉看成眩，兒嬌咀且顰。", "虛堂明永夜，高閣照清晨。", "樹石詩翁對，川原獵騎陳。", "凍狐迷舊穴，饑雀噪空囷。", "此土偏宜稼，而予濫長人。", "應須待和暖，載酒共行春。"]'),
('6f3c0bcc-2bb9-4a3f-9a66-8b05e8c1fc58','送楊先輩登第還家','歐陽修','宋','宋诗','song-poetry','','[]','解榻方欣待儁英，掛帆千里忽南征。',64,'全唐诗/poet.song.17000.json','["解榻方欣待儁英，掛帆千里忽南征。", "錦衣白日還家樂，鶴髮高堂獻壽榮。", "殘雪楚天寒料峭，春風淮水浪崢嶸。", "知君歸意先飛鳥，莫惜停舟酒屢傾。"]'),
('69915757-c8aa-499b-b47d-3fad55d7f325','初至潁州西湖種瑞蓮黄楊與郡官小酌其上聊書所見寄淮南轉運呂度支發運許主客','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平湖十頃碧琉璃，四面清陰乍合時。',64,'全唐诗/poet.song.17000.json','["平湖十頃碧琉璃，四面清陰乍合時。", "柳絮已將春去遠，海棠應恨我來遲。", "啼禽似與遊人語，明月閑撐野艇隨。", "每到最佳堪樂處，却思君共把芳巵。"]'),
('9d471035-b4b7-41b5-8bd0-e68f3f0b74c5','三橋詩 宜遠','歐陽修','宋','宋诗','song-poetry','','[]','朱欄明綠水，古柳照斜陽。',24,'全唐诗/poet.song.17000.json','["朱欄明綠水，古柳照斜陽。", "何處偏宜望，清漣對女郎。"]'),
('e04eb3f2-e5cb-4264-8088-003f1e555d9a','三橋詩 飛蓋','歐陽修','宋','宋诗','song-poetry','','[]','鳴騶入遠樹，飛蓋渡長橋。',24,'全唐诗/poet.song.17000.json','["鳴騶入遠樹，飛蓋渡長橋。", "水闊鷺雙起，波明魚自跳。"]'),
('3c0c553f-184a-4551-b1e7-3359c6477e07','三橋詩 望佳','歐陽修','宋','宋诗','song-poetry','','[]','輕舟轉孤嶼，幽浦漾平波。',24,'全唐诗/poet.song.17000.json','["輕舟轉孤嶼，幽浦漾平波。", "回看望佳處，歸路逐魚歌。"]'),
('d2253840-a4cb-409a-87fa-18fe8f6da2b2','答通判呂太博','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千頃芙蕖蓋水平，揚州太守舊多情。',64,'全唐诗/poet.song.17000.json','["千頃芙蕖蓋水平，揚州太守舊多情。", "畫盆圍處花光合，紅袖傳來酒令行。", "舞踏落暉留醉客，歌遲檀板換新聲。", "如今寂寞西湖上，雨後無人看落英。"]'),
('6321aedc-9ef7-4cbf-8a6e-6fb57de2dc7d','祈雨曉過湖上','歐陽修','宋','宋诗','song-poetry','','[]','清晨驅馬思悠然，渺渺平湖碧玉田。',64,'全唐诗/poet.song.17000.json','["清晨驅馬思悠然，渺渺平湖碧玉田。", "曉日未昇先起霧，綠陰初合自生煙。", "身閑始覺時光好，春去猶餘物色妍。", "更待四郊甘雨足，相隨蕭鼓樂豐年。"]'),
('fedc5eaf-d64c-49e0-aa38-bfeb67cac405','送謝中舍二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','滁南幽谷抱山斜，我鑿清泉子種花。',64,'全唐诗/poet.song.17000.json','["滁南幽谷抱山斜，我鑿清泉子種花。", "故事已傳遺老說，世人今作畫圖誇。", "金閨引籍子方壯，白髮盈簪我可嗟。", "試問弦歌爲縣政，何知罇俎樂無涯。"]'),
('ee84124e-9943-485e-b341-18dbdfdcf8b9','送謝中舍二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','喜聞嘉譽藹淮壖，又看吳帆解畫船。',64,'全唐诗/poet.song.17000.json','["喜聞嘉譽藹淮壖，又看吳帆解畫船。", "隴畝遺民談舊政，江山餘思入新篇。", "人生白首吾今爾，仕路青雲子勉旃。", "舉棹南風吹酒醒，禽觴莫惜少留連。"]'),
('b1bbe1c8-cbae-4921-b3df-07d7a74ed0d7','酬張器判官泛溪','歐陽修','宋','宋诗','song-poetry','','[]','園林初夏有清香，人意乘閑味愈長。',64,'全唐诗/poet.song.17000.json','["園林初夏有清香，人意乘閑味愈長。", "日暖魚跳波面靜，風輕鳥語樹陰凉。", "野亭飛蓋臨芳草，曲渚迴舟带夕陽。", "所得平時爲郡樂，況多嘉客共銜觴。"]'),
('397a6cbc-f9ab-4742-bba2-60507da7e736','西園石榴盛開','歐陽修','宋','宋诗','song-poetry','','[]','荒臺野徑共躋攀，正見榴花出短垣。',64,'全唐诗/poet.song.17000.json','["荒臺野徑共躋攀，正見榴花出短垣。", "綠葉晚鸎啼處密，紅房初日照時繁。", "最憐夏景鋪珍簟，尤愛晴香入睡軒。", "乘興便當携酒去，不須旌騎擁車轅。"]'),
('e30e55bb-983b-4473-9c1f-4bab60121d75','西湖戲作示同遊者','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','菡萏香清畫舸浮，使君寧復憶揚州。',32,'全唐诗/poet.song.17000.json','["菡萏香清畫舸浮，使君寧復憶揚州。", "都將二十四橋月，換得西湖十頃秋。"]'),
('6e51f338-aa9e-483c-8798-2f2acf3bf77f','夢中作','歐陽修','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u79cb\u5929", "\u591c\u665a", "\u5199\u666f"]','夜凉吹笛千山月，路暗迷人百種花。',32,'全唐诗/poet.song.17000.json','["夜凉吹笛千山月，路暗迷人百種花。", "棊罷不知人換世，酒闌無奈客思家。"]'),
('c54897ca-2510-43a4-a623-68adba271e35','秀才歐世英惠然見訪其還也聊以贈之','歐陽修','宋','宋诗','song-poetry','','[]','相逢十年舊，暫喜一罇同。',48,'全唐诗/poet.song.17000.json','["相逢十年舊，暫喜一罇同。", "昔日青衫令，今爲白髮翁。", "俟時君子守，求士有司公。", "況子之才美，焉能久困窮。"]'),
('27649c2f-707a-4bc1-ae97-7a05d961185f','送楊君之任永康','歐陽修','宋','宋诗','song-poetry','','[]','劍峰雲棧未嘗行，圖畫曾看已可驚。',64,'全唐诗/poet.song.17000.json','["劍峰雲棧未嘗行，圖畫曾看已可驚。", "險若登天懸鳥道，下臨無地瀉江聲。", "折腰莫以微官恥，爲政須通異俗情。", "況子多才兼美行，薦章期即達承明。"]'),
('9f6ec55a-c93b-443b-8429-01c89fd2e4ad','紀德陳情上致政太傅杜相公二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','儉節清名世絕倫，坐令風俗可還淳。',64,'全唐诗/poet.song.17000.json','["儉節清名世絕倫，坐令風俗可還淳。", "貌先年老因憂國，事與心違始乞身。", "四海儀刑瞻舊德，一罇談笑作閑人。", "鈴齋幸得親師席，東向時容問治民。"]'),
('ac11743c-d6fb-4ad0-b974-a4fc79a86ec3','紀德陳情上致政太傅杜相公二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','事國一心勤以瘁，還家五福壽而康。',63,'全唐诗/poet.song.17000.json','["事國一心勤以瘁，還家五福壽而康。", "風波已出憑忠信，松栢難凋雪霜。", "昔日青衫遇知己，今來白首再升堂。", "里門每入從千騎，賓主俱榮道路光。"]'),
('a1b84eb1-8af9-422d-85b2-031ed4f2bed0','太傅杜相公索聚星堂詩謹成','歐陽修','宋','宋诗','song-poetry','','[]','楚肆固知難衒玉，丘門安敢輒論詩。',64,'全唐诗/poet.song.17000.json','["楚肆固知難衒玉，丘門安敢輒論詩。", "藏之十襲真無用，報以雙金豈所宜。", "已恨語言多猥冗，況因盃杓正淋漓。", "願投几格資咍噱，俗展須於欲睡時。"]'),
('f59992df-2fc8-4517-85d7-17e127de6c14','和太傅杜相公寵示之作','歐陽修','宋','宋诗','song-poetry','','[]','平生孤拙荷公知，敢向公前自衒時。',64,'全唐诗/poet.song.17000.json','["平生孤拙荷公知，敢向公前自衒時。", "憂患飄流誠已甚，文辭衰落固其宜。", "非高僅比巴音下，少味還同魯酒漓。", "兩辱嘉篇永爲寶，豈惟榮耀詫當時。"]'),
('92335fe6-37e6-4493-89b9-c54b167dfb63','太傅杜相公有答兗州待制之句其卒章云獨無風雅可流傳因輒成','歐陽修','宋','宋诗','song-poetry','','[]','南都已見成新集，東魯休嗟未作詩。',64,'全唐诗/poet.song.17000.json','["南都已見成新集，東魯休嗟未作詩。", "霖雨曾爲天下福，甘棠何止郡人思。", "元劉事業時無取，姚宋篇章世不知。", "二美惟公所兼有，後生何者欲攀追。"]'),
('acf62429-daa4-4934-bfcf-ddbea5fbe305','依韻答杜相公寵示之作','歐陽修','宋','宋诗','song-poetry','','[]','醉翁豐樂一閑身，憔悴今來汴水濱。',64,'全唐诗/poet.song.17000.json','["醉翁豐樂一閑身，憔悴今來汴水濱。", "每聽鳥聲知改節，因吹柳絮惜殘春。", "平生未省降詩敵，到處何嘗訴酒巡。", "壯志銷磨都已盡，看花翻作飲茶人。"]'),
('cbf73176-bd14-4957-a6bb-a52564be2b39','依韻和杜相公喜雨之什','歐陽修','宋','宋诗','song-poetry','','[]','歲時豐儉若循環，天幸非由拙政然。',64,'全唐诗/poet.song.17000.json','["歲時豐儉若循環，天幸非由拙政然。", "一雨雖知爲美澤，三登猶未補兇年。", "桑陰蔽日交垂路，麥穗含風秀滿田。", "千里郊原想如畫，正宜携酒望晴川。"]'),
('48430698-33c1-4533-8aed-c5b5a5c02ace','謝太傅杜相公寵示嘉篇','歐陽修','宋','宋诗','song-poetry','','[]','凜凜節奇霜澗栢，昭昭心瑩玉壺冰。',64,'全唐诗/poet.song.17000.json','["凜凜節奇霜澗栢，昭昭心瑩玉壺冰。", "正身尚可清風俗，當暑何須厭鬰蒸。", "麈柄屢揮容請益，龍門雖峻忝先登。", "立朝行己師資久，寧止篇章此服膺。"]'),
('41c22162-f1b3-4577-8f64-196ad23eec27','答杜相公寵示去思堂詩','歐陽修','宋','宋诗','song-poetry','','[]','當年丞相倦洪鈞，弭節初來潁水濆。',64,'全唐诗/poet.song.17000.json','["當年丞相倦洪鈞，弭節初來潁水濆。", "惟以琴罇樂嘉客，能將富貴比浮雲。", "西溪水色春長綠，北渚花光暖自薰。", "得載公詩播人口，去思從此四夷聞。"]'),
('781c58bf-b23c-4f0e-8ab1-d5d815a01075','答太傅相公見贈長韻','歐陽修','宋','宋诗','song-poetry','','[]','蹤跡本羈單，登門二十年。',120,'全唐诗/poet.song.17000.json','["蹤跡本羈單，登門二十年。", "平生任愚拙，自進恥因緣。", "憂患經多矣，疲駑尚勉旃。", "凋零鸎谷友，憔悴鴈池邊。", "忽忽良時失，區區俗慮闐。", "公齋每偷暇，師席屢攻堅。", "善誨常無倦，餘談亦可編。", "仰高雖莫及，希驥豈非賢。", "報國如乖顧，歸耕寧買田。", "期無辱知己，肯逐利名遷。"]'),
('bc4646b3-83a8-4620-b194-5b2891b01769','借觀五老詩次韻爲謝','歐陽修','宋','宋诗','song-poetry','','[]','脫遺軒冕就安閑，笑傲丘園縱倒冠。',64,'全唐诗/poet.song.17000.json','["脫遺軒冕就安閑，笑傲丘園縱倒冠。", "白髮憂民雖種種，丹心許國尚桓桓。", "鴻冥得路高難慕，松老無風韻自寒。", "聞說優游多唱和，新篇何惜盡傳看。"]'),
('bab61f58-10b3-440f-95b8-fd7e0c3507c9','答杜相公惠詩','歐陽修','宋','宋诗','song-poetry','','[]','藥苗本是山家味，茶具偏於野客宜。',64,'全唐诗/poet.song.17000.json','["藥苗本是山家味，茶具偏於野客宜。", "敢以微誠將薄物，少資清興入新詩。", "言無俗韻精而勁，筆有神鋒老更奇。", "二寶收藏傳百世，豈惟榮耀詫當時。"]'),
('f10cc129-d517-4f56-acb2-726cb1394536','去思堂手植雙柳今已成陰因而有感','歐陽修','宋','宋诗','song-poetry','','[]','曲欄高柳拂層簷，却憶初栽映碧潭。',64,'全唐诗/poet.song.17000.json','["曲欄高柳拂層簷，却憶初栽映碧潭。", "人昔共遊今孰在，樹猶如此我何堪。", "壯心無復身從老，世事都銷酒半酣。", "後日更來知有幾，攀條莫惜駐征驂。"]'),
('754567b6-603c-411d-b62b-c3e8a3cb87ce','和陸子履再遊城西李園','歐陽修','宋','宋诗','song-poetry','','[]','京師花木類多奇，常恨春歸人不歸。',64,'全唐诗/poet.song.17000.json','["京師花木類多奇，常恨春歸人不歸。", "車馬喧喧走塵土，園林處處鎖芳菲。", "殘紅已落香猶在，羈客多傷涕自揮。", "我亦悠然無事者，約君聯騎訪郊圻。"]'),
('bfcda06c-da07-4fa0-8c1f-6ffd12ae88e9','內直對月寄子華舍人持國廷評','歐陽修','宋','宋诗','song-poetry','','[]','禁署沉沉玉漏傳，月華雲表溢金盤。',64,'全唐诗/poet.song.17000.json','["禁署沉沉玉漏傳，月華雲表溢金盤。", "纖埃不隔光初滿，萬物無聲夜向闌。", "蓮燭燒殘愁夢斷，蕙爐薰歇覺衣單。", "水精宮鎖黄金闕，故比人間分外寒。"]'),
('b054e83c-6c24-4a82-afce-54fb4929dd21','答子華舍人退朝小飲官舍','歐陽修','宋','宋诗','song-poetry','','[]','玉階朝罷卷晨班，官舍相留一笑間。',64,'全唐诗/poet.song.17000.json','["玉階朝罷卷晨班，官舍相留一笑間。", "與世漸疏嗟已老，得朋爲樂偶偷閑。", "紅牋搦管吟紅藥，綠酒盈罇舞綠鬟。", "自是風情年少事，多慙白髮與蒼顔。"]'),
('5607cff2-9e64-4cf6-9473-6326d4d809ed','內直晨出便赴奉慈齋宮馬上口占','歐陽修','宋','宋诗','song-poetry','','[]','凌晨更直九門開，驅馬悠悠望禁街。',64,'全唐诗/poet.song.17000.json','["凌晨更直九門開，驅馬悠悠望禁街。", "霜後樓臺明曉日，天寒煙霧著宮櫰。", "山林未去猶貪寵，罇酒何時共放懷。", "已覺蕭條悲晚歲，更憐衰病怯清齋。"]'),
('8a5e1f16-fd04-4314-b126-311aff73e492','景靈朝謁從駕還宮','歐陽修','宋','宋诗','song-poetry','','[]','琳館清晨藹瑞氛，玉旒朝罷奏詔鈞。',64,'全唐诗/poet.song.17000.json','["琳館清晨藹瑞氛，玉旒朝罷奏詔鈞。", "綠槐夾路飛黄蓋，翠輦鳴鞘向紫宸。", "金闕日高猶泫露，綵旗風細不驚塵。", "自慙白首追時彥，行近儲胥忝侍臣。"]'),
('10186de9-44f2-44d9-b210-2aae252f46f9','憶滁州幽谷','歐陽修','宋','宋诗','song-poetry','','[]','滁南幽谷抱千峯，高下山花遠近紅。',64,'全唐诗/poet.song.17000.json','["滁南幽谷抱千峯，高下山花遠近紅。", "當日辛勤皆手植，而今開落任春風。", "主人不覺悲華髮，野老猶能說醉翁。", "誰與援琴親寫取，夜泉聲在翠微中。"]'),
('52445fc5-6f56-4a7e-8e9b-fb296a46c64e','和韓學士襄州聞喜亭置酒','歐陽修','宋','宋诗','song-poetry','','[]','巀嶭高城漢水邊，登臨誰與共躋攀。',64,'全唐诗/poet.song.17000.json','["巀嶭高城漢水邊，登臨誰與共躋攀。", "清川萬古流不盡，白鳥雙飛意自閑。", "可笑沉碑憂岸谷，誰能把酒對江山。", "少年我亦曾遊目，風物今思一夢還。"]'),
('4dfb93e8-ad82-42f4-b0c7-a34bfdf52bf0','寄題梅龍圖滑州溪園','歐陽修','宋','宋诗','song-poetry','','[]','聞說溪園景漸佳，遥知清興已無涯。',64,'全唐诗/poet.song.17000.json','["聞說溪園景漸佳，遥知清興已無涯。", "飲闌歸騎多乘月，雪後尋春自探花。", "百囀黄鸝消永日，雙飛白鳥避鳴笳。", "平生喜接君酬唱，不得罇前詠落霞。"]'),
('e63f6ca1-f335-486f-b12c-17ca1635cbdd','奉使道中五言長韻','歐陽修','宋','宋诗','song-poetry','','[]','初旭瑞霞烘，都門祖帳供。',240,'全唐诗/poet.song.17000.json','["初旭瑞霞烘，都門祖帳供。", "親持使者節，曉出大明宮。", "城闕青煙起，樓臺白霧中。", "繡韉驕躍躍，貂袖紫蒙蒙。", "朔野驚飆慘，邊城畫角雄。", "過橋分一水，回首羨南鴻。", "地里山川隔，天文日月同。", "兒童能走馬，婦女亦腰弓。", "度險行愁失，盤高路欲窮。", "山深聞喚鹿，林黑自生風。", "松壑寒逾響，冰溪咽復通。", "望平愁驛迥，野曠覺天穹。", "駿足來山北，輕禽出海東。", "合圍飛走盡，移帳水泉空。", "講信鄰方睦，尊賢禮亦隆。", "斫冰燒酒赤，凍膾縷霜紅。", "白草經春在，黄沙盡日濛。", "新年風漸變，歸路雪初融。", "祗事須彊力，嗟予乃病翁。", "深慙漢蘇武，歸國不論功。"]'),
('9f58b456-db15-45cf-92e9-aabe55c3d02f','奉使契丹初至雄州','歐陽修','宋','宋诗','song-poetry','','[]','古關衰柳聚寒鵶，駐馬城頭日欲斜。',32,'全唐诗/poet.song.17000.json','["古關衰柳聚寒鵶，駐馬城頭日欲斜。", "猶去西樓二千里，行人到此莫思家。"]'),
('c4a98e9f-4d28-41a0-8126-4ee12b25cfe5','奉使契丹回出上京馬上作','歐陽修','宋','宋诗','song-poetry','','[]','紫貂裘暖朔風驚，潢水冰光射日明。',32,'全唐诗/poet.song.17000.json','["紫貂裘暖朔風驚，潢水冰光射日明。", "笑語同來向公子，馬頭今日向南行。"]'),
('caeb5b5f-8756-4d71-ab58-205c17086678','送渭州王圖','歐陽修','宋','宋诗','song-poetry','','[]','漢軍十萬控山河，玉帳優游暇日多。',64,'全唐诗/poet.song.17000.json','["漢軍十萬控山河，玉帳優游暇日多。", "夷狄從來懷信義，廟堂今不用干戈。", "吟餘畫角吹殘月，醉裏紅燈炫綺羅。", "此樂直須年少壯，嗟余心志已蹉跎。"]'),
('ee42f7f0-ac33-4751-92c5-8384c60a9dae','李留後家聞箏坐上作','歐陽修','宋','宋诗','song-poetry','','[]','不聽哀箏二十年，忽逢纖指弄鳴絃。',64,'全唐诗/poet.song.17000.json','["不聽哀箏二十年，忽逢纖指弄鳴絃。", "緜蠻巧囀花間舌，嗚咽交流冰下泉。", "常謂此聲今已絕，問渠從小自誰傳。", "樽前笑我聞彈罷，白髮蕭然涕泫然。"]'),
('7faacb37-3663-45c1-9d52-013adda1ee11','送鄆州李留後','歐陽修','宋','宋诗','song-poetry','','[]','北州遺頌藹嘉聲，東土還聞政有成。',64,'全唐诗/poet.song.17000.json','["北州遺頌藹嘉聲，東土還聞政有成。", "組甲光寒圍夜帳，綵旗風暖看春耕。", "金釵墜鬢分行立，玉麈高談四坐傾。", "富貴常情誰不羨，愛君風韻有餘清。"]'),
('69910ef4-5240-42ee-a1db-8c8cfbd3d16b','子華學士儤直未滿遽出館伴病夫遂當輪宿輒成拙句奉呈','歐陽修','宋','宋诗','song-poetry','','[]','萬釘寶带爛腰鐶，賜宴新陪一笑歡。',64,'全唐诗/poet.song.17000.json','["萬釘寶带爛腰鐶，賜宴新陪一笑歡。", "金馬並遊年最少，玉堂初直夜猶寒。", "自嗟零落凋顔鬢，晚得飛翔接羽翰。", "今日遽聞催遞宿，不容多病養衰殘。"]'),
('8d2d716d-3c96-4697-b58a-653fc8742b8f','禮部貢院閱進士就試','歐陽修','宋','宋诗','song-poetry','','["\u559c\u60a6", "\u6292\u60c5", "\u8003\u8bd5"]','紫案焚香暖吹輕，廣庭清曉席羣英。',64,'全唐诗/poet.song.17000.json','["紫案焚香暖吹輕，廣庭清曉席羣英。", "無譁戰士銜枚勇，下筆春蠶食葉聲。", "鄉里獻賢先德行，朝廷列爵待公卿。", "自慙衰病心神耗，賴有羣公鑒裁精。"]'),
('2e4f2813-537f-4e49-b024-51ddba5b8471','和梅聖俞元夕登東樓','歐陽修','宋','宋诗','song-poetry','','[]','遊豫恩同萬國懽，新年佳節候初還。',64,'全唐诗/poet.song.17000.json','["遊豫恩同萬國懽，新年佳節候初還。", "華燈爍爍春風裏，黄傘亭亭瑞霧間。", "可愛清光澄夜色，遥知喜氣動天顔。", "自憐曾預稱觴列，獨宿冰廳夢帝關。"]'),
('71bc0699-4f9d-4e70-89dd-ca21f794b958','再和','歐陽修','宋','宋诗','song-poetry','','[]','禁城東馬夜喧喧，閑繞危欄去復還。',64,'全唐诗/poet.song.17000.json','["禁城東馬夜喧喧，閑繞危欄去復還。", "遥望觚稜煙靄外，似聞天樂夢魂間。", "豈無罇酒當佳節，況有朋歡慰病顔。", "待得歸時花在否，春禽簷際已關關。"]'),
('8a695af0-2aaf-4e6d-a6b4-bdc5442c6a78','又和','歐陽修','宋','宋诗','song-poetry','','[]','憑高寓目偶乘閑，袨服遊人見往還。',64,'全唐诗/poet.song.17000.json','["憑高寓目偶乘閑，袨服遊人見往還。", "明月正臨雙闕上，行歌遥聽九衢間。", "黄金絡馬追朱幰，紅燭籠紗照玉顔。", "與世漸疏嗟老矣，佳辰樂事豈相關。"]'),
('ef50e44b-998c-4093-9006-6c58c123d95d','憶鶴呈公儀','歐陽修','宋','宋诗','song-poetry','','[]','一笑相驩樂得朋，誦君雙鶴句尤清。',64,'全唐诗/poet.song.17000.json','["一笑相驩樂得朋，誦君雙鶴句尤清。", "高懷自喜凌雲格，俗耳誰思警露聲。", "所好與時雖異趣，累心於物豈非情。", "歸休約我携琴去，共看婆娑舞月明。"]'),
('0289982b-ffa3-419c-af60-7b8e5902ba17','答王禹玉見贈','歐陽修','宋','宋诗','song-poetry','','[]','昔時叨入武成宮，曾看揮毫氣吐虹。',64,'全唐诗/poet.song.17000.json','["昔時叨入武成宮，曾看揮毫氣吐虹。", "夢寐閑思十年舊，笑談今此一罇同。", "喜君新賜黄金带，顧我宜爲白髮翁。", "自古薦賢爲報國，幸依精識士稱公。"]'),
('a11186eb-f93a-453b-9993-bdefd5400635','答王內翰范舍人','歐陽修','宋','宋诗','song-poetry','','[]','相從一笑歡無厭，屢獲新篇喜可涯。',64,'全唐诗/poet.song.17000.json','["相從一笑歡無厭，屢獲新篇喜可涯。", "自昔居前誚穅秕，幸容相倚媿蒹葭。", "白麻詔令追三代，青史文章自一家。", "我亦諫垣新忝命，君恩未報髮先華。"]'),
('a8e9fc80-36d1-4a00-95c2-6cbc5318fa5a','戲答聖俞持燭之句','歐陽修','宋','宋诗','song-poetry','','[]','辱君贈我言雖厚，聽我酬君意不同。',64,'全唐诗/poet.song.17000.json','["辱君贈我言雖厚，聽我酬君意不同。", "病眼自憎紅蠟燭，何人肯伴白鬚翁。", "花時浪過如春夢，酒敵先甘伏下風。", "惟有吟哦殊不倦，始知文字樂無窮。"]'),
('8cccf2ee-b106-4b8e-8c89-c6f694558823','小桃','歐陽修','宋','宋诗','song-poetry','','[]','雪裏花開人未知，摘來相顧共驚疑。',32,'全唐诗/poet.song.17000.json','["雪裏花開人未知，摘來相顧共驚疑。", "便當索酒花前醉，初見今年第一枝。"]'),
('a180ac35-b460-49e6-84c5-7be2bde91b0b','戲書','歐陽修','宋','宋诗','song-poetry','','[]','支離多病歎衰顔，賴得羣居一笑歡。',64,'全唐诗/poet.song.17000.json','["支離多病歎衰顔，賴得羣居一笑歡。", "人老思家甚年少，身閑泥酒過春寒。", "來時御柳天街凍，歸去梨花禁籞殘。", "纖使開門佳節晚，未妨雙鶴舞霜翰。"]'),
('8f70130c-337e-4d51-8cf7-7d8e51ca5a1e','春雪','歐陽修','宋','宋诗','song-poetry','','[]','逗曉風聲惡，褰簾雪勢斜。',48,'全唐诗/poet.song.17000.json','["逗曉風聲惡，褰簾雪勢斜。", "應憐未歸客，故勒欲開花。", "病思寒添睡，春愁夢在家。", "誰能慰寂寞，惟有酒如霞。"]'),
('56076271-afe5-4e76-8a3e-4e1d4c776c1b','和梅公儀嘗茶','歐陽修','宋','宋诗','song-poetry','','[]','溪山擊鼓助雷驚，逗曉靈芽發翠莖。',64,'全唐诗/poet.song.17000.json','["溪山擊鼓助雷驚，逗曉靈芽發翠莖。", "摘處兩旗香可愛，貢來雙鳳品尤精。", "寒侵病骨惟思睡，花落春愁未解酲。", "喜共紫甌吟且酌，羨君蕭灑有餘清。"]'),
('b6c289a9-ef8b-4207-9b04-448539f776de','和較藝書事','歐陽修','宋','宋诗','song-poetry','','[]','相隨懷詔下天閽，一鎖南宮隔幾旬。',64,'全唐诗/poet.song.17000.json','["相隨懷詔下天閽，一鎖南宮隔幾旬。", "玉麈清談消永日，金罇美酒惜餘春。", "杯盤餳粥春風冷，池館榆錢夜雨新。", "猶是人間好時節，歸休過我莫辭頻。"]'),
('38db7248-6dfa-4a07-b4b3-a656e7901435','和公儀贈白鷴','歐陽修','宋','宋诗','song-poetry','','[]','梅公憐我髭如雪，贈以雙禽意有云。',64,'全唐诗/poet.song.17000.json','["梅公憐我髭如雪，贈以雙禽意有云。", "但見尋常思白兔，便疑不解醉紅裙。", "吟齋雖喜留閑客，野性寧忘在嶺雲。", "我有銅臺方尺瓦，慙非玉案欲酬君。"]'),
('527a9aa7-68aa-4354-8493-e3285e2712a1','再和','歐陽修','宋','宋诗','song-poetry','','[]','佳翫能令百事忘，豈惟閑伴倒餘缸。',64,'全唐诗/poet.song.17000.json','["佳翫能令百事忘，豈惟閑伴倒餘缸。", "珍奇來自海千里，皎潔明如璧一雙。", "日暖朝籠青石砌，春寒夜宿碧紗窗。", "蠻煙瘴霧雖生處，何必區區憶陋邦。"]'),
('aa758cc5-4e09-429b-9cfa-bbb59a18fcb5','和聖俞春雨','歐陽修','宋','宋诗','song-poetry','','[]','簷瓦蕭蕭雨勢疏，寂寥官舍與君俱。',64,'全唐诗/poet.song.17000.json','["簷瓦蕭蕭雨勢疏，寂寥官舍與君俱。", "身遭鎖閉如鸚鵡，病識陰晴似鵓鴣。", "年少自愁花爛熳，春寒偏著老肌膚。", "莫嫌來往傳詩句，不爾須當泥酒壺。"]'),
('39506b5d-3589-4bd5-9c50-bc6dfbd66926','出省有日書事','歐陽修','宋','宋诗','song-poetry','','[]','凌晨小雨壓塵輕，閑憶登高望禁城。',64,'全唐诗/poet.song.17000.json','["凌晨小雨壓塵輕，閑憶登高望禁城。", "樹色連雲春泱漭，風光著草日晴明。", "看榆吐莢驚將落，見鵲移巢忽已成。", "誰向兒童報歸日，爲翁寒食少留餳。"]'),
('072b092e-321a-4cca-a5cf-eea894aff1c5','和較藝將畢','歐陽修','宋','宋诗','song-poetry','','[]','槐柳來時綠未勻，開門節物一番新。',64,'全唐诗/poet.song.17000.json','["槐柳來時綠未勻，開門節物一番新。", "踏青寒食追遊騎，賜火清明忝侍臣。", "拂面蜘蛛占喜事，入簾蝴蝶報家人。", "莫瞋年少思歸切，白髮衰翁尚惜春。"]'),
('1d36f19d-98cb-4eea-91e6-d8b561d3791d','喜定號和禹玉內翰','歐陽修','宋','宋诗','song-poetry','','[]','衡鑒慙叨選，英豪此所鍾。',72,'全唐诗/poet.song.17000.json','["衡鑒慙叨選，英豪此所鍾。", "古今參雅鄭，善惡雜臯共。", "揮翰飄飄思，懷奇落落胸。", "披文驚可畏，奏下始開封。", "但喜真才得，寧虞橫議攻。", "欲知儒學盛，首善本三廱。"]'),
('bca6889b-c0ea-43a9-bd76-0a047a8c05ff','和出省','歐陽修','宋','宋诗','song-poetry','','[]','僮奴補被莫相催，待報霜臺御史來。',64,'全唐诗/poet.song.17000.json','["僮奴補被莫相催，待報霜臺御史來。", "晴陌便當聯騎去，春風任放百花開。", "文章紙貴爭馳譽，朝野人言慶得才。", "共向丹墀侍臨選，莫驚鱗鬣化風雷。"]'),
('a83a10fc-cff6-4543-a093-1062b02458f3','送鄭革先輩賜第南歸','歐陽修','宋','宋诗','song-poetry','','[]','少年鄉譽歎才淹，六十猶隨貢士函。',64,'全唐诗/poet.song.17000.json','["少年鄉譽歎才淹，六十猶隨貢士函。", "握手親朋驚白髮，還愛閭里看青衫。", "閣涵空翠連衡阜，門枕寒江落楚帆。", "試問塵埃勤斗祿，何如琴酒老雲巖。"]'),
('32f1b56f-6617-48a6-a3fc-5a636fe7de2d','和原父揚州六題 時會堂二首 其一','歐陽修','宋','宋诗','song-poetry','','[]','積雪猶封蒙頂樹，驚雷未發建溪春。',32,'全唐诗/poet.song.17000.json','["積雪猶封蒙頂樹，驚雷未發建溪春。", "中州地暖萌牙早，入貢宜先百物新。"]'),
('150e42f7-2e88-49a0-a861-883a1ee6c8f4','和原父揚州六題 時會堂二首 其二','歐陽修','宋','宋诗','song-poetry','','[]','憶昔嘗修守臣職，先春自探兩旗開。',32,'全唐诗/poet.song.17000.json','["憶昔嘗修守臣職，先春自探兩旗開。", "誰知白首來辭禁，得與金鑾賜一杯。"]'),
('de155493-8082-4aba-a1b5-f5c7abf8160a','自東門泛舟至竹西亭登崑丘入蒙谷戲題春貢亭','歐陽修','宋','宋诗','song-poetry','','[]','崑丘蒙谷接新亭，畫舸悠悠春水生。',32,'全唐诗/poet.song.17000.json','["崑丘蒙谷接新亭，畫舸悠悠春水生。", "欲覓揚州使君處，但隨風際管絃聲。"]'),
('aec77a84-aaae-45a1-8656-8324fea17a09','竹西亭','歐陽修','宋','宋诗','song-poetry','','[]','十里樓臺歌吹繁，揚州無復似當年。',32,'全唐诗/poet.song.17000.json','["十里樓臺歌吹繁，揚州無復似當年。", "古來興廢皆如此，徒使登臨一慨然。"]'),
('d461d055-aa33-4c1d-a994-f4211f6be562','崑丘臺','歐陽修','宋','宋诗','song-poetry','','[]','訪古高臺半已傾，春郊誰從綵旗行。',32,'全唐诗/poet.song.17000.json','["訪古高臺半已傾，春郊誰從綵旗行。", "喜聞車馬人同樂，慣聽笙歌鳥不驚。"]'),
('5b6aee29-4f79-441f-84f8-ad90c2ae5e6f','蒙谷','歐陽修','宋','宋诗','song-poetry','','[]','一徑崎嶇入谷中，翠條紅刺罥春叢。',32,'全唐诗/poet.song.17000.json','["一徑崎嶇入谷中，翠條紅刺罥春叢。", "花深時有人相應，竹密初疑路不通。"]'),
('3c64d205-4ad8-4959-9384-f45818d69f6d','內直奉寄聖俞博士','歐陽修','宋','宋诗','song-poetry','','[]','千門鑰入斷人聲，樓閣沉沉夜氣生。',64,'全唐诗/poet.song.17000.json','["千門鑰入斷人聲，樓閣沉沉夜氣生。", "獨直偏知宮漏永，稍寒尤覺玉堂清。", "霜雲映月鱗鱗色，風葉飛空摵摵鳴。", "犬馬力疲恩未報，坐驚時節已崢嶸。"]'),
('3286d827-d490-47b0-aa15-175572e363fd','送梅龍圖公儀和杭州','歐陽修','宋','宋诗','song-poetry','','[]','萬室東南且繁，羨君風力有餘閑。',63,'全唐诗/poet.song.17000.json','["萬室東南且繁，羨君風力有餘閑。", "漁樵人樂江湖外，談笑詩成罇俎間。", "日暖梨花催美酒，天寒桂子落空山。", "郵筒不絕如飛翼，莫惜新篇屢往還。"]'),
('cd911a96-1076-4ec5-acdf-1052a199271c','送沈學士知常州','歐陽修','宋','宋诗','song-poetry','','[]','舊館芸香鎖寂寥，齋舲東下入秋濤。',64,'全唐诗/poet.song.17000.json','["舊館芸香鎖寂寥，齋舲東下入秋濤。", "江晴風暖旌旗颺，木落霜清鼓角高。", "吟就綵牋賓已醉，舞翻紅袖飲方豪。", "平生粗得爲州樂，因羨君行首重搔。"]'),
('7b169e59-9c06-4ee3-96fa-3ce897b95d22','聖俞在南省監印進士試卷有兀然獨坐之歎因思去歲同在禮闈慨然有感兼簡子華景仁','歐陽修','宋','宋诗','song-poetry','','[]','南宮官舍苦蕭條，常憶羣居接儁寮。',64,'全唐诗/poet.song.17000.json','["南宮官舍苦蕭條，常憶羣居接儁寮。", "古屋醉吟燈豔豔，畫廓愁聽雨蕭蕭。", "殘春共約無虛擲，一歲那知忽復銷。", "顧我心情又非昨，祗思相伴老漁樵。"]'),
('25e10918-cf05-4537-9a41-111e06bd1a1e','奉答聖俞歲日書事','歐陽修','宋','宋诗','song-poetry','','[]','積雪照清晨，東風冷著人。',48,'全唐诗/poet.song.17000.json','["積雪照清晨，東風冷著人。", "年光向老速，物意逐時新。", "貰酒閑邀客，披裘共探春。", "猶能自勉彊，顧我莫辭頻。"]'),
('b9b6c8d3-e16a-49e3-b1b9-b9b18ec6d802','夜聞春風有感奉寄同院子華紫微長文景仁','歐陽修','宋','宋诗','song-poetry','','[]','閏後春深雪始鎖，東風凌鑠勢方豪。',64,'全唐诗/poet.song.17000.json','["閏後春深雪始鎖，東風凌鑠勢方豪。", "陽生草木黄泉動，冰破江湖白浪高。", "未報國恩嗟病骨，可憐身事一漁舠。", "少年自與芳菲競，莫笑衰翁擁弊袍。"]'),
('0c378634-7214-4632-935a-bd563c98be47','病告中懷子華原父','歐陽修','宋','宋诗','song-poetry','','[]','狂來有意與春爭，老去心情漸不能。',64,'全唐诗/poet.song.17000.json','["狂來有意與春爭，老去心情漸不能。", "世味惟存詩淡泊，生涯半爲病侵陵。", "花明曉日繁如錦，酒撥浮醅綠似澠。", "自是少年豪橫過，而今癡鈍若寒蠅。"]'),
('6eff599e-59e3-4c9e-8fee-eb12c033be84','春酬長文舍人出城見示之句','歐陽修','宋','宋诗','song-poetry','','[]','春分臘雪未全銷，凜冽春寒氣尚驕。',64,'全唐诗/poet.song.17000.json','["春分臘雪未全銷，凜冽春寒氣尚驕。", "攝事初欣迎社燕，尋芳因得過溪橋。", "清浮酒蟻醅初撥，暖入鸎篁舌漸調。", "興味愛君年尚少，莫嫌齋禁暫無憀。"]'),
('e4e2b2c1-54f5-40ea-a6ec-7ae8dd6160dd','唐崇徽公主手痕和韓內翰','歐陽修','宋','宋诗','song-poetry','','[]','故鄉飛鳥尚啁啾，何況悲笳出塞愁。',64,'全唐诗/poet.song.17000.json','["故鄉飛鳥尚啁啾，何況悲笳出塞愁。", "青塚埋魂知不返，翠崖遺迹爲誰留。", "玉顔自古爲身累，肉食何人與國謀。", "行路至今空歎息，巖花澗草自春秋。"]'),
('c85c38ee-8108-449e-82d7-531d5e027a1d','答和閣老劉舍人雨中見寄','歐陽修','宋','宋诗','song-poetry','','[]','花間鳥語愁泥滑，屋上鳩鳴厭雨多。',64,'全唐诗/poet.song.17000.json','["花間鳥語愁泥滑，屋上鳩鳴厭雨多。", "坐見殘春一如此，可憐吾意已蹉跎。", "蕭條兩鬢霜後草，瀲灧十分金卷荷。", "此物猶能慰衰老，稍晴相約屢相過。"]'),
('bca07c95-a1a5-4f79-b614-e8b7f3f16096','寄閣老劉舍人','歐陽修','宋','宋诗','song-poetry','','[]','夢寐江西未得歸，誰憐蕭颯鬢毛衰。',64,'全唐诗/poet.song.17000.json','["夢寐江西未得歸，誰憐蕭颯鬢毛衰。", "莓苔生壁圖書室，風雨閉門桃李時。", "得酒雖能陪笑語，老年其實厭追隨。", "明朝雨止花應在，又踏春泥向鳳池。"]'),
('dd2013c2-8ce2-4ecf-8c3c-e7b915a9629e','詳定幕次呈同舍','歐陽修','宋','宋诗','song-poetry','','[]','來時宮柳綠初勻，坐見紅芳幾番新。',32,'全唐诗/poet.song.17000.json','["來時宮柳綠初勻，坐見紅芳幾番新。", "蜂蜜滿房花結子，還家何處覓殘春。"]'),
('7e3d3f30-e63d-4eb9-a432-67229fad042e','禁中見鞓紅牡丹','歐陽修','宋','宋诗','song-poetry','','[]','盛遊西洛方年少，晚落南譙號醉翁。',32,'全唐诗/poet.song.17000.json','["盛遊西洛方年少，晚落南譙號醉翁。", "白首歸來玉堂署，君王殿後見鞓紅。"]'),
('37b97faa-3ba5-4765-8f53-78549f274f6b','和江鄰幾學士桃花','歐陽修','宋','宋诗','song-poetry','','[]','草上紅多枝上稀，芳條綠萼憶來時。',32,'全唐诗/poet.song.17000.json','["草上紅多枝上稀，芳條綠萼憶來時。", "見桃著子始歸後，誰道仙花開落遲。"]'),
('f1e4858c-e9d9-4d64-97fd-83591b3f672e','送襄陵令李君','歐陽修','宋','宋诗','song-poetry','','[]','綠髮襄陵新長官，面顔雖老渥如丹。',64,'全唐诗/poet.song.17000.json','["綠髮襄陵新長官，面顔雖老渥如丹。", "折腰聊爲五斗屈，把酒猶能一笑歡。", "紅棗林繁欣歲熟，紫檀皮軟禦春寒。", "民淳政簡居多樂，無苦思歸欲掛冠。"]'),
('be1c2052-6965-4f95-af77-8afaa2ce3d15','景靈宮致齋','歐陽修','宋','宋诗','song-poetry','','[]','攝事衰年力不彊，誰憐岑寂卧齋坊。',64,'全唐诗/poet.song.17000.json','["攝事衰年力不彊，誰憐岑寂卧齋坊。", "青苔點點無人迹，綠葉陰陰覆砌凉。", "玉宇清風來處遠，仙家白日靜中長。", "却視九衢車馬客，自然顔鬢易蒼蒼。"]'),
('ddc95dc8-0cbc-49bb-803c-13f0ba48a7e4','夏享太廟攝事齋宮聞鸎寄原甫','歐陽修','宋','宋诗','song-poetry','','[]','四月田家麥穗稠，桑枝生椹鳥啁啾。',32,'全唐诗/poet.song.17000.json','["四月田家麥穗稠，桑枝生椹鳥啁啾。", "鳳城綠樹知多少，何處飛來黄栗留。"]'),
('abc67803-2fb1-4267-b8ea-a85a4ccefa87','送王平甫下第','歐陽修','宋','宋诗','song-poetry','','[]','歸袂摇摇心浩然，曉船鳴鼓轉風灘。',64,'全唐诗/poet.song.17000.json','["歸袂摇摇心浩然，曉船鳴鼓轉風灘。", "朝廷失士有司恥，貧賤不憂君子難。", "執手聊須爲醉別，還家何以慰親懽。", "自慙知子不能薦，白首胡爲侍從官。"]'),
('19a6c28c-3a63-4803-b616-9e9c9df99ead','對雪十韻','歐陽修','宋','宋诗','song-poetry','','[]','對雪無佳名，端居正杜門。',120,'全唐诗/poet.song.17000.json','["對雪無佳名，端居正杜門。", "人閑見初落，風定不勝繁。", "可喜輕明質，都無剪刻痕。", "鋪平失池沼，飄急響窗軒。", "惜不摇嘉樹，衝宜走畫轅。", "寒欺白酒嫩，暖愛紫貂溫。", "遠靄銷如洗，愁雲晚更屯。", "兒吟雛鳳語，翁坐凍鴟蹲。", "病思驚殘歲，朋歡賴酒罇。", "稍晴春意動，誰與探名園。"]'),
('511845bf-286d-4c9b-98ba-5961523df929','和武平學士歲晚禁直書懷五言二十韻','歐陽修','宋','宋诗','song-poetry','','[]','多病淹殘歲，初寒卧直廬。',240,'全唐诗/poet.song.17000.json','["多病淹殘歲，初寒卧直廬。", "朝廷務清靜，鈴索少文書。", "嚮學今爲盛，優賢古莫如。", "靚深嚴禁署，閑宴樂羣居。", "賜馬聯金絡，清塵侍玉輿。", "討論三代盛，獻納萬機餘。", "號令存寬大，文章復古初。", "笑談揮翰墨，俄頃列瓊琚。", "夜漏銷宮燭，春暉上玉除。", "歌詩唐李杜，言語漢嚴徐。", "自顧追時彥，多慙不鄙予。", "無鹽煩刻畫，寒谷借吹噓。", "朋友飛雝鷺，君臣在藻魚。", "貪榮同衛鶴，取笑類黔驢。", "皎皎心雖在，蕭蕭髮已疏。", "未知論報效，安得遂樵漁。", "雲破西山出，江橫畫閣虛。", "餘生歎勞止，搔首念歸歟。", "引綬誇民吏，樵牛會里閭。", "一麾終得請，此計豈躊躇。"]'),
('b764ea99-68f3-495c-9ddf-1238412755e6','答西京王尚書寄牡丹','歐陽修','宋','宋诗','song-poetry','','[]','新花來遠喜開封，呼酒看花興未窮。',64,'全唐诗/poet.song.17000.json','["新花來遠喜開封，呼酒看花興未窮。", "年少曾爲洛陽客，眼明重見魏家紅。", "却思初赴青油幕，自笑今爲白髮翁。", "西望無由陪勝賞，但吟佳句想芳叢。"]'),
('2fb043bd-4090-42e0-9486-02820fafee96','應制賞花釣魚','歐陽修','宋','宋诗','song-poetry','','[]','絳闕晨霞照霧開，輕塵不動翠華來。',64,'全唐诗/poet.song.17000.json','["絳闕晨霞照霧開，輕塵不動翠華來。", "魚遊碧沼涵靈德，花馥清香薦壽杯。", "夢聽鈞天聲杳默，日長化國景徘徊。", "自慙擊壤音多野，帝所賡歌亦許陪。"]'),
('529848bc-0801-48e4-a64c-7139110b8d23','清明賜新火','歐陽修','宋','宋诗','song-poetry','','[]','魚鑰侵晨放九門，天街一騎走紅塵。',64,'全唐诗/poet.song.17000.json','["魚鑰侵晨放九門，天街一騎走紅塵。", "桐華應候催佳節，榆火推恩忝侍臣。", "多病正愁餳粥冷，清香但愛蠟煙新。", "自憐慣識金蓮燭，翰苑曾經七見春。"]'),
('959ffb57-e6de-4446-a139-97837dcf16ca','明堂慶成','歐陽修','宋','宋诗','song-poetry','','[]','辰火天文次，臯門路寢閎。',96,'全唐诗/poet.song.17000.json','["辰火天文次，臯門路寢閎。", "奉親昭孝德，惟帝饗精誠。", "禮以三年講，時因萬物成。", "九筵嚴太室，六變導和聲。", "象魏中天起，風雷大號行。", "歡呼響山岳，流澤浹根莖。", "寶墨飛雲動，金文耀日晶。", "從臣才力薄，無以頌休明。"]'),
('6ed77789-f265-4262-a10d-5baaa0b80313','羣玉殿賜宴  其一','歐陽修','宋','宋诗','song-poetry','','[]','至治臻無事，豐年樂有成。',36,'全唐诗/poet.song.17000.json','["至治臻無事，豐年樂有成。", "圖書開秘府，宴飫集羣英。", "論道皇墳奧，貽謀寶訓明。"]'),
('1c6eda97-bb4a-417b-ad8c-fbc9b4f22f0f','羣玉殿賜宴  其二','歐陽修','宋','宋诗','song-poetry','','[]','九重多暇豫，八體極研精。',60,'全唐诗/poet.song.17000.json','["九重多暇豫，八體極研精。", "筆力千鈞勁，豪端萬象生。", "飛牋金灑落，拜賜玉鏘鳴。", "盛際崇儒學，愚臣濫寵榮。", "惟能同舞獸，聞樂識和聲。"]'),
('ae94d26a-a14b-469e-ab3a-fa70c673845c','永昭陵挽詞三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','與子雖天意，知人昔帝難。',48,'全唐诗/poet.song.17000.json','["與子雖天意，知人昔帝難。", "一言謀早定，九鼎勢先安。", "大舜仁由性，成湯治以寬。", "孤臣恩未報，清血但汍瀾。"]'),
('cb1121b0-0886-4589-9311-2bd90f4a6e64','永昭陵挽詞三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','干戈不用臻無事，朝野多歡樂有年。',64,'全唐诗/poet.song.17000.json','["干戈不用臻無事，朝野多歡樂有年。", "便坐看揮飛白筆，侍臣新和栢梁篇。", "衣冠忽見藏原廟，簫鼓愁聞向洛川。", "寂寞秋風羣玉殿，還同恍惚夢鈞天。"]'),
('9a93b590-405e-4829-aad7-4e555cca044d','永昭陵挽詞三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','行殿沉沉畫翣重，凄凉挽鐸出深宮。',64,'全唐诗/poet.song.17000.json','["行殿沉沉畫翣重，凄凉挽鐸出深宮。", "攀號不悟龍胡遠，侍從猶穿豹尾中。", "日薄山川長起霧，天寒松栢自生風。", "斯民四十年涵煦，耕鑿安知荷帝功。"]'),
('489b3965-a6a5-4ae2-934b-992d68398393','續作永昭陵挽詞五首  其一','歐陽修','宋','宋诗','song-poetry','','[]','王者居尊本無外，由來天下以爲家。',32,'全唐诗/poet.song.17000.json','["王者居尊本無外，由來天下以爲家。", "六龍白日乘雲去，何用金錢買道車。"]'),
('8575de60-6de4-48ca-bf4a-85e87161e73d','續作永昭陵挽詞五首  其二','歐陽修','宋','宋诗','song-poetry','','[]','苦霧霏霏著彩旗，猶排吉伏雜兇儀。',32,'全唐诗/poet.song.17000.json','["苦霧霏霏著彩旗，猶排吉伏雜兇儀。", "常時鳳輦行遊處，今日龍輴慟哭隨。"]'),
('9003cf45-108b-4049-b8b9-c5375ef2336f','續作永昭陵挽詞五首  其三','歐陽修','宋','宋诗','song-poetry','','[]','都人擾擾塞唐莊，西送靈車過苑牆。',32,'全唐诗/poet.song.17000.json','["都人擾擾塞唐莊，西送靈車過苑牆。", "金鼎藥成龍已去，人間惟有鼠拖腸。"]'),
('022b4d71-2a8c-477f-9bd5-e7bc173a93ec','續作永昭陵挽詞五首  其四','歐陽修','宋','宋诗','song-poetry','','[]','素幕悠悠逗曉風，行隨哀挽出深宮。',32,'全唐诗/poet.song.17000.json','["素幕悠悠逗曉風，行隨哀挽出深宮。", "妃嬪莫向蒼梧望，雲覆昭陵洛水東。"]'),
('8d5bf5d0-f927-4b02-8dd9-980a8ab42a08','續作永昭陵挽詞五首  其五','歐陽修','宋','宋诗','song-poetry','','[]','叨陪法從最多年，慣聽梨園奏管絃。',32,'全唐诗/poet.song.17000.json','["叨陪法從最多年，慣聽梨園奏管絃。", "從此無因瞻黼坐，惟應魂夢到鈞天。"]'),
('22e5c225-8643-4806-9c14-792f9c7fb8ad','赴集禧宮祈雪追憶從先皇駕幸泫然有感','歐陽修','宋','宋诗','song-poetry','','[]','琳闕岧岧倚瑞煙，憶陪遊豫入新年。',64,'全唐诗/poet.song.17000.json','["琳闕岧岧倚瑞煙，憶陪遊豫入新年。", "雲深曉日開宮殿，水闊春風颺管絃。", "千騎清塵回輦路，萬家明月放燈天。", "一朝人事凄涼改，惟有靈光獨巋然。"]'),
('8cdd82f4-8b88-42fd-b316-3b0ca457e676','夜宿中書東閤','歐陽修','宋','宋诗','song-poetry','','[]','翰林平日接羣公，文酒相歡慰病翁。',64,'全唐诗/poet.song.17000.json','["翰林平日接羣公，文酒相歡慰病翁。", "白首歸田徒有約，黄扉論道愧無功。", "攀髯路斷三山遠，憂國心危百箭攻。", "今夜靜聽丹禁漏，尚疑身在玉堂中。"]'),
('43d2b6b1-ce04-4fe6-b969-2072f882c22f','送王學士赴兩浙轉運','歐陽修','宋','宋诗','song-poetry','','[]','漢家財利析秋毫，暫屈清才豈足勞。',64,'全唐诗/poet.song.17000.json','["漢家財利析秋毫，暫屈清才豈足勞。", "邑屋連雲盈萬井，舳艫銜尾列千艘。", "春寒欲盡黄梅雨，海浪高翻白鷺濤。", "平昔壯心今在否，江山猶得助詩豪。"]'),
('5c6d6080-b2ad-4b34-a53b-218c5a18d5e6','早朝','歐陽修','宋','宋诗','song-poetry','','[]','閶闔初開瑞霧中，丹霞曉日上蒼龍。',64,'全唐诗/poet.song.17000.json','["閶闔初開瑞霧中，丹霞曉日上蒼龍。", "鳴鞭響徹廓千步，佩玉聲趨戟百重。", "雪後朝寒猶凜冽，柳梢春意已丰茸。", "少年自結芳菲侶，老病惟添睡思濃。"]'),
('88b6f34b-0d9a-433d-870c-df2ccfa93130','下直','歐陽修','宋','宋诗','song-poetry','','[]','宮柳街槐綠未齊，春陰不解宿雲低。',64,'全唐诗/poet.song.17000.json','["宮柳街槐綠未齊，春陰不解宿雲低。", "輕寒漠漠侵駞褐，小雨班班作燕泥。", "報國無功嗟已老，歸田有約一何稽。", "終當自駕柴車去，獨結茅廬潁水西。"]'),
('cf177a37-ac19-4ac3-a499-8f2a6f16f016','齋宮尚有殘雪思作學士時攝事于此嘗有聞鸎詩寄原父因而有感四首  其一','歐陽修','宋','宋诗','song-poetry','','[]','雪壓枯條脈未抽，春寒憀慄作春愁。',32,'全唐诗/poet.song.17000.json','["雪壓枯條脈未抽，春寒憀慄作春愁。", "却思綠葉清陰下，來此曾聞黄栗留。"]'),
('84db2fd2-845f-41db-bd2d-bc2f7ed2634c','齋宮尚有殘雪思作學士時攝事于此嘗有聞鸎詩寄原父因而有感四首  其二','歐陽修','宋','宋诗','song-poetry','','[]','老來何與青春事，閑處方知白日長。',32,'全唐诗/poet.song.17000.json','["老來何與青春事，閑處方知白日長。", "自恨乞身今未得，齒牙浮動鬢蒼浪。"]'),
('2386d29d-e70e-47b0-a30e-86a94637dbcf','齋宮尚有殘雪思作學士時攝事于此嘗有聞鸎詩寄原父因而有感四首  其三','歐陽修','宋','宋诗','song-poetry','','[]','兩京平日接英髦，不獨詩豪酒亦豪。',32,'全唐诗/poet.song.17000.json','["兩京平日接英髦，不獨詩豪酒亦豪。", "休把青銅照雙鬢，君謨今已白刁騷。"]'),
('0eebb388-4b64-4088-bf14-d9e3e7ce9b7c','齋宮尚有殘雪思作學士時攝事于此嘗有聞鸎詩寄原父因而有感四首  其四','歐陽修','宋','宋诗','song-poetry','','[]','詩篇自覺隨年老，酒力猶能助氣豪。',32,'全唐诗/poet.song.17000.json','["詩篇自覺隨年老，酒力猶能助氣豪。", "興味不衰惟此爾，其餘萬事一牛毛。"]'),
('9e43c861-bfa2-493f-9975-9402845eaefe','攝事齋宮偶書','歐陽修','宋','宋诗','song-poetry','','[]','齋宮岑寂偶偷閑，猶覺閑中興未闌。',64,'全唐诗/poet.song.17000.json','["齋宮岑寂偶偷閑，猶覺閑中興未闌。", "美酒清香銷晝景，冷風殘雪作春寒。", "丹心未死惟憂國，白髮盈簪盍掛冠。", "誰爲寄聲清潁客，此生終不負漁竿。"]'),
('e1e8b2c9-f430-4c52-91cb-48190d554611','早期感事','歐陽修','宋','宋诗','song-poetry','','[]','疏星牢落曉光微，殘月蒼龍闕角西。',64,'全唐诗/poet.song.17000.json','["疏星牢落曉光微，殘月蒼龍闕角西。", "玉勒爭門隨仗入，牙牌當殿報班齊。", "羽儀雖接鴛兼鷺，野性終存鹿與麛。", "笑殺汝陰常處士，十年騎馬聽朝雞。"]'),
('fb3964d4-f2b9-40a4-87ab-22969181ad70','集禧謝雨','歐陽修','宋','宋诗','song-poetry','','[]','十里長街五鼓催，泥深雨急馬行遲。',32,'全唐诗/poet.song.17000.json','["十里長街五鼓催，泥深雨急馬行遲。", "卧聽竹屋簫簫響，却憶滁州睡足時。"]'),
('b18747f6-e1f6-4452-a221-25552ac194d7','下直呈同行三公','歐陽修','宋','宋诗','song-poetry','','[]','午漏聲初轉，歸鞍路偶同。',96,'全唐诗/poet.song.17000.json','["午漏聲初轉，歸鞍路偶同。", "天清黄道日，街闊綠槐風。", "萬國舟車會，中天象魏雄。", "戢戈清四海，論道屬三公。", "自愧陪羣彥，從來但樸忠。", "時平容竊祿，歲晚歎衰翁。", "買地淮山北，垂竿潁水東。", "稻粱雖可戀，吾志在冥鴻。"]'),
('1be64cbe-8138-43f2-8b69-9fd61a712cd7','東閤雨中','歐陽修','宋','宋诗','song-poetry','','[]','直閤時偷暇，幽懷坐獨哦。',72,'全唐诗/poet.song.17000.json','["直閤時偷暇，幽懷坐獨哦。", "綠苔人迹少，黄葉雨聲多。", "雲結愁陰重，風傳禁漏過。", "瑶圖新嗣聖，玉塞久包戈。", "相府文書簡，豐年氣候和。", "還將鳳池句，聊雜野人歌。"]'),
('ca3792c5-290a-4dc1-bc86-8932efe69cbd','四月十七日景靈宮奉迎仁宗皇帝御容有感','歐陽修','宋','宋诗','song-poetry','','[]','行殿峨峨出綠槐，琳房芝闕聳崔嵬。',64,'全唐诗/poet.song.17000.json','["行殿峨峨出綠槐，琳房芝闕聳崔嵬。", "管絃飄落人間去，幛節疑從天上來。", "基業百年傳聖子，黔黎四紀樂春臺。", "孤臣不得同鍼虎，未死心先冷若灰。"]'),
('af462ed5-e9e8-4c60-8b56-2ee5242e4255','馬上默誦聖俞詩有感','歐陽修','宋','宋诗','song-poetry','','[]','興來筆力千鈞勁，酒醒人間萬事空。',32,'全唐诗/poet.song.17000.json','["興來筆力千鈞勁，酒醒人間萬事空。", "蘇梅二字今亡矣，索寞滁山一醉翁。"]'),
('46573eb5-d19e-4147-89bb-6f70fbf49274','定力院七葉木','歐陽修','宋','宋诗','song-poetry','','[]','伊洛多佳木，娑羅舊得名。',72,'全唐诗/poet.song.17000.json','["伊洛多佳木，娑羅舊得名。", "常於佛家見，宜在月宮生。", "釦砌陰鋪靜，虛堂子落聲。", "夜風疑雨過，朝露炫霞明。", "車馬王都盛，樓臺梵宇閎。", "惟應靜者樂，時聽野禽鳴。"]'),
('125ac740-9cfe-4e90-bbe5-62c52c607859','秋陰','歐陽修','宋','宋诗','song-poetry','','[]','秋陰積不散，夜氣凜初清。',48,'全唐诗/poet.song.17000.json','["秋陰積不散，夜氣凜初清。", "雨冷侵燈暈，風愁送葉聲。", "國恩慙未報，歲晚念餘生。", "却憶滁州睡，村醪自解酲。"]'),
('802f310e-0f98-4471-ba03-919a2d06660c','秋懷','歐陽修','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u6292\u6000", "\u5199\u666f", "\u601d\u5f52"]','節物豈不好，秋懷何黯然。',48,'全唐诗/poet.song.17000.json','["節物豈不好，秋懷何黯然。", "西風酒旗市，細雨菊花天。", "感事悲雙鬢，包羞食萬錢。", "鹿車終自駕，歸去潁東田。"]'),
('4383b3a6-4890-4b60-ad83-f356191ee03f','初寒','歐陽修','宋','宋诗','song-poetry','','[]','多病淹殘歲，初寒悄獨吟。',48,'全唐诗/poet.song.17000.json','["多病淹殘歲，初寒悄獨吟。", "雲容乍濃淡，秋色半晴陰。", "籬菊催佳節，山泉響夜琴。", "自能知此樂，何必戀腰金。"]'),
('60a90086-1c0f-4f67-a7d6-b4b3653ac1d5','寄渭州王仲儀龍圖','歐陽修','宋','宋诗','song-poetry','','[]','羨君三作臨邊守，慣聽胡笳不慘然。',64,'全唐诗/poet.song.17000.json','["羨君三作臨邊守，慣聽胡笳不慘然。", "弓勁秋風鳴白角，帳寒春雪壓青氈。", "威行四境烽煙斷，響入千山號令傳。", "翠幕紅燈照羅綺，心情何似十年前。"]'),
('fd88a70a-6ba1-4204-a23d-a0eb240eed05','崇政殿試賢良晚歸','歐陽修','宋','宋诗','song-poetry','','[]','槐柳依依禁籞長，初寒人意自凄凉。',64,'全唐诗/poet.song.17000.json','["槐柳依依禁籞長，初寒人意自凄凉。", "鳳城斜日留殘照，玉闕浮雲結夜霜。", "老負漁竿貪國寵，病須樽酒送年光。", "歸來解带西風冷，衣袖猶霑玉案香。"]'),
('78442d2c-f503-4f70-aed4-28f8d681cf6a','聞潁州通判國博與知郡學士唱和頗多因以奉寄知郡陸經通判楊褒','歐陽修','宋','宋诗','song-poetry','','[]','一自蘇梅閉九泉，始聞東潁播新篇。',64,'全唐诗/poet.song.17000.json','["一自蘇梅閉九泉，始聞東潁播新篇。", "金樽留客史君醉，玉麈高談別乘賢。", "十里秋風紅菡萏，一溪春水碧漪漣。", "政成事簡何爲樂，終日吟哦雜管絃。"]'),
('4a3f84cc-7d62-4ee4-9240-3a29bd7a91b4','南郊慶成','歐陽修','宋','宋诗','song-poetry','','[]','祀教民昭孝，天惟德是親。',72,'全唐诗/poet.song.17000.json','["祀教民昭孝，天惟德是親。", "太宮嚴大饗，吉土兆精禋。", "禮樂三五盛，梯航萬國賓。", "恩霑羣動洽，慶與一陽新。", "奉冊尊長樂，均釐及眾臣。", "不須雲物瑞，和氣浹人神。"]'),
('a037896e-0cf8-4055-adce-24185376d624','和昭文相公上巳宴','歐陽修','宋','宋诗','song-poetry','','[]','一雨初消九陌塵，秉蘭修禊及芳辰。',64,'全唐诗/poet.song.17000.json','["一雨初消九陌塵，秉蘭修禊及芳辰。", "恩深始錫龍池宴，節正須知鳳曆新。", "紅琥珀傳盃瀲灧，碧琉璃瑩水奫淪。", "上林未放花齊發，留待鳴鞘出紫宸。"]'),
('3efcf8b4-a5b1-475c-8b78-254c2a90a3be','三日赴宴口占','歐陽修','宋','宋诗','song-poetry','','[]','賜飲初逢禊節佳，昆池新漲碧無涯。',64,'全唐诗/poet.song.17000.json','["賜飲初逢禊節佳，昆池新漲碧無涯。", "九門寒食多遊騎，三月春陰正養花。", "共喜流觴修故事，自憐雙鬢惜年華。", "鳳城殘照歸鞍晚，禁籞無風柳自斜。"]'),
('559212e0-de69-463b-9238-a3665afebf38','讀楊蟠章安集','歐陽修','宋','宋诗','song-poetry','','[]','蘇梅久作黄泉客，我亦今爲白髮翁。',32,'全唐诗/poet.song.17000.json','["蘇梅久作黄泉客，我亦今爲白髮翁。", "卧讀楊蟠一千首，乞渠秋月與春風。"]'),
('840a1ac8-5382-45e9-bfd0-2a49d19d672f','蘇主簿挽歌','歐陽修','宋','宋诗','song-poetry','','[]','布衣馳譽入京都，丹旐俄驚反舊閭。',64,'全唐诗/poet.song.17000.json','["布衣馳譽入京都，丹旐俄驚反舊閭。", "諸老誰能先賈誼，君王猶未識相如。", "三年弟子行喪禮，千兩鄉人會葬車。", "我獨空齋掛塵榻，遺編時閱子雲書。"]'),
('366cfdc0-d2dd-43b8-b493-62ac3c55708f','寄題沙溪寶錫院','歐陽修','宋','宋诗','song-poetry','','[]','爲愛江西物物佳，作詩嘗向北人誇。',64,'全唐诗/poet.song.17000.json','["爲愛江西物物佳，作詩嘗向北人誇。", "青林霜日換楓葉，白水秋風吹稻花。", "釀酒烹雞留醉客，鳴機織苧徧山家。", "野僧獨得無生樂，終日焚香坐結跏。"]'),
('e5ea214c-d37e-4211-bc4f-f7cd84196d94','宋司空挽辭','歐陽修','宋','宋诗','song-poetry','','[]','文章天下無雙譽，伯仲人間第一流。',64,'全唐诗/poet.song.17000.json','["文章天下無雙譽，伯仲人間第一流。", "出入兩朝推舊德，周旋三事著嘉謀。", "從容進退身名泰，寵錫哀榮禮數優。", "棠棣從來敦友愛，九原相望接松楸。"]'),
('43390bbe-a7ea-4f65-86a7-b692cf3baf37','感事','歐陽修','宋','宋诗','song-poetry','','[]','故園三徑久成荒，賢路胡爲此坐妨。',64,'全唐诗/poet.song.17000.json','["故園三徑久成荒，賢路胡爲此坐妨。", "病骨瘦便花蕊暖，煩心渴喜鳳團香。", "號弓但灑孤臣血，憂國空餘兩鬢霜。", "何日君恩憫衰朽，許從初服返耕桑。"]'),
('b7583cc6-8285-45a3-b453-a915a495aed9','大行皇帝靈駕以引挽歌辭  其一','歐陽修','宋','宋诗','song-poetry','','[]','享國年雖近，斯民澤已深。',72,'全唐诗/poet.song.17000.json','["享國年雖近，斯民澤已深。", "儉勤成禹聖，仁孝本虞心。", "方慶逢千載，俄驚遏八音。", "天愁嵩嶺外，雲慘洛川潯。", "仗動千官衛，神行萬象陰。", "孤臣恩未報，清血但盈襟。"]'),
('657ee4e8-370e-40b0-8053-32fffb21ffd5','大行皇帝靈駕以引挽歌辭  其二','歐陽修','宋','宋诗','song-poetry','','[]','文景孜孜儉與恭，慨然思就太平功。',64,'全唐诗/poet.song.17000.json','["文景孜孜儉與恭，慨然思就太平功。", "興隆學校皇家盛，放斥嬪嬙永巷空。", "威懾黠羌方問罪，凡成仙鼎忽遺弓。", "霜清日薄簫笳咽，萬國悲號慘澹中。"]'),
('f048105a-dc01-409e-97e9-c61371c44b65','大行皇帝靈駕以引挽歌辭  其三','歐陽修','宋','宋诗','song-poetry','','[]','千齡應運葉天人，四海方欣政日新。',64,'全唐诗/poet.song.17000.json','["千齡應運葉天人，四海方欣政日新。", "忽見九門陳羽衛，猶疑五載欲時巡。", "觚稜月暗翔金鳳，輦道霜清卧石麟。", "白首舊臣瞻畫翣，秋風淚灑屬車塵。"]'),
('80b9d605-5b57-48bb-a6b6-6eebfb4e8660','奉答子履學士見贈之作','歐陽修','宋','宋诗','song-poetry','','[]','誰言潁水似瀟湘，一笑相逢樂未央。',64,'全唐诗/poet.song.17000.json','["誰言潁水似瀟湘，一笑相逢樂未央。", "歲晚君尤耐霜雪，興闌吾欲返耕桑。", "銅槽旋壓清樽美，玉麈閑揮白日長。", "豫約詩筒屢來往，兩州雞犬接封疆。"]'),
('f16acb80-604e-46b1-9579-a714bd5ec16f','送道州張職方','歐陽修','宋','宋诗','song-poetry','','[]','桂籍青衫憶共遊，憐君華髮始爲州。',64,'全唐诗/poet.song.17000.json','["桂籍青衫憶共遊，憐君華髮始爲州。", "身行南鴈不到處，山與北人相對愁。", "莫爲高才輕遠俗，當令遺老識賢侯。", "三年解組來歸日，吾已先耕潁水頭。"]'),
('6f2a41f8-431a-48f1-abd8-8ec3bfd6f7f7','再至汝陰三絕  其一','歐陽修','宋','宋诗','song-poetry','','[]','黄栗留鳴桑葚美，紫櫻桃熟麥風凉。',32,'全唐诗/poet.song.17000.json','["黄栗留鳴桑葚美，紫櫻桃熟麥風凉。", "朱輪昔愧無遺愛，白首重來似故鄉。"]'),
('2f366f02-3b19-428f-949c-f55ed4a949ad','再至汝陰三絕  其二','歐陽修','宋','宋诗','song-poetry','','[]','十載榮華貪國寵，一生憂患損天真。',32,'全唐诗/poet.song.17000.json','["十載榮華貪國寵，一生憂患損天真。", "潁人莫怪歸來晚，新向君前乞得身。"]'),
('8718ee9e-74e9-41e9-bf1d-5dd03a379558','再至汝陰三絕  其三','歐陽修','宋','宋诗','song-poetry','','[]','水味甘於大明井，魚肥恰似新開湖。',32,'全唐诗/poet.song.17000.json','["水味甘於大明井，魚肥恰似新開湖。", "十四五年勞夢寐，此時才得少踟躕。"]'),
('8215f0d9-61c5-4434-ab8f-c8735522942c','郡齋憶書事寄子履','歐陽修','宋','宋诗','song-poetry','','[]','使君居處似山中，吏散焚香一室空。',64,'全唐诗/poet.song.17000.json','["使君居處似山中，吏散焚香一室空。", "雨過紫苔惟鳥迹，夜凉蒼檜起天風。", "白醪酒嫩迎秋熟，紅棗林繁喜歲豐。", "寄語瀛洲未歸客，醉翁今已作僊翁。"]'),
('56431edd-a873-4d47-80af-839d0f383c94','答子履學士見寄','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潁毫相望樂未央，吾州仍得治仙鄉。',64,'全唐诗/poet.song.17000.json','["潁毫相望樂未央，吾州仍得治仙鄉。", "夢回枕上黄粱熟，身在壺中白日長。", "每恨老年才已盡，怕逢詩敵力難當。", "知君欲別西湖去，乞我橋南菡萏香。"]'),
('b8dab621-f48e-4f3c-8cfe-d90f1868fd58','寄棗人行書贈子履學士','歐陽修','宋','宋诗','song-poetry','','[]','秋來紅棗壓枝繁，堆向君家白玉盤。',64,'全唐诗/poet.song.17000.json','["秋來紅棗壓枝繁，堆向君家白玉盤。", "甘辛楚國赤萍實，磊落韓嫣黄金丸。", "聊效詩人投木李，敢期佳句報琅玕。", "嗟予久苦相如渴，却憶冰梨熨齒寒。"]'),
('4684314e-8366-4fd0-a3f2-193a03d68128','贈隱者','歐陽修','宋','宋诗','song-poetry','','[]','五岳嵩當天地中，聞君仍在最高峯。',64,'全唐诗/poet.song.17000.json','["五岳嵩當天地中，聞君仍在最高峯。", "山藏六月陰崖雪，潭養千年蛻骨龍。", "物外自應多至樂，人間何事忽相逢。", "飲罷飄然不辭决，孤雲飛去杳無蹤。"]'),
('45efaf32-290d-4059-9d52-d2f49e1d165f','戲書示黎教授','歐陽修','宋','宋诗','song-poetry','','[]','古郡誰云毫陋邦，我來仍值歲豐穰。',64,'全唐诗/poet.song.17000.json','["古郡誰云毫陋邦，我來仍值歲豐穰。", "烏銜棗實園林熟，峰採檜花村落香。", "世治人方安垅畝，興闌吾欲反耕桑。", "若無潁水肥魚蟹，終老仙鄉作醉鄉。"]'),
('f692e7a3-86ad-43d4-b995-031863a1c772','書懷','歐陽修','宋','宋诗','song-poetry','','[]','齒牙零落鬢毛踈，潁水多年已結廬。',64,'全唐诗/poet.song.17000.json','["齒牙零落鬢毛踈，潁水多年已結廬。", "解組便爲閑處士，新花莫笑病尚書。", "青衫仕至千鍾錄，白首歸乘一鹿車。", "況有西鄰隱君子，輕蓑短笠伴春鋤。"]'),
('710a21ce-9253-490c-b3a4-5fb37d2cecb4','渦河龍潭','歐陽修','宋','宋诗','song-poetry','','[]','碧潭風定影涵虛，神物中藏岸不枯。',32,'全唐诗/poet.song.17000.json','["碧潭風定影涵虛，神物中藏岸不枯。", "一夜四郊春雨足，却來閑卧養明珠。"]'),
('3c7e37df-0cb1-42a0-a69f-a868a9b4a4ac','遊太清宮出城馬上口占','歐陽修','宋','宋诗','song-poetry','','[]','擁旆西城一據鞍，耕夫初識勸農官。',64,'全唐诗/poet.song.17000.json','["擁旆西城一據鞍，耕夫初識勸農官。", "鵶鳴日出林光動，野闊風摇麥浪寒。", "漸暖綠楊纔弄色，得晴丹杏不勝繁。", "牛羊雞犬田家樂，終日思歸盍掛冠。"]'),
('d93921d2-f156-4083-b492-47377bb1ec8f','太清宮燒香','歐陽修','宋','宋诗','song-poetry','','[]','清晨琳闕聳巑岏，弭節齋坊暫整冠。',64,'全唐诗/poet.song.17000.json','["清晨琳闕聳巑岏，弭節齋坊暫整冠。", "玉案拜時香裊裊，畫廓行處佩珊珊。", "壇場夜雨蒼苔古，樓殿春風碧瓦寒。", "我是蓬萊宮學士，朝真便合列仙官。"]'),
('0b4c1f95-c77f-46b9-b6c5-1f59a0149051','謝提刑張郎中寄笻竹拄杖','歐陽修','宋','宋诗','song-poetry','','[]','玉光瑩潤錦斕斑，霜雪經多節愈堅。',32,'全唐诗/poet.song.17000.json','["玉光瑩潤錦斕斑，霜雪經多節愈堅。", "珍重故人相贈意，扶持衰病過殘年。"]'),
('fc1daab2-59d8-4ee4-bb6b-53299c490781','七言二首答黎教授  其一','歐陽修','宋','宋诗','song-poetry','','[]','撥甕浮醅新釀熟，得霜寒菊始開齊。',64,'全唐诗/poet.song.17000.json','["撥甕浮醅新釀熟，得霜寒菊始開齊。", "養丹道士顔如玉，愛酒山公醉似泥。", "不惜蕊從蜂採去，尚餘香有蝶來棲。", "莫嫌學舍官閑冷，猶得芳樽此共携。"]'),
('18a0c2ff-b82b-4f21-96fb-892f8fbde2a8','七言二首答黎教授  其二','歐陽修','宋','宋诗','song-poetry','','[]','共坐欄邊日欲斜，更將金蕊泛流霞。',32,'全唐诗/poet.song.17000.json','["共坐欄邊日欲斜，更將金蕊泛流霞。", "俗知却老延齡藥，百草枯時始見花。"]'),
('22a2c259-f39e-4100-81e9-6cfa34c8768f','又寄許道人','歐陽修','宋','宋诗','song-poetry','','[]','綠髮方瞳瘦骨輕，飄然乘鶴去吹笙。',32,'全唐诗/poet.song.17000.json','["綠髮方瞳瘦骨輕，飄然乘鶴去吹笙。", "郡齋獨坐風生竹，疑是孫登長嘯聲。"]'),
('f79a6561-71ab-4aba-a200-4881d64da7d4','扶溝知縣周職方錄示白鶴宮蘇才翁子美贈黄道士詩并盛作三絕見索拙句輒爲四韻奉酬','歐陽修','宋','宋诗','song-poetry','','[]','能棊好飲一道士，醉墨狂吟二謫仙。',64,'全唐诗/poet.song.17000.json','["能棊好飲一道士，醉墨狂吟二謫仙。", "道士不聞乘白鶴，謫仙今已揜黄泉。", "古來豪傑皆如此，誰拂塵埃爲惘然。", "華髮郎官才調美，更將新句續遺篇。"]'),
('74ad175a-ef60-492e-87c7-b082c356e581','曉發齊州道中二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','東州幾日倦征軒，千騎驂驔白草原。',64,'全唐诗/poet.song.17000.json','["東州幾日倦征軒，千騎驂驔白草原。", "鴈入寒雲驚曉角，雞鳴蒼海浴朝暾。", "國恩未報身先老，客思無憀歲已昏。", "誰得平時爲郡樂，自憐痟渴馬文園。"]'),
('058666fa-8a0f-4dea-916f-e4383a605a25','曉發齊州道中二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','歲晚勞征役，三齊舊富閑。',48,'全唐诗/poet.song.17000.json','["歲晚勞征役，三齊舊富閑。", "人行桑下路，日上海邊山。", "軒冕非吾志，風霜犯客顔。", "惟應思潁夢，先過穆陵關。"]'),
('2e557c2b-c8cb-4bc5-ac11-1c1bb932754d','表海亭','歐陽修','宋','宋诗','song-poetry','','[]','望海亭亭古堞間，獨憑危檻俯人寰。',64,'全唐诗/poet.song.17000.json','["望海亭亭古堞間，獨憑危檻俯人寰。", "苦寒冰合分流水，欲雪雲垂四面山。", "髀肉已消嗟病骨，凍醪猶可慰愁顔。", "潁田二頃春蕪沒，安得柴車自駕還。"]'),
('ea56106f-3639-4758-9a1b-e99d329914de','歲晚書事','歐陽修','宋','宋诗','song-poetry','','[]','一麾新命古三齊，白首滄洲願已違。',64,'全唐诗/poet.song.17000.json','["一麾新命古三齊，白首滄洲願已違。", "軒冕從來爲外物，山川信美獨思歸。", "長天極目無飛鳥，積雪生光射落暉。", "臘候已窮春俗動，勸耕猶得覽郊圻。"]'),
('07ea3286-bab7-4524-a224-401c0405d50e','謁廟馬上有感','歐陽修','宋','宋诗','song-poetry','','[]','旌旆曉悠悠，行驚歲已遒。',48,'全唐诗/poet.song.17000.json','["旌旆曉悠悠，行驚歲已遒。", "霜雲依日薄，野水带冰流。", "富庶齊三服，山川禹九州。", "自憐思潁意，無異旅人愁。"]'),
('d3ab710b-347b-4367-821d-e4ed0d92d7e2','毬場看山','歐陽修','宋','宋诗','song-poetry','','[]','爲愛南山紫翠峯，偶來仍值雪初融。',64,'全唐诗/poet.song.17000.json','["爲愛南山紫翠峯，偶來仍值雪初融。", "自嫌前引朱衣吏，不稱閑行白髮翁。", "向老光陰雙轉轂，此身天地一飄蓬。", "何時粗報君恩了，去逐冥冥物外鴻。"]'),
('43211f9f-1cfe-45d6-af70-2d86eb7eee69','殘臘','歐陽修','宋','宋诗','song-poetry','','[]','臘雪初銷上古臺，桑郊向日綵旗開。',64,'全唐诗/poet.song.17000.json','["臘雪初銷上古臺，桑郊向日綵旗開。", "山橫南陌城中見，春逐東風海上來。", "老去每驚新歲換，病多能使壯心摧。", "自嗟空有東陽瘦，覽物慙無八詠才。"]'),
('a08fda9c-e933-4ae6-b0e6-72679624823e','歲暮書事','歐陽修','宋','宋诗','song-poetry','','[]','東州負海圻，風物老依依。',48,'全唐诗/poet.song.17000.json','["東州負海圻，風物老依依。", "歲熟鵶聲樂，天寒鴈過稀。", "跨鞍驚髀骨，數带減腰圍。", "却羨常夫子，終年獨掩扉。"]'),
('fc524e2d-553e-4135-8fff-7016f19a1001','聞沂州盧侍郎致仕有感','歐陽修','宋','宋诗','song-poetry','','[]','少年相與探花開，老病惟愁節物催。',64,'全唐诗/poet.song.17000.json','["少年相與探花開，老病惟愁節物催。", "蹉跎歸計荒三徑，牢落生涯泥一杯。", "潁上先生招不起，沂州太守亦歸來。", "自媿國恩終莫報，尚貪榮祿此徘徊。"]'),
('980af30e-520d-4fda-9470-157090d5581b','春晴書事','歐陽修','宋','宋诗','song-poetry','','[]','莫笑青州太守頑，三齊人物舊安閑。',64,'全唐诗/poet.song.17000.json','["莫笑青州太守頑，三齊人物舊安閑。", "晴明風日家家柳，高下樓臺處處山。", "嘉客但當傾美酒，青春終不換頹顔。", "惟慙未報君恩了，昨日盧公衣錦還。"]'),
('0e6bbf0d-4280-48bd-aadc-58174c9f30b8','遊石子澗','歐陽修','宋','宋诗','song-poetry','','[]','巀嶭高亭古澗隈，偶携嘉客共徘徊。',64,'全唐诗/poet.song.17000.json','["巀嶭高亭古澗隈，偶携嘉客共徘徊。", "席間風起聞天籟，雨後山光入酒杯。", "泉落斷崖舂壑響，花藏深崦過春開。", "麏䴥禽鳥莫驚顧，太守不將車騎來。"]'),
('2954744b-7d7a-4389-91bb-0e0465ed4b68','讀易','歐陽修','宋','宋诗','song-poetry','','[]','莫嫌白髮擁朱輪，恩許東州養病臣。',64,'全唐诗/poet.song.17000.json','["莫嫌白髮擁朱輪，恩許東州養病臣。", "飲酒橫琴銷永日，焚香讀易過殘春。", "昔賢軒冕如遺屣，世路風波偶脫身。", "寄語西家隱君子，奈何名姓已驚人。"]'),
('da8c0210-306d-4cd2-88d3-8185ba1fd21c','水磨亭子','歐陽修','宋','宋诗','song-poetry','','[]','多病山齋厭鬰蒸，經時久不到東城。',64,'全唐诗/poet.song.17000.json','["多病山齋厭鬰蒸，經時久不到東城。", "新荷出水雙飛鷺，喬木成陰百囀鸎。", "載酒未妨佳客醉，憑高仍見老農耕。", "史君自有林泉趣，不用絲篁亂水聲。"]'),
('7a0f7faf-6eca-4bef-841e-3925adf0b633','寄題相州榮歸堂','歐陽修','宋','宋诗','song-poetry','','[]','白首三朝社稷臣，壺漿夾道擁如雲。',64,'全唐诗/poet.song.17000.json','["白首三朝社稷臣，壺漿夾道擁如雲。", "金貂爭看真丞相，竹馬猶迎舊使君。", "豈止軒裳誇故里，已將鍾鼎勒元勳。", "不須授簡樽前客，好學平津自有文。"]'),
('c70c9196-3ddb-4b5c-a397-f59fe2e35b9f','晝錦堂','歐陽修','宋','宋诗','song-poetry','','[]','昔憩甘棠長舊圍，重來城郭歎人非。',32,'全唐诗/poet.song.17000.json','["昔憩甘棠長舊圍，重來城郭歎人非。", "隨車仍是爲霖雨，被衮何如衣錦歸。"]'),
('3f9303c6-66c5-4066-9638-63d20aff3291','觀魚軒','歐陽修','宋','宋诗','song-poetry','','[]','當年下澤驅羸馬，今見犀兵擁碧油。',32,'全唐诗/poet.song.17000.json','["當年下澤驅羸馬，今見犀兵擁碧油。", "位望愈隆心愈靜，每來臨水翫游鯈。"]'),
('3d94906b-4715-42f3-80d0-94ef4bbc2cfe','狎鷗亭','歐陽修','宋','宋诗','song-poetry','','[]','險夷一節如金石，勳德俱高映古今。',32,'全唐诗/poet.song.17000.json','["險夷一節如金石，勳德俱高映古今。", "豈止忘機鷗鳥信，陶鈞萬物本無心。"]'),
('6b08d945-8d8e-48a2-b35b-de20d083f3de','休逸臺','歐陽修','宋','宋诗','song-poetry','','[]','清談終日對清樽，不似崇高富貴身。',32,'全唐诗/poet.song.17000.json','["清談終日對清樽，不似崇高富貴身。", "已有山川資勝賞，更將風月醉嘉賓。"]'),
('8c936bd2-ef04-40d7-9117-3e604db7aa34','青州書事','歐陽修','宋','宋诗','song-poetry','','[]','年豐千里無夜警，吏退一室焚清香。',64,'全唐诗/poet.song.17000.json','["年豐千里無夜警，吏退一室焚清香。", "青春固非老者事，白日自爲閑人長。", "祿厚豈惟慙飽食，俸餘仍足買輕裝。", "君恩天地不違物，歸去行歌潁水傍。"]'),
('bec4c5dc-64ea-40e2-b323-22eb10265347','留題南樓二絕  其一','歐陽修','宋','宋诗','song-poetry','','[]','偷得青州一歲閑，四時終日面孱顔。',32,'全唐诗/poet.song.17000.json','["偷得青州一歲閑，四時終日面孱顔。", "須知我是愛山者，無一詩中不說出。"]'),
('4bc18ee7-a896-45dd-8086-74a7481f9196','留題南樓二絕  其二','歐陽修','宋','宋诗','song-poetry','','[]','醉翁到處不曾醒，問向青州作麽生。',32,'全唐诗/poet.song.17000.json','["醉翁到處不曾醒，問向青州作麽生。", "公退留賓誇酒美，睡餘欹枕看山橫。"]'),
('f50adf99-16e8-405b-83ed-703077a97aed','答和王宣徽','歐陽修','宋','宋诗','song-poetry','','[]','相逢莫怪我皤然，出處參差四紀間。',64,'全唐诗/poet.song.17000.json','["相逢莫怪我皤然，出處參差四紀間。", "有道方令萬物遂，無能擬乞一身閑。", "花前獨酌罇前月，淮上扁舟枕上山。", "此樂想公應未暇，且持金盞醉紅顔。"]'),
('fb3f4367-645b-4480-b744-c973ddea6224','答和呂侍讀','歐陽修','宋','宋诗','song-poetry','','[]','昔日題輿媿屈賢，今來還見擁朱轓。',64,'全唐诗/poet.song.17000.json','["昔日題輿媿屈賢，今來還見擁朱轓。", "笑談二紀思如昨，名望三朝老更尊。", "野徑冷香黄菊秀，平湖斜照白鷗翻。", "此中自有忘言趣，病客猶堪奉一罇。"]'),
('94fb2c11-9051-4ce5-9f62-7b3fa72c1bd6','奉答子履學士見寄之作','歐陽修','宋','宋诗','song-poetry','','[]','憶昨初爲亳守行，暫休車騎汝陰城。',64,'全唐诗/poet.song.17000.json','["憶昨初爲亳守行，暫休車騎汝陰城。", "喜君再共罇俎樂，憐我久懷丘壑情。", "累牘已嘗陳素志，新春應許遂歸耕。", "老年雖不堪東作，猶得酣歌詠太平。"]'),
('8f0647a2-5d32-4e77-adb9-8d84b2060b7e','謝景平挽詞','歐陽修','宋','宋诗','song-poetry','','[]','憶見奇童髧兩髦，遽驚名譽眾推高。',64,'全唐诗/poet.song.17000.json','["憶見奇童髧兩髦，遽驚名譽眾推高。", "東山子弟家風在，西漢文章筆力豪。", "方看凌雲馳騄驥，已嗟埋玉向蓬蒿。", "追思陽夏曾遊處，撫事傷心涕滿袍。"]'),
('7c1bca8a-840c-4f1a-9476-c81b62835f0c','答資政邵諫議見寄二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','豪橫當年氣吐虹，蕭條晚節鬢如蓬。',64,'全唐诗/poet.song.17000.json','["豪橫當年氣吐虹，蕭條晚節鬢如蓬。", "欲知潁水新居士，即是滁山舊醉翁。", "所樂蕃籬追尺鷃，敢言寥廓逐冥鴻。", "期公歸輔巖廓上，顧我無忘畎畝中。"]'),
('14894ea7-e13a-48e7-94b8-31ef33c63c5e','答資政邵諫議見寄二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','欲知歸計久遷延，三十篇詩二十年。',64,'全唐诗/poet.song.17000.json','["欲知歸計久遷延，三十篇詩二十年。", "受寵不思身報效，乞骸惟冀上哀憐。", "相如舊苦中痟渴，陶令猶能一醉眠。", "材薄力殫難勉强，豈同高士愛林泉。"]'),
('e462f308-d85f-4c23-b1e3-8baf116c6b56','擬玉臺體七首 欲眠','歐陽修','宋','宋诗','song-poetry','','[]','行人夜已斷，明河南陌頭。',24,'全唐诗/poet.song.17000.json','["行人夜已斷，明河南陌頭。", "雙璫不擬解，更欲要君留。"]'),
('1eaec81e-f37f-4d41-9acf-d02690d35b6b','擬玉臺體七首 携手曲','歐陽修','宋','宋诗','song-poetry','','[]','落日堤上行，獨歌携手曲。',24,'全唐诗/poet.song.17000.json','["落日堤上行，獨歌携手曲。", "却憶携手人，處處春華綠。"]'),
('cb5e8fc9-106e-4544-a516-0d7c44b0ad8c','擬玉臺體七首 雨中歸','歐陽修','宋','宋诗','song-poetry','','[]','朝看樓上雲，日幕城南雨。',24,'全唐诗/poet.song.17000.json','["朝看樓上雲，日幕城南雨。", "路遠香車遲，迢迢向何所。"]'),
('3f88cb6c-56ef-4520-96cd-c976d3945d92','擬玉臺體七首 別後','歐陽修','宋','宋诗','song-poetry','','[]','連環結連带，贈君情不忘。',24,'全唐诗/poet.song.17000.json','["連環結連带，贈君情不忘。", "暫別莫言易，一夕九回腸。"]'),
('7b29e8b7-9bb2-40ab-b1fc-84ae6fff155e','擬玉臺體七首 夜夜曲','歐陽修','宋','宋诗','song-poetry','','[]','浮雲吐明月，流影玉階陰。',24,'全唐诗/poet.song.17000.json','["浮雲吐明月，流影玉階陰。", "千里雖共照，安知夜夜心。"]'),
('da6e984d-203f-4f64-9efc-14069ab806de','落日窗中坐','歐陽修','宋','宋诗','song-poetry','','[]','朝聞驚禽去，日暮見禽歸。',24,'全唐诗/poet.song.17000.json','["朝聞驚禽去，日暮見禽歸。", "瑶琴坐不理，含情復爲誰。"]'),
('40227ad0-60dd-4b6a-9c4e-b0680463482e','落日窗中坐 領邊繡','歐陽修','宋','宋诗','song-poetry','','[]','雙鴛刺繡領，粲爛五文章。',24,'全唐诗/poet.song.17000.json','["雙鴛刺繡領，粲爛五文章。", "暫近已復遠，猶持歌扇障。"]'),
('a5f9c228-f860-44f8-bb4a-eb1603e72329','七交七首 河南府張推官','歐陽修','宋','宋诗','song-poetry','','[]','堯夫大雅哲，稟德實溫粹。',60,'全唐诗/poet.song.17000.json','["堯夫大雅哲，稟德實溫粹。", "霜筠秀含潤，玉海湛無際。", "平明坐大府，官事盈案几。", "高談遣放紛，外物不能累。", "非惟席上珍，乃是青雲器。"]'),
('16b2c94c-8aeb-4117-ac2c-2cd9e09e6531','七交七首 尹書記','歐陽修','宋','宋诗','song-poetry','','[]','師魯天下才，神鋒凜豪儁。',60,'全唐诗/poet.song.17000.json','["師魯天下才，神鋒凜豪儁。", "逸驥卧秋櫪，意在騤騤迅。", "平居弄翰墨，揮酒不停瞬。", "談笑帝王略，驅馳古今論。", "良工正求玉，片石胡爲韞。"]'),
('2a92f705-703e-48ed-9452-4128b3d082fb','七交七首 楊戶曹','歐陽修','宋','宋诗','song-poetry','','[]','子聰江山稟，弱歲擅奇譽。',60,'全唐诗/poet.song.17000.json','["子聰江山稟，弱歲擅奇譽。", "盱衡恣文辯，落筆妙言語。", "胡爲冉冉趨，三十滯公府。", "美璞思善價，浮雲有夷路。", "大雅惡速成，俟命宜希古。"]'),
('5a874955-6d81-4353-b52e-306157e85b50','七交七首 梅主簿','歐陽修','宋','宋诗','song-poetry','','[]','聖俞翹楚才，乃是東南秀。',60,'全唐诗/poet.song.17000.json','["聖俞翹楚才，乃是東南秀。", "玉山高岑岑，映我覺形陋。", "離騷喻草香，詩人識鳥獸。", "城中爭擁鼻，欲學不能就。", "平日禮文賢，寧久滯奔走。"]'),
('089c6e81-ac98-4a1b-a091-b918c41e53ff','七交七首 張判官','歐陽修','宋','宋诗','song-poetry','','[]','洛城車隆隆，曉門爭道入。',72,'全唐诗/poet.song.17000.json','["洛城車隆隆，曉門爭道入。", "連袂紛如帷，文者豈無十。", "壯矣張太素，拂羽擇其集。", "遠慕鄴才子，一笑懽相挹。", "雖有軒與冕，攀翔莫能及。", "人將孰君子，盍視其遊執。"]'),
('70ea4f10-a803-4eb0-9a22-d00ddfad849f','七交七首 王秀才','歐陽修','宋','宋诗','song-poetry','','[]','幾道顔之徒，沈深務覃聖。',60,'全唐诗/poet.song.17000.json','["幾道顔之徒，沈深務覃聖。", "采藻薦良璧，文潤相輝映。", "入市羊駕車，談道犀爲柄。", "時時一文出，往往紙價盛。", "無爲戀丘樊，遂滯蒲輪聘。"]'),
('d5ec8142-f55a-4612-9b7a-74dd85524626','七交七首 自敘','歐陽修','宋','宋诗','song-poetry','','[]','余本漫浪者，茲亦漫爲官。',72,'全唐诗/poet.song.17000.json','["余本漫浪者，茲亦漫爲官。", "胡然類鴟夷，託載隨車轅。", "時士不俛眉，默默誰與言。", "賴有洛中俊，日許相躋攀。", "飲德醉醇酎，襲馨佩春蘭。", "平時罷軍檄，文酒聊相歡。"]'),
('65035214-3069-4ab7-b80c-292d373167b0','答楊闢喜雨長句','歐陽修','宋','宋诗','song-poetry','','[]','吾聞陰陽在天地，升降上下無時窮。',192,'全唐诗/poet.song.17000.json','["吾聞陰陽在天地，升降上下無時窮。", "環回不得不差失，所以歲時無常豐。", "古之爲政知若此，均節收歛勤人功。", "三年必有一年食，九歲常備三歲兇。", "縱令水旱或時遇，以多補少能相通。", "今者吏愚不善政，民亦游惰離於農。", "軍國賦歛急星火，兼并奉養過王公。", "終年之耕幸一熟，聚而耗者多於蠭。", "是以比歲屢登稔，然而民室常虛空。", "遂令一時暫不雨，輒以困急號天翁。", "賴天閔民不責吏，甘澤流布何其濃。", "農當勉力吏當愧，敢不酌酒澆神龍。"]'),
('ada34d49-d445-4fb2-a67e-a3ac0b927855','嵩山十二首 公路澗','歐陽修','宋','宋诗','song-poetry','','[]','驅馬渡寒流，斷澗橫荒堡。',48,'全唐诗/poet.song.17000.json','["驅馬渡寒流，斷澗橫荒堡。", "槎危欲欹岸，花落多依草。", "擊汰翫游鯈，倒影看飛鳥。", "留連愛芳社，漸下西峯照。"]'),
('50c7b07d-4cab-40b7-b8bd-399a4a549ce1','嵩山十二首 拜馬澗','歐陽修','宋','宋诗','song-poetry','','[]','昔聞王子晉，把袂浮丘仙。',36,'全唐诗/poet.song.17000.json','["昔聞王子晉，把袂浮丘仙。", "金駿於此墮，吹笙不復還。", "玉蹄無迹久，澗草但荒煙。"]'),
('00cfb241-b795-496c-b013-44d72eb49053','嵩山十二首 二室道','歐陽修','宋','宋诗','song-poetry','','[]','二室對岧嶢，羣峯聳崷直。',48,'全唐诗/poet.song.17000.json','["二室對岧嶢，羣峯聳崷直。", "雲隨高下起，路轉參差碧。", "春晚桂叢深，日下山煙白。", "芝英已可茹，悠然想泉石。"]'),
('c832414b-b435-4dd0-8a4a-e7510f7e2a8f','嵩山十二首 自峻極中院步登太室中峯','歐陽修','宋','宋诗','song-poetry','','[]','繫馬青松陰，躡屣蒼崖路。',36,'全唐诗/poet.song.17000.json','["繫馬青松陰，躡屣蒼崖路。", "驚鳥動林花，空山答人語。", "雲霞不可攬，直入冥冥霧。"]'),
('a43da4e2-a4ff-4fe4-807e-e4245d918377','嵩山十二首 玉女窗','歐陽修','宋','宋诗','song-poetry','','[]','玉女不可邀，蒼崖鬰岧直。',36,'全唐诗/poet.song.17000.json','["玉女不可邀，蒼崖鬰岧直。", "石乳滴空竇，仰見泬寥碧。", "徙倚難久留，桂樹含春色。"]'),
('30eef9a1-abe8-468f-8cd2-c85dcb482683','嵩山十二首 玉女擣衣石','歐陽修','宋','宋诗','song-poetry','','[]','玉女擣仙衣，夜下青松嶺。',36,'全唐诗/poet.song.17000.json','["玉女擣仙衣，夜下青松嶺。", "山深風露寒，月杵遥相應。", "靈蹤杳可尋，片石秋光瑩。"]'),
('5d4141f9-f360-4ae8-9a64-ab15763d7112','嵩山十二首 天門','歐陽修','宋','宋诗','song-poetry','','[]','石徑方盤紆，雙峯忽中斷。',36,'全唐诗/poet.song.17000.json','["石徑方盤紆，雙峯忽中斷。", "呀豁青冥間，畜泄煙雲亂。", "杉蘿試舉手，自可階天漢。"]'),
('ebb4071f-3d35-4d28-b1e6-9238f4421f8c','嵩山十二首 天門泉','歐陽修','宋','宋诗','song-poetry','','[]','煙霞天門深，靈泉吐巖側。',36,'全唐诗/poet.song.17000.json','["煙霞天門深，靈泉吐巖側。", "雲濕顥氣寒，石老林腴碧。", "長松暫休坐，一酌煩心滌。"]'),
('a8494ca4-6f8d-49b9-bea0-33cb11910761','嵩山十二首 天池','歐陽修','宋','宋诗','song-poetry','','[]','高步登天池，靈源湛然吐。',36,'全唐诗/poet.song.17000.json','["高步登天池，靈源湛然吐。", "俯窺不可見，淵默神龍護。", "靜夜天籟寒，宿客疑風雨。"]'),
('fd1a626d-cce4-4d41-8980-f0b68a260980','嵩山十二首 三醉石','歐陽修','宋','宋诗','song-poetry','','[]','拂石登古壇，曠懷聊共醉。',36,'全唐诗/poet.song.17000.json','["拂石登古壇，曠懷聊共醉。", "雲霞伴酣樂，忽在千峯外。", "坐久還自醒，日落松聲起。"]'),
('aafcab96-3f76-44f4-a2ac-3cef74989b6c','嵩山十二首 峻極寺','歐陽修','宋','宋诗','song-poetry','','[]','路入石門見，蒼蒼深靄間。',36,'全唐诗/poet.song.17000.json','["路入石門見，蒼蒼深靄間。", "雲生石砌潤，木老天風寒。", "客來依返照，徙倚聽山蟬。"]'),
('de601cf3-fa2a-4bc3-b97e-38c49c768835','嵩山十二首 中峯','歐陽修','宋','宋诗','song-poetry','','[]','望望不可到，行行何屈盤。',36,'全唐诗/poet.song.17000.json','["望望不可到，行行何屈盤。", "一逕林杪出，千巖雲下看。", "煙嵐半明滅，落照在峯端。"]'),
('60b89ed9-d612-4a69-8aad-3f2cfa377f64','初秋普明寺竹林小飲餞梅聖俞分韻得亭臯木葉下五首  其一','歐陽修','宋','宋诗','song-poetry','','[]','臨水復欹石，陶然同醉醒。',24,'全唐诗/poet.song.17000.json','["臨水復欹石，陶然同醉醒。", "山霞坐未斂，池月來亭亭。"]'),
('46df2e09-7dbf-4457-8d2b-f3762a33fe51','初秋普明寺竹林小飲餞梅聖俞分韻得亭臯木葉下五首  其二','歐陽修','宋','宋诗','song-poetry','','[]','洛城風日美，秋色滿蘅臯。',24,'全唐诗/poet.song.17000.json','["洛城風日美，秋色滿蘅臯。", "誰同茂林下，掃葉酌松醪。"]'),
('5b585cf8-6287-4c27-a74f-a65a3879afb6','初秋普明寺竹林小飲餞梅聖俞分韻得亭臯木葉下五首  其三','歐陽修','宋','宋诗','song-poetry','','[]','野水竹間清，秋山酒中綠。',24,'全唐诗/poet.song.17000.json','["野水竹間清，秋山酒中綠。", "送子此酣歌，淮南應落木。"]'),
('b28e21df-ce7e-414a-a065-27de7c4b0a78','初秋普明寺竹林小飲餞梅聖俞分韻得亭臯木葉下五首  其四','歐陽修','宋','宋诗','song-poetry','','[]','勸客芙蓉盃，欲搴芙蓉葉。',24,'全唐诗/poet.song.17000.json','["勸客芙蓉盃，欲搴芙蓉葉。", "垂楊礙行舟，演漾回輕楫。"]'),
('ba8d9609-2953-46d1-a712-05e73f0c4a94','初秋普明寺竹林小飲餞梅聖俞分韻得亭臯木葉下五首  其五','歐陽修','宋','宋诗','song-poetry','','[]','山水日已佳，登臨同上下。',24,'全唐诗/poet.song.17000.json','["山水日已佳，登臨同上下。", "衰蘭尚可採，欲贈離居者。"]'),
('8c12240c-bbd9-48a2-83f4-500a4a87f677','和謝學士泛伊川浩然無歸意因詠劉長卿佳句作欲留篇之什','歐陽修','宋','宋诗','song-poetry','','[]','久不見南山，依然已秋色。',96,'全唐诗/poet.song.17000.json','["久不見南山，依然已秋色。", "悠哉川上行，復邀城中客。", "木落山半空，川明潦尤積。", "飛鳥鑑中看，行雲舟中白。", "夷猶白蘋裏，笑傲清風側。", "極浦追所遠，回峯高易夕。", "觴詠共留連，高懷追昔賢。", "惟應謝公興，不減向臨川。"]'),
('de0c7305-1535-4e9e-81ab-aacb282d4118','戲書拜呈學士三丈','歐陽修','宋','宋诗','song-poetry','','[]','淵明本嗜酒，一錢常不持。',60,'全唐诗/poet.song.17000.json','["淵明本嗜酒，一錢常不持。", "人邀輒就飲，酩酊籃輿歸。", "歸來步三徑，索寞繞東籬。", "詠句把黄菊，望門逢白衣。", "欣然復坐酌，獨醉卧斜暉。"]'),
('5461fb85-4570-4b99-b63b-ac06c680898f','和楊子聰答聖俞月夜見寄','歐陽修','宋','宋诗','song-poetry','','[]','秋露藹已繁，迢迢星漢回。',48,'全唐诗/poet.song.17000.json','["秋露藹已繁，迢迢星漢回。", "皎潔庭際月，流光依井苔。", "有客愛凉景，幽軒爲君開。", "所思不可極，但慰清風來。"]'),
('a9ee7db7-dfa7-4d9c-a19e-6feb12c5cc95','謝人寄雙桂樹子','歐陽修','宋','宋诗','song-poetry','','[]','有客賞芳叢，移根自幽谷。',48,'全唐诗/poet.song.17000.json','["有客賞芳叢，移根自幽谷。", "爲懷山中趣，愛此巖下綠。", "曉露秋暉浮，清陰藥欄曲。", "更待繁花白，邀君弄芒馥。"]'),
('d12ab824-ccb4-4625-a951-24569a566d55','雨中獨酌二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','老大世情薄，掩關外郊原。',72,'全唐诗/poet.song.17000.json','["老大世情薄，掩關外郊原。", "英英少年子，誰肯過我門。", "宿雲屯朝陰，暑雨清北軒。", "逍遥一罇酒，此意誰與論。", "酒味正薰烈，吾心方浩然。", "鳴禽時一弄，如與古人言。"]'),
('b4bfd574-ebff-44cb-b704-a27aeff7479d','雨中獨酌二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','幽居草木深，蒙籠蔽窗戶。',60,'全唐诗/poet.song.17000.json','["幽居草木深，蒙籠蔽窗戶。", "鳥語知天陰，蛙鳴識天雨。", "亦復命罇酒，欣茲却煩暑。", "人情貴自適，獨樂非鍾鼓。", "出門何所之，閉門誰我顧。"]'),
('c7203e27-09a8-40cc-bdfb-0912530854b6','庭前兩好樹','歐陽修','宋','宋诗','song-poetry','','[]','庭前兩好樹，日夕欣相對。',84,'全唐诗/poet.song.17000.json','["庭前兩好樹，日夕欣相對。", "風霜歲苦晚，枝葉常葱翠。", "午眠背清陰，露坐蔭高蓋。", "東城桃李月，車馬傾闤闠。", "而我不出門，依然伴憔悴。", "榮華不隨時，寂寞幸相慰。", "君子固有常，小人多變態。"]'),
('693b98ed-4387-4ba0-9c7b-9fe245d5df1d','綠竹堂獨飲','歐陽修','宋','宋诗','song-poetry','','[]','夏篁解籜陰加樛，卧齋公退無喧囂。',384,'全唐诗/poet.song.17000.json','["夏篁解籜陰加樛，卧齋公退無喧囂。", "清和況復值佳月，翠樹好鳥鳴咬咬。", "芳罇有酒美可酌，胡爲欲飲先長謠。", "人生暫別客秦楚，尚欲泣淚相攀邀。", "況茲一訣乃永已，獨使幽夢恨蓬蒿。", "憶予驅馬別家去，去時柳陌東風高。", "楚鄉留滯一千里，歸來落盡李與桃。", "殘花不共一日看，東風送哭聲嗷嗷。", "洛池不見青春色，白楊但有風蕭蕭。", "姚黄魏紫開次第，不覺成恨俱零凋。", "榴花最晚今又拆，紅綠點綴如裙腰。", "年芳轉新物轉好，逝者日與生期遥。", "予生本是少年氣，瑳磨牙角爭雄豪。", "馬遷班固洎歆向，下筆點竄皆嘲嘈。", "客來共坐說今古，紛紛落盡玉麈毛。", "彎弓或擬射石虎，又欲醉斬荆江蛟。", "自言剛氣貯心腹，何爾柔軟爲脂膏。", "吾聞莊生善齊物，平日吐論奇牙聱。", "憂從中來不自遣，强叩瓦缶何譊譊。", "伊人達者尚乃爾，情之所鍾況吾曹。", "愁填胸中若山積，雖欲强飲如沃焦。", "乃判自古英壯氣，不有此恨如何消。", "又聞浮屠說生死，滅沒謂若夢幻泡。", "前有萬古後萬世，其中一世獨虭蟧。"]'),
('b6e08a93-961a-4bb9-87f8-c9307abb3f48','暇日雨後綠竹堂獨居兼簡府中諸僚','歐陽修','宋','宋诗','song-poetry','','[]','新晴竹林茂，日夕愛此君。',120,'全唐诗/poet.song.17000.json','["新晴竹林茂，日夕愛此君。", "佳禽哢翠樹，若與幽人親。", "掃徑綠苔靜，引流清派分。", "開軒見遠岫，欹枕送歸雲。", "桐槿漸秋意，琴觴懷友文。", "浩然滄洲思，日厭京洛塵。", "車騎方開府，梁王多上賓。", "平時罷飛檄，行樂喜從軍。", "騎省悼亡後，漳濱多病身。", "南窗若可傲，方事陶潛巾。"]'),
('b63e045e-a3e7-4f7a-9445-ce50cb0de58a','江上彈琴','歐陽修','宋','宋诗','song-poetry','','[]','江水深無聲，江雲夜不明。',132,'全唐诗/poet.song.17000.json','["江水深無聲，江雲夜不明。", "抱琴舟上彈，棲鳥林中驚。", "遊魚爲跳躍，山風助清泠。", "境寂聽愈真，絃舒心已平。", "用茲有道器，寄此無景情。", "經緯文章合，諧和雌雄鳴。", "颯颯驟風雨，隆隆隱雷霆。", "無射變凜冽，黄鍾催發生。", "詠歌文王雅，怨刺離騷經。", "二典意澹薄，三盤語丁寧。", "琴聲雖可狀，琴意誰可聽。"]'),
('8425ce2a-2768-486c-9175-c84f8bd5277b','送白秀才西歸','歐陽修','宋','宋诗','song-poetry','','[]','白子來自西，投我文與書。',108,'全唐诗/poet.song.17000.json','["白子來自西，投我文與書。", "升階揖讓席，言氣溫且舒。", "萬轍走聲利，獨趨仁義塗。", "仁義荒已久，斤鋤費耕除。", "吾常患力寡，欣子好古徒。", "終當竭其力，剗治爲通衢。", "旗旄侍天子，安駕五輅車。", "盡驅天子民，垂白歌其隅。", "子其從我游，有志知何如。"]'),
('8841a701-c5d2-4579-ab86-7cf726c54d82','鞏縣初見黄河','歐陽修','宋','宋诗','song-poetry','','[]','河决三門合四水，徑流萬里東輸海。',384,'全唐诗/poet.song.17000.json','["河决三門合四水，徑流萬里東輸海。", "鞏洛之山夾而峙，河來齧山作沙嘴。", "山形迤邐若奔避，河益洶洶怒而詈。", "舟師弭檝不以帆，頃刻奔過不及視。", "舞波淵旋投沙渚，聚沫倏忽爲平地。", "下窺莫測濁且深，癡龍怪魚肆憑恃。", "我生居南不識河，但見禹貢書之記。", "其言河狀鉅且猛，驗河質書信皆是。", "昔者帝堯與帝舜，有子朱商不堪嗣。", "皇天意欲開禹聖，以水病堯民以潰。", "堯愁下人瘦若腊，眾臣薦鯀帝曰試。", "試之九載功不效，遂殛羽山慙而斃。", "禹羞父罪哀且勤，天始以書畀於姒。", "書曰五行水潤下，禹得其術因而治。", "鑿山疏流浚畎澮，分擘枝派有條理。", "萬邦入貢九州宅，生人始免生鱗尾。", "功深德大夏以家，施及三代蒙其利。", "江海淮濟洎漢沔，豈不浩渺汪而大。", "收波卷怒畏威德，萬古不敢肆兇厲。", "惟茲濁流不可律，歷自秦漢尤爲害。", "崩堅决壅勢益橫，斜跳旁出惟其意。", "制之以力不以德，驅民就溺財隨弊。", "蓋聞河源出崑崙，其山上高大無際。", "自高瀉下若激箭，一直一曲一千里。"]'),
('cfa9fe34-fc20-458a-a204-393c260c6402','代書寄尹十一兄楊十六王三','歐陽修','宋','宋诗','song-poetry','','[]','竝轡登北原，分首昭陵道。',288,'全唐诗/poet.song.17000.json','["竝轡登北原，分首昭陵道。", "秋風吹行衣，落日下霜草。", "昔日憩鞏縣，信馬行苦早。", "行行過任村，遂歷黄河隩。", "登高望河流，洶洶若怒鬧。", "予生平居南，但聞河浩渺。", "停鞍暫遊目，茫洋肆驚眺。", "並河行數曲，山坡亦縈繞。", "甖子與山口，呀險乃天竈。", "秤鈎真如鈎，上下欲顛倒。", "虎牢吏當關，譏問名已告。", "滎陽夜聞雨，故人留我笑。", "明朝已高塵，輤車引旌纛。", "傳云送主喪，窀穸詣墳兆。", "後乘皆輜軿，輪轂相輝照。", "辟易未及避，廬兒已呵噭。", "午出鄭東門，下馬僕射廟。", "中牟去鄭遠，記里十餘堠。", "抵牟日已暮，僕馬困米槀。", "漸望閶闔門，崛若中天表。", "趨門爭道入，羈鞅不及掉。", "浪墥遊九衢，風埃嘆何浩。", "京師天下聚，奔走紛擾擾。", "但聞街鼓喧，忽忽夜復曉。"]'),
('e050fa8c-d68c-4274-badf-2da2036442a3','別聖俞','歐陽修','宋','宋诗','song-poetry','','[]','車馬古城隅，喧喧分曉色。',108,'全唐诗/poet.song.17000.json','["車馬古城隅，喧喧分曉色。", "行人念歸塗，居者徒慘惻。", "薄宦共羈旅，論交喜金石。", "薦以朋酒懽，寧知歲月適。", "人事坐云變，出處俄乖隔。", "關山自茲始，揮袂舉輕策。", "歲暮寒雲多，野曠陰風積。", "征蹄踐嚴霜，別酒臨長陌。", "應念同時人，獨爲未歸客。"]'),
('d1b14b5a-df41-465f-874c-0aa0f1a33bfd','送劉秀才歸河內','歐陽修','宋','宋诗','song-poetry','','[]','落日古京門，車馬動行色。',72,'全唐诗/poet.song.17000.json','["落日古京門，車馬動行色。", "河上多悲風，山陽有歸客。", "朽篋蠹蟲篆，遺文摹鳥迹。", "言干有司知，豈顧時人識。", "山陂歲始寒，霰雪密已積。", "還愛寧久留，方言事征軛。"]'),
('85dad190-c57c-43e2-88dc-8a09a14549a8','數詩','歐陽修','宋','宋诗','song-poetry','','[]','一室曾何埽，居閑俗慮平。',120,'全唐诗/poet.song.17000.json','["一室曾何埽，居閑俗慮平。", "二毛經節變，青鑑不須驚。", "三復磨圭戒，深防悔吝生。", "四愁寧敢擬，高詠且陶情。", "五鼎期君祿，無思死必烹。", "六奇還自祕，海宇正休兵。", "七日南山霧，彪文幸有成。", "八門當鼓翼，凌厲指霄程。", "九德方居位，皇猷日月明。", "十朋如可問，從此卜嘉亨。"]'),
('a2f596b0-b29e-4651-affb-f765d38706f5','答錢寺丞憶伊川','歐陽修','宋','宋诗','song-poetry','','[]','之子問伊川，伊川已春色。',48,'全唐诗/poet.song.17000.json','["之子問伊川，伊川已春色。", "綠芷雜芳浦，青溪含白石。", "山阿昔留賞，屐齒無遺迹。", "惟有巖桂花，留芳待歸客。"]'),
('3019d691-494f-4a2e-8f2f-156e3701a4c7','書懷感事寄梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','相別始一歲，幽憂有百端。',288,'全唐诗/poet.song.17000.json','["相別始一歲，幽憂有百端。", "乃知一世中，少樂多悲患。", "每憶少年日，未知人事艱。", "顛狂無所閡，落魄去羈牽。", "三月入洛陽，春深花未殘。", "龍門翠鬰鬰，伊水清潺潺。", "逢君伊水畔，一見已開顔。", "不暇謁大尹，相携步香山。", "自茲愜所適，便若投山猿。", "幕府足文士，相公方好賢。", "希深好風骨，迥出風塵間。", "師魯心磊落，高談羲與軒。", "子漸口若訥，誦書坐千言。", "彥國善飲酒，百盞顔未丹。", "幾道事閑遠，風流如謝安。", "子聰作參軍，常跨破虎韉。", "子野乃禿翁，戲弄時脫冠。", "次公才曠奇，王霸馳筆端。", "聖俞善吟哦，共嘲爲閬仙。", "惟予號達老，醉必如張顛。", "洛陽古郡邑，萬戶美風煙。", "荒凉見宮闕，表裏壯河山。", "相將日無事，上馬若鴻翩。", "出門盡垂柳，信步即名園。"]'),
('319c9849-e49b-49ed-84e6-c42482ee2272','雜言答聖俞見寄兼簡東京諸友','歐陽修','宋','宋诗','song-poetry','','[]','昔君居洛陽，樂事無時有。',60,'全唐诗/poet.song.17000.json','["昔君居洛陽，樂事無時有。", "竇府富文章，謝墅從親友。", "豐年政頗簡，命駕時爲偶。", "不問竹林主，仍携步兵酒。", "芬芳弄嘉月，翠綠相森茂。"]'),
('6143fc27-b5bd-463d-a9eb-d3555198a6b2','聞梅二授德興令戲書','歐陽修','宋','宋诗','song-poetry','','[]','君家小謝城，爲客洛陽裏。',168,'全唐诗/poet.song.17000.json','["君家小謝城，爲客洛陽裏。", "綠髮方少年，青衫喜爲吏。", "重湖亂山綠，歸夢寄千里。", "洛浦見秋鴻，江南老芳芷。", "自言北地禽，能感南人耳。", "京國本繁花，馳逐多英軌。", "爭歌白雪曲，取酒西城市。", "朝逢油壁車，暮結青驄尾。", "歲月倏可忘，行樂方未已。", "忽爾畏簡書，翻然浩歸思。", "江山故國近，風物饒陽美。", "楚柚煙中黄，吳蓴波上紫。", "還鄉問井邑，上堂多慶喜。", "離別古所難，更畏秋風起。"]'),
('e012811a-e7ad-48c0-a7d0-b57fe2222702','戲贈','歐陽修','宋','宋诗','song-poetry','','[]','莫愁家住洛川傍，十五纖腰聞四方。',64,'全唐诗/poet.song.17000.json','["莫愁家住洛川傍，十五纖腰聞四方。", "堂上金罇邀上客，門前白馬繫垂楊。", "春風滿城花滿樹，落日花光爭粉光。", "城頭行人莫駐馬，一曲能令君斷腸。"]'),
('b400865e-5ad2-4695-bad6-bb2069f3bf4a','寄左軍巡劉判官','歐陽修','宋','宋诗','song-poetry','','[]','遥聽洛城鍾，獨渡伊川水。',48,'全唐诗/poet.song.17000.json','["遥聽洛城鍾，獨渡伊川水。", "綠樹鬰參差，行人去無已。", "因高望京邑，驅馬沿山趾。", "落日亂峯多，龍門何處是。"]'),
('7b381d1a-e5b5-468d-b30a-802262aebb42','罷官後初還襄城弊居述懷十韻回寄洛中舊寮','歐陽修','宋','宋诗','song-poetry','','[]','路盡見家山，欣然望吾廬。',120,'全唐诗/poet.song.17000.json','["路盡見家山，欣然望吾廬。", "陋巷叩柴扉，迎候遥驚呼。", "兒童戲竹馬，田里邀籃輿。", "春桑鬰已綠，歲事催農夫。", "朝日飛雉雊，東皋新雨餘。", "植杖望遠林，行歌登故墟。", "夙志在一壑，茲焉將荷鋤。", "言謝洛社友，因招洛中愚。", "馬卿已倦客，嚴安猶獻書。", "行矣方于役，豈能遂歸歟。"]'),
('f7b494b9-2d74-44dd-99b6-068976746206','和聖俞聚蚊','歐陽修','宋','宋诗','song-poetry','','[]','頹陽照窮巷，暑退凉風生。',264,'全唐诗/poet.song.17000.json','["頹陽照窮巷，暑退凉風生。", "夫子卧環堵，振衣步前楹。", "愁煙四鄰起，鳥雀喧空庭。", "餘景藹欲昏，眾蚊復薨薨。", "羣飛豈能數，但厭聲營營。", "抱琴不暇撫，揮麈無由停。", "散帙復歸卧，詠言聊寫情。", "覆載無巨細，善惡皆生成。", "朽木出眾蠹，腐草爲飛螢。", "書魚長陰溼，鬰雞由鬰蒸。", "豕鬣固多虱，牛閑常聚虻。", "元氣或臺鬰，𢹔之爲孽腥。", "卑臭乃其類，清虛非所經。", "華堂敞高棟，綺疏仍藻扃。", "金紅瑩椒壁，玉壺含夜冰。", "終朝事薰祓，豈敢近簷甍。", "富貴非苟得，抱節居茅衡。", "陰牆百蟲聚，下偃眾穢盈。", "何嘗曲肱樂，但苦聚雷聲。", "江南美山水，水木正秋明。", "自古佳麗國，能助詩人情。", "喧囂不可久，片席何時征。"]'),
('aa0e7fa7-b02e-4f7e-8ec8-2db26ca83b5d','送劉學士知衡州','歐陽修','宋','宋诗','song-poetry','','[]','楊子懶屬書，平居惟嗜酒。',132,'全唐诗/poet.song.17000.json','["楊子懶屬書，平居惟嗜酒。", "一沐或彌旬，解酲須五斗。", "淡爾輕榮利，何常問無有。", "忍憶四馬歸，行爲一麾守。", "湘酎自古醇，醽水聞名久。", "簿領但盈几，聖經不離口。", "湖田賦稻蟹，民訟爭垅畝。", "兀爾即沈冥，安能知可否。", "聊爲寄情樂，豈與素懷偶。", "藏器思適時，投刃寧煩手。", "行當考官績，勿復困甖缶。"]'),
('ebd5d3b8-7c96-4195-8106-d50b79ca7187','送張屯田歸洛歌','歐陽修','宋','宋诗','song-poetry','','[]','昔年洛浦見花落，曾作悲歌歌落花。',288,'全唐诗/poet.song.17000.json','["昔年洛浦見花落，曾作悲歌歌落花。", "愁來欲遣何可柰，時向金河尋杜家。", "杜家花雖非絕品，猶可開顔爲之飲。", "少年意氣易成懽，醉不還家伴花寢。", "一來京國兩傷春，憔悴窮愁九陌塵。", "紅房紫莟處處有，騎馬欲尋無故人。", "黄河三月入隋河，河水多時悵望多。", "爲憐此水來何處，中有伊流與洛波。", "忽聞君至自西京，洗眼相看眼暫明。", "心衰面老畏人問，驚我瘦骨清如冰。", "今年七月妹喪夫，稚兒孀女啼呱呱。", "季秋九月予喪婦，十月厭厭成病軀。", "端居移病新城下，日不出門無過者。", "獨行時欲强高歌，一曲未終雙涕淚。", "可憐明月與春風，歲歲年年事不同。", "暫別已嗟非舊態，再來應是作衰翁。", "感時惜別情無已，無酒送君空有淚。", "西歸必有問君人，爲道別來今若此。"]'),
('dc56e960-046b-4d7a-a327-039f3e3e99e3','述懷送張總之','歐陽修','宋','宋诗','song-poetry','','[]','鬰鬰河堤綠樹平，送君困得到東城。',176,'全唐诗/poet.song.17000.json','["鬰鬰河堤綠樹平，送君困得到東城。", "落花已盡鸎猶囀，垂柳初長蟬欲鳴。", "去年送客亦曾到，正值楊花亂芳草。", "人心不復故時歡，景物自隨時節好。", "感今懷昔復傷離，一別相逢知幾時。", "莫辭今日一罇酒，明日思君難重持。", "東吳山水天下秀，羨君輕舟片帆逗。", "江城月下夜聞歌，淮浦山前朝放溜。", "樂哉此行時未晚，萬壑千巖不知遠。", "可憐病客厭京塵，寂寞淹留已再春。", "扁舟待得東南下，猶更河橋送幾人。"]'),
('943cf550-83a3-414d-8f37-810c0431decc','送子野','歐陽修','宋','宋诗','song-poetry','','[]','四時慘舒不可調，冬夏寒暑易鬰陶。',240,'全唐诗/poet.song.17000.json','["四時慘舒不可調，冬夏寒暑易鬰陶。", "春陽著物大軟媚，獨有秋節最勁豪。", "金方堅剛屏炎瘴，兌氣高爽清風飚。", "煙霞破散灝氣豁，山河震發地脈摇。", "天開寶鑑露寒月，海拍積雪卷怒潮。", "光輝通透奪星耀，蟠潛驚奮鬭蜃蛟。", "高樓精爽毛髮竦，壯懷直恐衝斗杓。", "欲飛輕衣上拂漢，擬乘王氣戲鷺濤。", "念時文法密於織，覊縻束縛不自聊。", "豈無策議獻人主，扼持舌在口已膠。", "當秋且幸際軒豁，誰能兒女聽螗蜩。", "君方壯歲襟宇快，名聲樂與家聲高。", "輕舟從遊山川底，詩酒合興皆翹翹。", "堪嗟宋玉自悲攪，可並張翰同逍遥。", "功名富貴有時到，忍把壯節良辰消。"]'),
('e9b1896d-aeb1-40af-a2a1-00695734d841','送劉十三南遊','歐陽修','宋','宋诗','song-poetry','','[]','決決汴河流，櫓聲過晚浦。',48,'全唐诗/poet.song.17000.json','["決決汴河流，櫓聲過晚浦。", "行客問吳山，舟人多楚語。", "春深紫蘭澤，夏早黄梅雨。", "時應賦登眺，聊以忘覊旅。"]'),
('b85b13bb-c59f-4254-b514-8d7ef5ef663c','與李獻臣宋子京春集東園得節字','歐陽修','宋','宋诗','song-poetry','','[]','綠野秀可餐，遊驂喜初結。',72,'全唐诗/poet.song.17000.json','["綠野秀可餐，遊驂喜初結。", "芸局苦寂寥，禁署隔清切。", "歡言得幽尋，況此及嘉節。", "鳥哢已關關，泉流初決決。", "紫萼繁若綴，翠苕柔可擷。", "屢期無後時，芳物畏鶗鴂。"]'),
('0e8f8146-1e50-4003-9ba8-2c12dc7b8f76','晚泊岳陽','歐陽修','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u8d2c\u8c2a", "\u5b8b\u8bd7", "\u5199\u666f", "\u601d\u5f52"]','卧聞岳陽城裏鍾，繫舟岳陽城下樹。',64,'全唐诗/poet.song.17000.json','["卧聞岳陽城裏鍾，繫舟岳陽城下樹。", "正見空江明月來，雲水蒼茫失江路。", "夜深江月弄清輝，水上人歌月下歸。", "一闋聲長聽不盡，輕舟短楫去如飛。"]'),
('4027a14a-094e-40ec-aaf6-c030831e7a54','新開棊軒呈元珍表臣','歐陽修','宋','宋诗','song-poetry','','[]','竹樹日已滋，軒窗漸幽興。',48,'全唐诗/poet.song.17000.json','["竹樹日已滋，軒窗漸幽興。", "人閑與世遠，鳥語知境靜。", "春光藹欲布，山色寒尚映。", "獨收萬慮心，於此一枰競。"]'),
('5c6e1bb4-5b88-4481-97a8-4168f320f10e','代贈田文初','歐陽修','宋','宋诗','song-poetry','','[]','感君一顧重千金，贈君白璧爲妾心。',96,'全唐诗/poet.song.17000.json','["感君一顧重千金，贈君白璧爲妾心。", "舟中繡被薰香夜，春雪江頭三尺深。", "西陵長官頭已白，憔悴窮愁媿相識。", "手持玉斝唱陽春，江上梅花落如積。", "津亭送別君未悲，夢闌酒解始相思。", "須知巫峽聞猿處，不似荆江夜雪時。"]'),
('85d4d786-3b17-4aa3-8477-99701305f9bf','惠泉亭','歐陽修','宋','宋诗','song-poetry','','[]','翠壁刻孱顔，煙霞跬步間。',120,'全唐诗/poet.song.17000.json','["翠壁刻孱顔，煙霞跬步間。", "使君能愛客，朝夕弄山泉。", "春巖雨過春流長，置酒來聽山溜響。", "鑑中樓閣俯清池，雪裏峯巒開曉幌。", "須知清興無時已，酒美賓嘉自相對。", "席間誰伴謝公吟，日暮多逢山簡醉。", "淹留桂樹幾經春，野鳥巖花識使君。", "使君今是罇前客，誰與山泉作主人。"]'),
('72ae3e06-45d2-4ca5-8662-a4b1f2697c90','過張至祕校莊','歐陽修','宋','宋诗','song-poetry','','[]','田家何所樂，籉笠日相親。',96,'全唐诗/poet.song.17000.json','["田家何所樂，籉笠日相親。", "桑條起蠶事，菖葉候耕辰。", "望歲占風色，寬徭知政仁。", "樵漁逐晚浦，雞犬隔前村。", "泉溜塍間動，山田樹杪分。", "鳥聲梅店雨，野色柳橋春。", "有客問行路，呼童驚候門。", "焚魚酌白醴，但坐且懽忻。"]'),
('faa3bbf8-104a-4d09-b875-a1bfbbbb065e','行次葉縣','歐陽修','宋','宋诗','song-poetry','','[]','朝渡汝河流，暮宿楚山曲。',48,'全唐诗/poet.song.17000.json','["朝渡汝河流，暮宿楚山曲。", "城陰日下寒，野氣春深綠。", "征車倦長道，故國有喬木。", "行行漸樂郊，東風滿平陸。"]'),
('ded7a3a3-7791-42c9-8c93-a0ce251afb2b','將至淮安馬上早行學謝靈運體六韻','歐陽修','宋','宋诗','song-poetry','','[]','晴霞煦東浦，驚鳥動煙林。',72,'全唐诗/poet.song.17000.json','["晴霞煦東浦，驚鳥動煙林。", "曙河兼斗沒，沓嶂隱雲深。", "寒雞隔樹起，曲塢留風吟。", "征失倦行役，秋興感登臨。", "衡皋積涂迥，江蘺香露沉。", "行矣歲華晚，歸歟勞歎音。"]'),
('615ed839-3d12-4256-912a-26a1a50cbbbc','自岐江山行至平陸驛五言二十四韻','歐陽修','宋','宋诗','song-poetry','','[]','岐江望平陸，百里千餘嶺。',288,'全唐诗/poet.song.17000.json','["岐江望平陸，百里千餘嶺。", "蕭條斷煙火，莽蒼無人境。", "峯巒互前後，南北失壬丙。", "天秋雲愈高，木落歲方冷。", "水涉愁蜮射，林行憂虎猛。", "萬仞懸巖崖，一彴履枯梗。", "緣危類猨猱，陷淖若蛙黽。", "腰輿懼傾撲，煩馬倦鞭警。", "攀躋誠畏塗，習俗羨蠻獷。", "度隘足雖踠，因高目還騁。", "九野畫荆衡，羣山亂巫郢。", "煙嵐互明滅，點綴成圖屏。", "時時度深谷，往往得佳景。", "翠樹鬰如蓋，飛泉溜垂綆。", "幽花亂黄紫，蒨粲弄光影。", "山鳥囀成歌，寒蜩嘒如哽。", "登臨雖云勞，巨細得周省。", "晨裝趁徒旅，夕宿訪閭井。", "村暗水茫茫，雞鳴星耿耿。", "登高近佳節，歸思時引領。", "谿菊薦山罇，田鴽佐烹鼎。", "家近夢先歸，夜寒衾屢整。", "崎嶇念行役，昔宿已爲永。", "豈如江上舟，棹歌方酩酊。"]'),
('68f6b872-a074-43db-868a-7198e672af8e','春日西湖寄謝法曹歌','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6625\u5929", "\u601d\u4e61", "\u5199\u666f"]','西湖春色歸，春水綠於染。',120,'全唐诗/poet.song.17000.json','["西湖春色歸，春水綠於染。", "羣芳爛不收，東風落如糝。", "參軍春思亂如雲，白髮題詩愁送春。", "遥知湖上一罇酒，能憶天涯萬里人。", "萬里思春尚有情，忽逢春至客心驚。", "雪消門外千山綠，花發江邊二月晴。", "少年把酒逢春色，今日逢春頭已白。", "異鄉物態與人殊，惟有東風舊相識。"]'),
('14789f4f-2d0d-4e2a-b2a2-9432ba433a71','答謝景山遺古瓦硯歌','歐陽修','宋','宋诗','song-poetry','','[]','火數四百炎靈銷，誰其代者當塗高。',384,'全唐诗/poet.song.17000.json','["火數四百炎靈銷，誰其代者當塗高。", "窮姦極酷不易取，始知文景基扃牢。", "坐揮長喙啄天下，豪傑競起如蝟毛。", "董呂傕汜相繼死，紹術權備爭咆咻。", "力彊者勝怯者敗，豈較才德爲功勞。", "然猶到手不敢取，而使螟蝗生蝮蜪。", "子丕當初不自耻，敢謂舜禹傳之堯。", "得之以此失亦此，誰知三馬食一槽。", "當其盛時爭意氣，叱咤雷雹生風飚。", "干戈戰罷數功閥，周蔑方召堯無皋。", "英雄致酒奉高會，巍然銅雀高岧岧。", "圓歌宛轉激清徵，妙舞左右回纖腰。", "一朝西陵看拱木，寂寞繐帳空蕭蕭。", "當時凄涼已可歎，而況後世悲前朝。", "高臺已傾漸平地，此瓦一墜埋蓬蒿。", "苔文半滅荒土蝕，戰血曾經野火燒。", "敗皮弊網各有用，誰使鎸鑱成凸凹。", "景山筆力若半弩，句遒語老能揮毫。", "嗟予奪得何所用，簿領朱墨徒紛淆。", "走官南北未嘗捨，緹襲三四勤緘包。", "有時屬思欲飛灑，意緒軋軋難抽繰。", "舟行屢備水神奪，往往冥晦遭風濤。", "質頑物久有精怪，常恐變化成靈妖。", "名都所至必傳玩，愛之不換魯寶刀。"]'),
('ff456c28-f594-4b0c-884a-c5599a395f24','古瓦硯','歐陽修','宋','宋诗','song-poetry','','[]','甎瓦賤微物，得廁筆墨間。',72,'全唐诗/poet.song.17000.json','["甎瓦賤微物，得廁筆墨間。", "於物用有宜，不計醜與妍。", "金非不爲寶，玉豈不爲堅。", "用之以發墨，不及瓦礫頑。", "乃知物雖賤，當用價難攀。", "豈惟瓦礫爾，用人從古難。"]'),
('e90e2d3a-7daa-4fe3-87bf-47f75397ea03','新營小齋鑿地爐輒成五言三十七韻','歐陽修','宋','宋诗','song-poetry','','[]','霜降百工休，居者皆入室。',288,'全唐诗/poet.song.17000.json','["霜降百工休，居者皆入室。", "墐戶畏初寒，開爐代溫律。", "規模不盈丈，廣狹足容膝。", "軒窗共幽窳，竹栢助蒙密。", "辛勤慚巧宦，窮賤守卑秩。", "無術政奚爲，有年秋屢實。", "文書少期會，租訟省鞭抶。", "地僻與世踈，官閑得身佚。", "荆蠻苦卑陋，氣候常壹鬰。", "天日每陰翳，風飆多凜凓。", "衰顔慘時晚，病骨如寒疾。", "蠻牀倦晨興，籃輿厭朝出。", "南山近樵採，僮僕免呵叱。", "禦歲畜蹲鴟，饋客薦包橘。", "霜薪吹晶熒，石鼎沸啾唧。", "披方養丹砂，候節煎秋朮。", "西鄰有高士，轗軻卧蓬蓽。", "鶴髮善高談，鮐背更炙熨。", "披裘屢相就，束縕亦時乞。", "傳經伏生老，愛酒楊雄吃。", "晨灰煖餘盃，夜火爆山粟。", "無言兩忘形，相對或終日。", "微生慕剛毅，勁强早難屈。", "自從世欲牽，常恐天性失。"]'),
('d75a9c1b-7657-4bc2-b6f9-db9a9c23eaef','南獠','歐陽修','宋','宋诗','song-poetry','','[]','洪宋區夏廣，恢張際四維。',288,'全唐诗/poet.song.17000.json','["洪宋區夏廣，恢張際四維。", "狂孽久不聳，民物含春熙。", "耆稚適所尚，游泳光華時。", "遽然攝提歲，南獠掠邊陲。", "予因叩村叟，此事曷如斯。", "初似却人問，未語先涕垂。", "收涕謝客問，爲客陳始基。", "撫水有上源，水淺山嶮巇。", "生民三千室，聚此天一涯。", "狠勇復輕脫，性若鹿與麋。", "男夫不耕鑿，刀兵動相隨。", "宜融兩境上，殺人取其貲。", "因斯久久來，此寇易爲羈。", "鼠竊及蟻聚，近裏焉敢窺。", "勢亦不久住，官軍來即馳。", "景德祥符後，時移事亦移。", "四輔哲且善，天子仁又慈。", "將軍稱招安，兵非羽林兒。", "龍江一牧拙，邏騎材亦非。", "威惠不兼濟，徒以官力欺。", "智略仍復短，從此難羈縻。", "引兵卸甲嶺，部陣自參差。", "鋒鏑殊未接，士卒心先離。", "奔走六吏死，明知國挫威。"]'),
('a341c2fc-4238-4b70-a14e-69fe41d7ef07','寄聖俞','歐陽修','宋','宋诗','song-poetry','','[]','西陵山水天下佳，我昔謫官君所嗟。',176,'全唐诗/poet.song.17000.json','["西陵山水天下佳，我昔謫官君所嗟。", "官閑憔悴一病叟，縣古瀟灑如山家。", "雪消深林自斸筍，人響空山隨摘茶。", "有時携酒探幽絕，往往上下窮煙霞。", "巖蓀綠縟軟可藉，野卉青紅春自華。", "風餘落蕊飛面旋，日暖山鳥鳴交加。", "貪追時俗翫歲月，不覺萬里留天涯。", "今來寂寞西岡口，秋盡不見東籬花。", "市亭插旗鬭新酒，十千得斗不可賒。", "材非世用自當去，一舸聱牙揮釣車。", "君能先往勿自滯，行矣春洲生荻芽。"]'),
('bdf693fe-95b2-4cd9-b30e-29fd1e8779af','答梅聖俞寺丞見寄','歐陽修','宋','宋诗','song-poetry','','[]','憶昔識君初，我少君方壯。',288,'全唐诗/poet.song.17000.json','["憶昔識君初，我少君方壯。", "風期一相許，意氣曾誰讓。", "交遊盛京洛，罇俎陪丞相。", "騄驥日相追，鸞凰志高颺。", "詞章盡崔蔡，論議皆歆向。", "文會忝予盟，詩壇推子將。", "談精鋒愈出，飲劇歡無量。", "賈勇爲無前，餘光誰敢望。", "茲年五六歲，人事堪悽愴。", "南北頓暌乖，相離獨飄蕩。", "失杯由畫足，傷手因代匠。", "移書雖激切，拙語非欺誑。", "安知乃心愚，而使所言妄。", "權豪不自避，斧質誠爲當。", "蒼皇得一邑，奔走踰千嶂。", "楚峽聽猿鳴，荆江畏蛟浪。", "蠻方異時俗，景物殊氣象。", "綠髮變風霜，丹顔侵疾癢。", "常憂鵬鳥窺，幸免江魚葬。", "今茲荷寬宥，遷徙來漢上。", "惟悴戴囚冠，驅馳嗟俗狀。", "王事多倥傯，學業差遺忘。", "未能解綬去，所戀寸祿養。", "舉足畏逢仇，低頭惟避謗。"]'),
('d941b274-22bd-47e3-8571-82412f322dde','酬聖俞朔風見寄','歐陽修','宋','宋诗','song-poetry','','[]','因君朔風句，令我苦寒吟。',84,'全唐诗/poet.song.17000.json','["因君朔風句，令我苦寒吟。", "離別時未幾，崢嶸歲再陰。", "驚飚擊曠野，餘響入空林。", "客路行役遠，馬蹄冰雪深。", "瞻言洛中舊，期我高陽吟。", "故館哭知己，新年傷客心。", "相逢豈能飲，惟有涕沾襟。"]'),
('2647587f-e57a-4aa6-bb2c-145ed6afe0ae','送琴僧知白','歐陽修','宋','宋诗','song-poetry','','[]','吾聞夷中琴已久，常恐老死無其傳。',160,'全唐诗/poet.song.17000.json','["吾聞夷中琴已久，常恐老死無其傳。", "夷中未識不得見，豈謂今逢知白彈。", "遺音髣髴尚可愛，何況之子傳其全。", "孤禽曉警秋野露，空澗夜落春巖泉。", "二年遷謫寓三峽，江流無底山侵天。", "登臨探賞久不厭，每欲圖畫存於前。", "豈知山高水深意，久以寫此朱絲絃。", "酒酣耳熱神氣王，聽之爲子心肅然。", "嵩陽山高雪三尺，有客擁鼻吟苦寒。", "負琴北走乞其贈，持我此句爲之先。"]'),
('836f668a-d358-4f1c-ac4d-d1a235ad4089','聽平戎操','歐陽修','宋','宋诗','song-poetry','','[]','西戎負固稽天誅，勇夫戰死智士謨。',208,'全唐诗/poet.song.17000.json','["西戎負固稽天誅，勇夫戰死智士謨。", "上人知白何爲者，年少力壯逃浮屠。", "自言平戎有古操，抱琴欲進爲我娛。", "我材不足置廓廟，力弱又不堪戈殳。", "遭時有事獨無用，偷安飽食與汝俱。", "爾知平戎競何事，自古無不由吾儒。", "周宣六月伐獫狁，漢武五道征匈奴。", "方叔召虎乃真將，衛青去病誠區區。", "建功立業當盛日，後世稱詠於詩書。", "平生又欲慕賈誼，長纓直請繫單于。", "當衢理檢四面啟，有策不獻空踟躕。", "慙君爲我奏此曲，聽之空使壯士吁。", "推琴置酒恍若失，誰謂子琴能起予。"]'),
('756dd242-e4e2-45e8-b2a0-d60ac098f2b2','書宜城修水渠記後奉呈朱寺丞','歐陽修','宋','宋诗','song-poetry','','[]','因民之利無難爲，使民以說民忘疲。',80,'全唐诗/poet.song.17000.json','["因民之利無難爲，使民以說民忘疲。", "樂哉朱君鄣靈堤，導鄢及蠻興眾陂。", "古渠廢久人莫知，朱君三月而復之。", "沃土如膏瘠土肥，百里歲歲無兇菑。", "鄢蠻之水流不止，襄人思君無時已。"]'),
('4a961a69-f3b8-401d-82d3-77fe9a6276d5','谷正至始得先所寄書及詩不勝喜慰因書數韻奉酬聖俞','歐陽修','宋','宋诗','song-poetry','','[]','寒日照深巷，柴門朝尚閉。',144,'全唐诗/poet.song.17000.json','["寒日照深巷，柴門朝尚閉。", "有客自江來，尺書千里至。", "啟書復何云，但言南北異。", "南方地常暖，風物稱佳麗。", "梅蘤入新年，蘭皋動芳氣。", "樂哉登臨興，豈厭江湖滯。", "伊予方寂寞，刻苦窮文字。", "萬國會王州，羣英馳儁軌。", "方朔常苦餓，子雲非官意。", "歲暮慘風塵，官閑倦朝市。", "出處一云別，所思寧可冀。", "春江有歸鴈，但使音書繼。"]'),
('35e3b759-7a6b-410e-b852-a9e16b41b33c','答梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','寒日照窮巷，荆扉晨未開。',72,'全唐诗/poet.song.17000.json','["寒日照窮巷，荆扉晨未開。", "驚聞遠方信，有客渡江來。", "開緘復何喜，宛若見瓊瑰。", "一爾乖出處，未嘗持酒盃。", "官閑隱朝市，歲暮慘風埃。", "音書日可待，春鴈暖應回。"]'),
('b082fb76-8217-494c-aa82-170fe99db71e','病中聞梅二南歸','歐陽修','宋','宋诗','song-poetry','','[]','聞君解舟去，秋水正沄沄。',84,'全唐诗/poet.song.17000.json','["聞君解舟去，秋水正沄沄。", "野岸曠歸思，都門辭世紛。", "稍逐商帆伴，初隨征鴈羣。", "山多淮甸出，柳盡汴河分。", "楚色蕪尚綠，江煙日半曛。", "客意浩已遠，離懷寧復云。", "宣城好風月，歸信幾時聞。"]'),
('f771fa1f-ffdd-42ef-b8cc-53f857bb3c62','送智蟾上人遊天台','歐陽修','宋','宋诗','song-poetry','','[]','昔年在伊洛，林壑每相從。',120,'全唐诗/poet.song.17000.json','["昔年在伊洛，林壑每相從。", "對掃竹下榻，坐思湖上峯。", "自言伊洛波，每起滄洲憶。", "今茲道行遊，千里東南國。", "都門汴河上，柳色入青煙。", "流水向淮浦，歸人隨越船。", "東南遍林巘，萬壑新流滿。", "小桂綠應芳，江春行已晚。", "藹藹赤城陰，依依識古岑。", "一去誰復見，石橋雲霧深。"]'),
('f5124b2b-ce17-42cb-a0c8-7f4cff6a92ed','送徐生秀州法曹','歐陽修','宋','宋诗','song-poetry','','[]','一笑暫相從，結交方恨晚。',48,'全唐诗/poet.song.17000.json','["一笑暫相從，結交方恨晚。", "猶茲簿領困，況爾東南遠。", "落帆淮口暮，採石江洲暖。", "黄鴿可寄書，惟嗟雙翅短。"]'),
('e8453197-0c36-41f9-8c3e-39ab6b7e15cc','讀山海經圖','歐陽修','宋','宋诗','song-poetry','','[]','夏鼎象九州，山經有遺載。',96,'全唐诗/poet.song.17000.json','["夏鼎象九州，山經有遺載。", "空濛大荒中，杳靄羣山會。", "炎海積歊蒸，陰幽異明晦。", "奔趨各異種，倏忽俄萬態。", "羣倫固殊稟，至理寧一槩。", "駭者自云驚，生兮孰知怪。", "未能識造化，但爾披圖繪。", "不有萬物殊，豈知方輿大。"]'),
('7033c667-b8d7-4083-bcaf-321ffbb214d5','依韻和聖俞見寄','歐陽修','宋','宋诗','song-poetry','','[]','與君結交深，相濟同水火。',120,'全唐诗/poet.song.17000.json','["與君結交深，相濟同水火。", "文章發春葩，節行凜筠笴。", "吾才已愧君，子齒又先我。", "君惡予所非，我許子云可。", "厥趣共乖時，畏塗難轉輠。", "道肥家所窮，身老志彌果。", "每嗟游從異，有甚樊籠鎖。", "天匠染青紅，花腰呈裊娜。", "苟能杯酌同，直待冠巾墮。", "無欺校讎貧，鹽米尚餘顆。"]'),
('86f9e4b8-b943-4dde-9164-f7c50935343d','晏太慰西園賀雪歌','歐陽修','宋','宋诗','song-poetry','','[]','陰陽乖錯辭五行，窮冬山谷暖不冰。',258,'全唐诗/poet.song.17000.json','["陰陽乖錯辭五行，窮冬山谷暖不冰。", "一陽且出在地上，地下誰發萬物萌。", "太陰當用不用事，蓋由姦將不軒虧國刑。", "遂令邪風伺間隙，潛中瘟疫於疲氓。", "神哉陛下至仁聖，憂勤懇禱通精誠。", "聖人與天同一體，意未發口天已聽。", "忽收寒威還水官，正時肅物凜以清。", "寒風得勢獵獵走，瓦乾霰急落不停。", "恍然天地半夜白，羣雞失曉不及鳴。", "清晨拜表東上閤，鬰鬰瑞氣盈宮庭。", "退朝騎馬下銀闕，馬滑不慣行瑶瓊。", "晚趨賓館賀太尉，坐覺滿路流歡聲。", "便開西園掃徑步，正見玉樹花凋零。", "小軒却坐對山石，拂拂酒面紅煙生。", "主人與國共休戚，不惟喜悅將豐登。", "須憐鐵甲冷徹骨，四十餘萬屯邊兵。"]'),
('14df4081-53d8-42b3-8294-d24a2dea4bd9','送吳照鄰還江南','歐陽修','宋','宋诗','song-poetry','','[]','霜前江水磨碧銅，岸背菱葉翹青蟲。',64,'全唐诗/poet.song.17000.json','["霜前江水磨碧銅，岸背菱葉翹青蟲。", "吳郎鬢絲生幾縷，不羞月上扶桑東。", "羞見清波照人景，去時黑髮吹春風。", "五年歸來婦應喜，從此不問西飛鴻。"]'),
('490debcd-6b8f-4fcf-9b22-40d5b26fead2','答朱宷捕蝗詩','歐陽修','宋','宋诗','song-poetry','','[]','捕蝗之術世所非，欲究此語興於誰。',384,'全唐诗/poet.song.17000.json','["捕蝗之術世所非，欲究此語興於誰。", "或云豐兇歲有數，天孽未可人力支。", "或言蝗多不易捕，驅民入野踐其畦。", "因之姦吏恣貪擾，戶到頭斂無一遺。", "蝗災食苗民自苦，吏虐民苗皆被之。", "吾嗟此語祗知一，不究其本論其皮。", "驅雖不盡勝養患，昔人固已决不疑。", "秉蟊投火況舊法，古之去惡猶如斯。", "既多而捕誠未易，其失安在常由遲。", "詵詵最說子孫眾，爲腹所孕多蜫蚳。", "始生朝畝暮已頃，化一爲百無根涯。", "口含鋒刃疾風雨，毒腸不滿疑常饑。", "高原下濕不知數，進退整若隨金鼙。", "嗟茲羽孽物共惡，不知造化其誰尸。", "大凡萬事悉如此，禍當早絕防其微。", "蠅頭出土不急捕，羽翼已就功難施。", "只驚羣飛自天下，不究生子由山陂。", "官書立法空太峻，吏愚畏罰反自欺。", "蓋藏十不敢申一，上心雖惻何由知。", "不如寬法擇良令，告蝗不隱捕以時。", "今苗因捕雖踐死，明歲猶免爲蝝菑。", "吾嘗捕蝗見其事，較以利害曾深思。", "官錢二十買一斗，示以明信民爭馳。", "歛微成眾在人力，頃刻露積如京坻。"]'),
('85f2b514-cc31-4ef3-88ed-bf3f09129f2d','答蘇子美離京見寄','歐陽修','宋','宋诗','song-poetry','','[]','眾奇子美貌，堂堂千人英。',288,'全唐诗/poet.song.17000.json','["眾奇子美貌，堂堂千人英。", "我獨疑其胸，浩浩包滄溟。", "滄溟產龍蜃，百怪不可名。", "是以子美辭，吐出人輒驚。", "其於詩最豪，奔放何縱橫。", "眾絃排律呂，金石次第鳴。", "間以險絕句，非時震雷霆。", "兩耳不及掩，百痾爲之醒。", "語言既可駭，筆墨尤其精。", "少雖嘗力學，老乃若天成。", "濡毫弄點畫，信手不自停。", "端莊雜醜怪，羣星見攙槍。", "爛然溢紙幅，視久無定形。", "使我終老學，得一已足矜。", "而君兼眾美，磊落猶自輕。", "高冠出人上，誰敢揖其膺。", "羣臣列丹陛，幾位缺公卿。", "使之束带立，可以重朝廷。", "況令參國議，高論吐崢嶸。", "惜哉三十五，白髮今已生。", "近者去江淮，作詩寄離情。", "口誦不及寫，一日傳都城。", "退之序百物，其鳴由不平。", "天方苦君心，欲使發其聲。"]'),
('f18c51d4-9d56-4271-86a0-aa63a1894ae9','立秋有感寄蘇子美','歐陽修','宋','宋诗','song-poetry','','[]','庭樹忽改色，秋風動其枝。',96,'全唐诗/poet.song.17000.json','["庭樹忽改色，秋風動其枝。", "物情未必爾，我意先已悽。", "雖恐芳節謝，猶忻早凉歸。", "起步雲月暗，顧瞻星斗移。", "四時有大信，萬物誰與期。", "故人在千里，歲月令我悲。", "所嗟事業晚，豈惜顔色衰。", "廟謀今謂何，胡馬日以肥。"]'),
('0be5c801-92aa-484f-a6a2-6e60c3acc0a3','喜雪示徐生','歐陽修','宋','宋诗','song-poetry','','[]','清穹凜冬威，旱野渴天澤。',216,'全唐诗/poet.song.17000.json','["清穹凜冬威，旱野渴天澤。", "經旬三尺雪，萬物變顔色。", "愁雲噓不開，慘慘連日夕。", "寒風借天勢，豪忽肆陵轢。", "空枝凍鳥雀，癡不避彈弋。", "長河寂無聲，厚地若龜坼。", "陰階夜自照，缺瓦晨復積。", "貯潔瑩冰壺，量深埋玉尺。", "凝陰反窮剝，陽九兆初畫。", "春回百草心，氣動黄泉脈。", "堅冰雖未破，土潤已潛釋。", "常聞老農語，一臘見三白。", "是爲豐年候，占驗勝蓍策。", "天兵血西陲，萬轍走供億。", "嗟予媿疲俗，奚術肥爾瘠。", "惟幸歲之穰，茲惠豈人力。", "非徒給租調，且可銷盜賊。", "從今潔鬴廩，期共飽麰麥。"]'),
('f44a8cb9-8cda-447c-af0b-db9147604ee8','賦竹上甘露','歐陽修','宋','宋诗','song-poetry','','[]','梢梢兩竹枝，甘露葉間垂。',72,'全唐诗/poet.song.17000.json','["梢梢兩竹枝，甘露葉間垂。", "草木有靈液，陰陽凝以時。", "深山與窮谷，往往嘗有之。", "幸當君子軒，得爲眾人知。", "物生隨所託，晦顯各有宜。", "聊以助歌詠，兼堪飲童兒。"]'),
('95caaae7-f958-4875-9bef-ae06548fb88b','和對雪憶梅花','歐陽修','宋','宋诗','song-poetry','','[]','昔官西陵江峽間，野花紅紫多斕斑。',208,'全唐诗/poet.song.17000.json','["昔官西陵江峽間，野花紅紫多斕斑。", "惟有寒梅舊所識，異鄉每見心依然。", "爲憐花自洛中看，花上蜀鳥啼綿蠻。", "當時作詩誰唱和，粉蕊自折清香繁。", "今來把酒對殘雪，却憶江上高樓山。", "羣花四時媚者眾，何獨此樹令人攀。", "窮冬萬木立枯死，玉艷獨發陵清寒。", "鮮妍皎如鏡裏面，綽約對若風中仙。", "惜哉北地無此樹，霰雪漫漫平沙川。", "徐生隨我客此郡，冰霜旅舍逢新年。", "憶花對雪晨起坐，清詩寶鐵裁琅玕。", "長河風色暖將動，即看綠柳含春煙。", "寒齋寂寞何以慰，卯盃且醉酣午眠。"]'),
('178a2a71-de1c-4356-b113-6a83e8c6d051','歸鴈亭','歐陽修','宋','宋诗','song-poetry','','[]','荒蹊臘雪春尚埋，我初獨與徐生來。',272,'全唐诗/poet.song.17000.json','["荒蹊臘雪春尚埋，我初獨與徐生來。", "城高樹古禽鳥野，聲響格磔寒毰毸。", "頹垣敗屋巍然在，略可遠眺臨傾臺。", "高株唯有柳數十，夾路對立初誰栽。", "漸誅榛莽辨草樹，頗有桃李當牆隈。", "欣然便擬趁時節，斤鋤日夕勞耘培。", "新年風色日漸好，晴天仰見鴈已回。", "枯根老脈凍不發，遶之百匝空徘徊。", "頑姿野態煩造化，勾芒不肯先煦吹。", "酒酣幾欲揈大鼓，驚起龍蟄驅春雷。", "偶然不到才數日，顔色一變由誰催。", "翠芽紅粒迸條出，纖趺嫩萼如剪裁。", "卧槎燒枿亦强發，老朽不避眾艷咍。", "姹然山杏開最早，其餘紅白各自媒。", "初開盛發與零落，皆有意思牽人懷。", "眾芳勿使一時發，當令一落續一開。", "畢春應須酒萬斛，與子共醉三千盃。"]'),
('a19b3f7f-0e45-4697-8d92-bca556b187a0','送韓子華','歐陽修','宋','宋诗','song-poetry','','[]','嗟我久不見韓子，如讀古書思古人。',146,'全唐诗/poet.song.17000.json','["嗟我久不見韓子，如讀古書思古人。", "忽然相逢又數日，笑語反不共一罇。", "諫垣尸居職業廢，朝事汲汲勞精神。", "子華筆力天馬足，駑駘千百誰可羣。", "嗟予老鈍不自笑，尚欲疾走追其塵。", "子華有時高談駭我聽，榮枯萬物移秋春。", "所以不見令我思，見之如飲玉醴醇。", "叩門下馬忽來別，高帆得風披飛雲。", "離懷有酒不及寫，別後慰我寓於文。"]'),
('2601995f-c20c-421f-afd3-2f4df8e9974f','送李太傅知冀州','歐陽修','宋','宋诗','song-poetry','','[]','吾慕李漢超，爲將勇無儔。',204,'全唐诗/poet.song.17000.json','["吾慕李漢超，爲將勇無儔。", "養士三千人，人人百貔貅。", "關南三十年，天子不北憂。", "吾愛李允則，善覘多計籌。", "虜動靜寢食，皎如在雙眸。", "出入若變化，談笑摧敵謀。", "恩信浹南北，聲名落燕幽。", "二公材各異，戰守兩堪尤。", "天下不用兵，爾來三十秋。", "今其繼者誰，守冀得李侯。", "李侯年尚少，文武學彬彪。", "河朔一尺雪，北風煖貂裘。", "上馬擘長弓，白羽飛金鍭。", "臨行問我言，我慙本儒鯫。", "漢超雖已久，故老尚歌謳。", "允則事最近，猶能想風流。", "將此聊爲贈，勉哉行無留。"]'),
('f0e2120e-2db5-4120-a034-8304396db198','石篆詩','歐陽修','宋','宋诗','song-poetry','','[]','寒巖飛流落青苔，旁斲石篆何奇哉。',176,'全唐诗/poet.song.17000.json','["寒巖飛流落青苔，旁斲石篆何奇哉。", "其人已死骨已朽，此字不滅留山隈。", "山中老僧憂石泐，印之以紙磨松煤。", "欲令留傳在人世，持以贈客比瓊瑰。", "我疑此字非筆畫，又疑人力非能爲。", "始從天地胚渾判，元氣結此高崔嵬。", "當時野鳥踏山石，萬古遺迹於蒼崖。", "山祗不欲人屢見，每吐雲霧深藏埋。", "羣仙飛空欲下讀，常借海月清光來。", "嗟我豈能識字法，見之但覺心眼開。", "辭慳語鄙不足記，封題遠寄蘇與梅。"]'),
('b9cae7f8-5720-4470-958c-297e139f480c','題滁州醉公亭','歐陽修','宋','宋诗','song-poetry','','[]','四十未爲老，醉翁偶題篇。',132,'全唐诗/poet.song.17000.json','["四十未爲老，醉翁偶題篇。", "醉中遺萬物，豈復記吾年。", "但愛亭下水，來從亂峯間。", "聲如自空落，瀉向兩簷前。", "流入巖下溪，幽泉助涓涓。", "響不亂人語，其清非管絃。", "豈不美絲竹，絲竹不勝繁。", "所以屢携酒，遠步就潺湲。", "野鳥窺我醉，溪雲留我眠。", "山花徒能笑，不解與我言。", "惟有巖風來，吹我還醒然。"]'),
('055d472b-c01a-4c4f-adb4-44c2f699d5ed','贈學者','歐陽修','宋','宋诗','song-poetry','','[]','人稟天地氣，乃物中最靈。',96,'全唐诗/poet.song.17000.json','["人稟天地氣，乃物中最靈。", "性雖有五常，不學無由明。", "輪曲揉而就，木直在中繩。", "堅金礪所利，玉琢器乃成。", "仁義不遠躬，勤勤入至誠。", "學既積於心，猶木之敷榮。", "根本既堅好，蓊鬰其幹莖。", "爾曹宜勉勉，無以吾言輕。"]'),
('66aea821-02df-4aa8-9f82-71d966d7911a','春寒效李長吉體','歐陽修','宋','宋诗','song-poetry','','[]','東風吹雲海天黑，饑龍凍雲雨不滴。',96,'全唐诗/poet.song.17000.json','["東風吹雲海天黑，饑龍凍雲雨不滴。", "嗔雷隱隱愁煙白，宿露無光瑶草寂。", "東皇染花滿春國，天爲花迷借春色。", "呼雲鎖日恐紅蔫，幾日春陰養花魄。", "悠悠遠絮縈空擲，愁思織春挽不得。", "高樓去天無幾尺，遠岫參差亂屏碧。"]'),
('37f07049-261f-45f3-9810-44fe5dc77c6e','幽谷晚飲','歐陽修','宋','宋诗','song-poetry','','[]','一徑入蒙密，已聞流水聲。',144,'全唐诗/poet.song.17000.json','["一徑入蒙密，已聞流水聲。", "行穿翠篠盡，忽見青山橫。", "山勢抱幽谷，谷泉含石泓。", "旁生嘉樹林，上有好鳥鳴。", "鳥語谷中靜，樹凉泉影清。", "露蟬已嘒嘒，風溜時泠泠。", "渴心不待飲，醉耳傾還醒。", "嘉我二三友，偶同丘壑情。", "環流席高蔭，置酒當崢嶸。", "是時新雨餘，日落山更明。", "山色已可愛，泉聲難久聽。", "安得白玉琴，寫以朱絲繩。"]'),
('7c4f25e3-a228-4150-800a-a3a3bab75cda','桐花','歐陽修','宋','宋诗','song-poetry','','[]','猗猗井上桐，花葉何蓑蓑。',168,'全唐诗/poet.song.17000.json','["猗猗井上桐，花葉何蓑蓑。", "下蔭百尺泉，上聳陵雲材。", "翠色洗朝露，清陰午當階。", "幽蟬自嘒嘒，鳴鳥何喈喈。", "日出花照耀，飛香動浮埃。", "今朝一雨過，狼籍黏青苔。", "斯桐乃誰樹，意若銘吾齋。", "常聞漢道隆，上下相和諧。", "選吏擇孝廉，視民嬰與孩。", "政聲如九韶，百物絕妖災。", "優優潁川守，能致鳳凰來。", "到此幾千載，丹山自崔嵬。", "聖君勤治理，百郡列賢才。", "嗟爾不自勉，鳳凰其來哉。"]'),
('e8717476-509f-4e53-8d91-096fa28f3e92','思二亭送光祿謝寺丞歸滁陽  其一','歐陽修','宋','宋诗','song-poetry','','[]','吾嘗思醉翁，醉翁名自我。',132,'全唐诗/poet.song.17000.json','["吾嘗思醉翁，醉翁名自我。", "山林本我性，章服偶包裹。", "君恩未知報，進退奚爲可。", "自非因讒逐，决去焉能果。", "前時永陽謫，誰與脫韁鎖。", "山氣無四時，幽花常婀娜。", "石泉咽然鳴，野艷笑而傞。", "賓歡正諠譁，翁醉已岌峩。", "我樂世所悲，眾馳予坎軻。", "惟茲三二子，嗜好其同頗。", "因歸謝巖石，爲我刻其左。"]'),
('8455ecf7-7f22-4c5b-937a-dcfe615d8468','思二亭送光祿謝寺丞歸滁陽  其二','歐陽修','宋','宋诗','song-poetry','','[]','吾嘗思豐樂，魂夢不在身。',96,'全唐诗/poet.song.17000.json','["吾嘗思豐樂，魂夢不在身。", "三年永陽謫，幽谷最來頻。", "谷口兩三家，山泉爲四鄰。", "但聞山泉聲，豈識山意春。", "春至換羣物，花開思故人。", "故人今何在，憔悴潁之濱。", "人去山自綠，春歸花更新。", "空令谷中叟，笑我種花勤。"]'),
('9dff4911-fe67-4159-8434-238be7ee1b47','堂中畫像探題得杜子美','歐陽修','宋','宋诗','song-poetry','','[]','風雅久寂寞，吾思見其人。',48,'全唐诗/poet.song.17000.json','["風雅久寂寞，吾思見其人。", "杜君詩之豪，來者孰比倫。", "生爲一身窮，死也萬世珍。", "言苟可垂後，士無羞賤貧。"]'),
('a9df12b1-c433-4f7c-9f57-cf87b9dde4bc','和徐生假山','歐陽修','宋','宋诗','song-poetry','','[]','匠智無遺巧，天形極幽探。',288,'全唐诗/poet.song.17000.json','["匠智無遺巧，天形極幽探。", "謂我愛山者，爲山列前簷。", "頹垣不數尺，萬嶮由心潛。", "或開如斷裂，或吐似谺𧯃。", "或長隨靡迤，或瘦露崆嵌。", "陰穴覷杳杳，高屏立巉巉。", "後出忽孤聳，羣奔沓相參。", "靉若氣融結，突如鬼鎸鑱。", "昔歲貶荆楚，扁舟極東南。", "孤山馬當夾，兩岸臨江潭。", "常恨江水惡，輕風不留帆。", "峯巒千萬狀，可愛不可談。", "但欲借粉繪，圖之掛紈縑。", "豈如几席間，百態生濃纖。", "暮雲點新翠，孤煙起朝嵐。", "況此窮冬節，陰飚積凝嚴。", "幽齋喜深處，遠目生遐瞻。", "晝卧不移枕，晨興自開簾。", "吾聞君子居，出處無常占。", "卷道或獨善，施物仁貴兼。", "於時苟無益，懷祿古所慚。", "嵩山幸不遠，薇蕨豈不甘。", "自可結幽侶，披雲老溪巖。", "胡爲不即往，一室安且恬。"]'),
('23253dd6-17fc-414c-a873-05f5e00c7029','送楊員外','歐陽修','宋','宋诗','song-poetry','','[]','予昔走南宮，江湖浩然涉。',84,'全唐诗/poet.song.17000.json','["予昔走南宮，江湖浩然涉。", "今來厭塵土，常懷把輕楫。", "聞君東南行，山水恣登躡。", "秋江湛已清，樹色映丹葉。", "羨君舟插櫨，去若魚鼓鬣。", "君家兄弟才，門族當世甲。", "行期薦賢書，疾驛來上閤。"]'),
('3ecfade2-0f24-42ff-b012-479bb78ca4f5','讀梅氏詩有感示徐生','歐陽修','宋','宋诗','song-poetry','','[]','子美忽已死，聖俞舍吾南。',180,'全唐诗/poet.song.17000.json','["子美忽已死，聖俞舍吾南。", "嗟吾譬馳車，而失左右驂。", "勍敵嘗壓壘，羸兵當戒嚴。", "凡人貴勉强，惰逸易安恬。", "吾既苦多病，交朋復調殲。", "篇章久不作，意思如膠粘。", "良田失時耕，草莽廢鋤芟。", "美井不日汲，何由發濤甘。", "偶開梅氏篇，不覺日掛簷。", "乃知文字樂，愈久益無厭。", "吾嘗哀世人，聲利競爭貪。", "哇咬聾兩耳，死不享韶咸。", "而幸知此樂，又常深討探。", "今官得閑散，舍此欲奚耽。", "頑庸須警策，賴子發其箝。"]'),
('52607be0-7959-4c9b-8577-94d7e08ee42b','和人三橋  其一','歐陽修','宋','宋诗','song-poetry','','[]','笳鼓下層臺，旌旗轉和嶼。',24,'全唐诗/poet.song.17000.json','["笳鼓下層臺，旌旗轉和嶼。", "橋響騖歸軒，溪明望行炬。"]'),
('2d2c014c-0ebe-402a-b05c-b8556a374095','和人三橋  其二','歐陽修','宋','宋诗','song-poetry','','[]','北臨白雲澗，南望清風閣。',24,'全唐诗/poet.song.17000.json','["北臨白雲澗，南望清風閣。", "出樹見人行，隔溪聞魚躍。"]'),
('1f6c9c79-80fe-446d-9eb2-e2bc886dbb6f','和人三橋  其三','歐陽修','宋','宋诗','song-poetry','','[]','斷虹跨曲岸，倒影涵清波。',24,'全唐诗/poet.song.17000.json','["斷虹跨曲岸，倒影涵清波。", "爲愛斜陽好，迴舟特特過。"]'),
('cde103aa-6eb3-4337-93f8-4cc4d5e60cf0','初夏劉氏竹林小飲','歐陽修','宋','宋诗','song-poetry','','[]','春榮忽已衰，夏葉換初秀。',252,'全唐诗/poet.song.17000.json','["春榮忽已衰，夏葉換初秀。", "披荒得深蹊，掃綠蔭清晝。", "萬竿交已聳，千畝蔚何富。", "驚雷迸狂鞭，霧籜舒文繡。", "虛心高自擢，勁節晚愈瘦。", "雖慚桃李妖，豈愧松柏後。", "川源湛新霽，林麓洗昏霧。", "猗猗色可餐，滴滴翠欲溜。", "況茲夏首月，景物得嘉候。", "晚蝶舞新黄，孤禽弄清咮。", "窺深入窗蒙，玩密愛林茂。", "依依带幽澗，隱隱見孤岫。", "林蓀縟堪眠，野汲泠可漱。", "鳴琴瀉山風，高籟發仙奏。", "暑却自蠲渴，心閑疑愈疚。", "杯盤雜芬芳，圖籍羅左右。", "怡然忘簪組，釋若出羈廄。", "矧予懷一丘，未得解黄綬。", "官事偶多閑，郊扉須屢叩。", "新篁漸添林，晚筍堪薦豆。", "誰邀接䍦公，有酒幸相就。"]'),
('a263a78a-c0bd-48da-8782-dc05445464bb','眼有黑花戲書自遣','歐陽修','宋','宋诗','song-poetry','','[]','洛陽三見牡丹月，春醉往往眠人家。',64,'全唐诗/poet.song.17000.json','["洛陽三見牡丹月，春醉往往眠人家。", "揚州一遇芍藥時，夜飲不覺生朝霞。", "天下名花惟有此，罇前樂事更無加。", "如今白首春風裏，病眼何須厭黑花。"]'),
('12cd27b7-ddf4-409d-9887-b9f85f911da8','送朱生','歐陽修','宋','宋诗','song-poetry','','[]','萬物各有役，無心獨浮雲。',48,'全唐诗/poet.song.17000.json','["萬物各有役，無心獨浮雲。", "遂令幽居客，日與山雲親。", "植桂比芳操，佩蘭思潔身。", "何必濯於水，本無纓上塵。"]'),
('58f6c30a-3c91-4910-ac96-266cc63a861f','雪','歐陽修','宋','宋诗','song-poetry','','[]','新陽力微初破萼，客陰用壯猶相薄。',224,'全唐诗/poet.song.17000.json','["新陽力微初破萼，客陰用壯猶相薄。", "朝寒稜稜風莫犯，暮雪緌緌止還作。", "驅馳風雲初慘淡，炫晃山川漸開廓。", "光芒可愛初日照，潤澤終爲和氣爍。", "美人高堂晨起驚，幽士虛窗靜聞落。", "酒壚成徑集缾罌，獵騎尋蹤得狐貉。", "龍蛇掃處斷復續，猊虎團成呀且攫。", "共貪終歲飽麰麥，豈恤空林饑鳥雀。", "沙墀朝賀迷象笏，桑野行歌沒芒屩。", "乃知一雪萬人喜，顧我不飲胡爲樂。", "坐看天地絕氛埃，使我胸襟如洗瀹。", "脫遺前言笑塵雜，搜索萬象窺冥漠。", "潁雖陋邦文士眾，巨筆人人把矛槊。", "自非我爲發其端，凍口何由開一噱。"]'),
('b94b0bcf-25a3-4e64-99e0-347613947332','雪晴','歐陽修','宋','宋诗','song-poetry','','[]','悠悠野水來，灧灧西溪闊。',72,'全唐诗/poet.song.17000.json','["悠悠野水來，灧灧西溪闊。", "曉日披宿雲，荒臺照殘雪。", "風光變窮臘，歲律新陽月。", "凍卉意初回，綠醅浮可撥。", "人閑樂朋友，鳥哢知時節。", "豈止探芳菲，耕桑行可閱。"]'),
('06aae93e-f13e-4cfa-84d1-2e5d54f3107a','琴高魚','歐陽修','宋','宋诗','song-poetry','','[]','琴高一去不復見，神仙雖有亦何爲。',32,'全唐诗/poet.song.17000.json','["琴高一去不復見，神仙雖有亦何爲。", "溪鱗佳味自可愛，何必虛名務好奇。"]'),
('651e6a09-edf8-4fca-ad42-6cf618d6399c','竹間亭','歐陽修','宋','宋诗','song-poetry','','[]','高亭照初日，竹影凉蕭森。',84,'全唐诗/poet.song.17000.json','["高亭照初日，竹影凉蕭森。", "新篁漸解籜，翠色日已深。", "雨多苔莓青，幽徑無人尋。", "靜趣久迺得，暫來聊解襟。", "清風颯然生，鳴鳥送好音。", "佳時不易得，濁酒聊自斟。", "興盡即言返，生來期抱琴。"]'),
('f59991d6-628c-4954-aea5-253e2465d1f1','箕山','歐陽修','宋','宋诗','song-poetry','','[]','朝下黄蘆坂，夕望箕山雲。',72,'全唐诗/poet.song.17000.json','["朝下黄蘆坂，夕望箕山雲。", "緬懷巢上客，想彼巖中人。", "弱歲慕高節，壯年嬰世紛。", "漱流羨潁水，振衣嗟洛塵。", "空祠亂驚鳥，山木含餘曛。", "聊茲謝芝桂，歸月及新春。"]'),
('29121924-d5ae-405a-8707-2137ab3667f1','西園','歐陽修','宋','宋诗','song-poetry','','[]','落日叩溪門，西溪復何所。',48,'全唐诗/poet.song.17000.json','["落日叩溪門，西溪復何所。", "人侵樹裏耕，花落田中雨。", "平野見南山，荒臺起寒霧。", "歌舞昔云誰，今人但懷古。"]'),
('a4f8dfab-0340-4898-b46f-588d3827e88d','白兔','歐陽修','宋','宋诗','song-poetry','','[]','天冥冥，雲濛濛，白兔擣藥姮娥宮。',172,'全唐诗/poet.song.17000.json','["天冥冥，雲濛濛，白兔擣藥姮娥宮。", "玉關金鎖夜不閉，竄入滁山千萬重。", "滁泉清甘瀉大壑，滁草軟翠摇輕風。", "渴飲泉，困棲草，滁人遇之豐山道。", "網羅百計偶得之，千里持爲翰林寶。", "翰林酬酢委金璧，珠箔花籠玉爲食。", "朝隨孔翠伴，暮綴鸞皇翼。", "主人邀客醉籠下，凉洛風埃不霑席。", "羣詩名貌極豪縱，爾兔有意果誰識。", "天資潔白已爲累，物性拘囚盡無益。", "上林榮落幾時休，回首峯巒斷消息。"]'),
('0396f921-e84c-44a4-ad6b-aba4c14718ae','偶書','歐陽修','宋','宋诗','song-poetry','','[]','吾見陶靖節，愛酒又愛閑。',132,'全唐诗/poet.song.17000.json','["吾見陶靖節，愛酒又愛閑。", "二者人所欲，不問愚與賢。", "柰何古今人，遂此樂尤難。", "飲酒或時有，得閑何鮮焉。", "浮屠老子流，營營盈市廛。", "二物尚如比，仕宦不待言。", "官高責愈重，祿厚足憂患。", "暫息不可得，況欲閑長年。", "少壯務貪得，銳意力爭前。", "老來難勉强，思此但長歎。", "决計不宜晚，歸耕潁尾田。"]'),
('1d4ed765-748a-4ced-8120-2db161427911','日本刀歌','歐陽修','宋','宋诗','song-poetry','','[]','昆夷道遠不復通，世傳切玉誰能窮。',192,'全唐诗/poet.song.17000.json','["昆夷道遠不復通，世傳切玉誰能窮。", "寶刀近出日本國，越賈得之滄海東。", "魚皮裝貼香木鞘，黄白閑雜鍮與銅。", "百金傳入好事手，佩服可以禳妖兇。", "傳聞其國居大島，土壤沃饒風俗好。", "其先徐福詐秦民，採藥淹留丱童老。", "百工五種與之居，至今器玩皆精巧。", "前朝貢獻屢往來，士人往往工詞藻。", "徐福行時書未焚，逸書百篇今尚存。", "令嚴不許傳中國，舉世無人識古文。", "先王大典藏夷貊，蒼波浩蕩無通津。", "令人感激坐流涕，鏽澁短刀何足云。"]'),
('7deebcba-5860-4158-8ad1-0744b14e6e30','會峰亭','歐陽修','宋','宋诗','song-poetry','','[]','山勢百里見，新亭壓其巔。',108,'全唐诗/poet.song.17000.json','["山勢百里見，新亭壓其巔。", "羣峯漸靡迤，高下相綿聯。", "下窺疑無地，杳藹但蒼煙。", "是時新雨餘，眾壑鳴春泉。", "林籟靜更響，山光晚逾鮮。", "巖花爲誰開，春去夏猶妍。", "野鳥窺我醉，谿雲留我眠。", "日暮山風來，吹我還醒然。", "醉醒各任物，雲鳥徒留連。"]'),
('ce423f2c-2be0-4db7-a1ba-d1f439da6fc1','晚步綠陰園遂登凝翠亭','歐陽修','宋','宋诗','song-poetry','','[]','餘春去已遠，綠水涵新塘。',72,'全唐诗/poet.song.17000.json','["餘春去已遠，綠水涵新塘。", "漸愛樹陰密，初迎蕙風凉。", "高亭可四望，繞郭青山長。", "野色晚更好，嵐曛共微茫。", "幽懷不可寫，雅詠同誰觴。", "明月如慰我，開軒送清光。"]'),
('c186e9ed-316e-48a7-a175-2194e4454b24','聖俞惠宣州筆戲書','歐陽修','宋','宋诗','song-poetry','','[]','聖俞宣城人，能使紫毫筆。',120,'全唐诗/poet.song.17000.json','["聖俞宣城人，能使紫毫筆。", "宣人諸葛高，世業守不失。", "緊心縛長毫，三副頗精密。", "硬軟適人手，百管不差一。", "京師諸筆工，牌榜自稱述。", "纍纍相國東，比若衣縫蝨。", "或柔多虛尖，或硬不可屈。", "但能裝管榻，有表曾無實。", "價高仍費錢，用不過數日。", "豈如宣城毫，耐久仍可乞。"]'),
('14e434c8-4e0f-45fa-8d66-ea64de2ccaa7','贈潘景溫叟','歐陽修','宋','宋诗','song-poetry','','[]','秦盧不世出，俗子相矜誇。',156,'全唐诗/poet.song.17000.json','["秦盧不世出，俗子相矜誇。", "治疾不知源，橫死紛如麻。", "番陽奇男子，衣冠本儒家。", "學本得心訣，照底窮根厓。", "泠然鑒五藏，曾靡毫釐差。", "公卿掃榻迎，黄金載盈車。", "語言無羽翰，飛入萬齒牙。", "相逢京洛下，使我驚且嗟。", "七年慈母病，庸工口咿啞。", "恨不早見君，以乞壺中砂。", "通宵耳高論，飲恨知何涯。", "瞥然別我去，征途指煙霞。", "孤雲不可留，淚線風中斜。"]'),
('83ee4c19-ea1f-4451-aee0-17600ffe9660','學書二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','蘇子歸黄泉，筆法遂中絕。',60,'全唐诗/poet.song.17000.json','["蘇子歸黄泉，筆法遂中絕。", "賴有蔡君謨，名聲馳晚節。", "醉翁不量力，每欲追其轍。", "人生浪自苦，以取兒女悅。", "豈止學書然，自悔從今决。"]'),
('2cb84cbe-3ba4-4c91-b965-1e2a74202013','學書二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','學書不覺夜，但怪西窗暗。',60,'全唐诗/poet.song.17000.json','["學書不覺夜，但怪西窗暗。", "病目故已昏，墨不分濃淡。", "人生不自知，勞苦殊無憾。", "所得乃虛名，榮華俄頃暫。", "豈止學書然，作銘聊自鑒。"]'),
('cf00a1f7-5382-45e6-a0e5-45aa65dbc1cf','奉使道中作三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','執手意遲遲，出門還草草。',56,'全唐诗/poet.song.17000.json','["執手意遲遲，出門還草草。", "無嫌去時速，但願歸時早。", "北風吹雪犯片裘，夾路花開回馬頭。", "若無二月還家樂，爭奈千山遠客愁。"]'),
('ced707fb-b39d-45ea-aefd-9ee37b1f0f61','奉使道中作三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','爲客莫思家，客行方遠道。',56,'全唐诗/poet.song.17000.json','["爲客莫思家，客行方遠道。", "還家自有時，空使朱顔老。", "禁城春色暖融怡，花倚春風待客歸。", "勸君還家須飲酒，記取思歸未得時。"]'),
('5edc49b0-d5bb-45f6-b0d1-b1db8e6c4445','奉使道中作三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','客夢方在家，角聲已催曉。',56,'全唐诗/poet.song.17000.json','["客夢方在家，角聲已催曉。", "怱怱行人起，共怨角聲早。", "馬蹄終日踐水霜，未到思回空斷腸。", "少貪夢裏還家樂，早起前山路正長。"]'),
('25699d90-59d4-4433-adc5-986a7bb9859a','奉使道中寄坦師','歐陽修','宋','宋诗','song-poetry','','[]','道人少賈海上遊，海舶破散身沉浮。',160,'全唐诗/poet.song.17000.json','["道人少賈海上遊，海舶破散身沉浮。", "黄金滿篋人所寄，吹簸偶得還中州。", "臝身歸金不受報，祗取斗酒相獻酬。", "歡娛慈母終一世，脫棄妻子藏巖幽。", "蒼煙寥寥池水漫，白玉菡萏吹高秋。", "夜燃栢子煮山藥，憶此東望無時休。", "塞垣春枯積雪溜，沙礫威怒黄雲愁。", "五更匹馬隨鴈起，想見鄮郭花今稠。", "百年夸奪終一丘，世上滿眼真悠悠。", "寄聲萬里心綢繆，莫道異趣無相求。"]'),
('03b6c48e-a905-46fd-9496-f010063f484e','勉劉甲','歐陽修','宋','宋诗','song-poetry','','[]','有司精考覈，中第爲公卿。',48,'全唐诗/poet.song.17000.json','["有司精考覈，中第爲公卿。", "本基在積習，優學登榮名。", "吾子齒尚少，加勤無自輕。", "努力圖樹立，庶幾終有成。"]'),
('b08735a7-cc22-4c0c-b446-30e770685c19','壽樓','歐陽修','宋','宋诗','song-poetry','','[]','碧瓦照日生青煙，誰家高樓當道邊。',140,'全唐诗/poet.song.17000.json','["碧瓦照日生青煙，誰家高樓當道邊。", "昨日丁丁斤且斲，今朝朱欄橫翠幕。", "主人起樓何太高，欲誇富力壓羣豪。", "樓中女兒十五六，紅膏畫眉雙鬢綠。", "日暮春風吹管弦，過者仰首皆留連。", "應笑樓前騎馬客，腰垂金章頭已白。", "苦貪名利損形骸，爭若庸愚恣聲色。", "朝見騎馬過，暮見騎馬歸。", "經年無補朝廷事，何用區區來往爲。"]'),
('c0ab3341-270d-447f-8c9c-37872eba00e8','試院聞奚琴作','歐陽修','宋','宋诗','song-poetry','','[]','奚琴本出奚人樂，奚虜彈之雙淚落。',128,'全唐诗/poet.song.17000.json','["奚琴本出奚人樂，奚虜彈之雙淚落。", "抱琴置酒試一彈，曲罷依然不能作。", "黄河之水向東流，鳧飛鴈下白雲秋。", "岸上行人舟上客，朝來暮去無今昔。", "哀絃一奏池上風，忽聞如在河舟中。", "絃聲千古聽不改，可憐纖手今何在。", "誰知著意弄新音，斷我罇前今日心。", "當時應有曾聞者，若使重聽須淚下。"]'),
('fbc033cd-f910-4107-9bfb-21511ac8fa0f','乞藥有感呈梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','宣州紫沙合，圓若截郫筒。',217,'全唐诗/poet.song.17000.json','["宣州紫沙合，圓若截郫筒。", "偶得今十載，走宦南北東。", "持之聖俞前，乞藥戒羸僮。", "聖俞見之喜，遽以手磨礱。", "謂此吾家物，問誰持贈公。", "因嗟與君交，事事無不同。", "憶昔初識面，青衫游洛中。", "高標不可揖，杳若雲間鴻。", "不獨體輕健，目明仍耳聰。", "爾來三十年，多難面憂攻。", "君晚得奇藥，靈根斸離宮。", "其狀若狗蹄，其香比芎藭。", "愛君方食貧，面色悅以豐。", "不憚乞餘劑，庶幾助衰衰癃。", "平時一笑歡，飲酒各爭雄。", "向老面病出，區區論藥功。", "衰盛物常理，循環勢無窮。", "寄語少年兒，慎勿笑兩翁。"]'),
('c7d59521-fcc1-4d24-a132-8a2857f1f325','擬剝啄行寄趙少師','歐陽修','宋','宋诗','song-poetry','','[]','剝剝復啄啄，柴門驚鳥雀。',104,'全唐诗/poet.song.17000.json','["剝剝復啄啄，柴門驚鳥雀。", "故人千里駕，信士百金諾。", "搢紳相趨動顔色，閭巷歡呼共嗟愕。", "顧我非惟慰寂寥，於時自可警偷薄。", "事國十年憂患同，酣歌幾日暫相從。", "酒醒初不戒徒馭，歸思瞥起如飛鴻。", "車馬閴然人已去，荷鋤去向野田中。"]'),
('fa0e39bf-d0ad-40fb-9b8e-2e81eb776caf','絕句','歐陽修','宋','宋诗','song-poetry','','[]','冷雨漲焦陂，人去陂寂寞。',24,'全唐诗/poet.song.17000.json','["冷雨漲焦陂，人去陂寂寞。", "惟有霜前花，鮮鮮對高閣。"]'),
('d5fd137b-5158-43f0-abba-80953f40dde1','冬夕小齋聯句寄梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','寒窗明夜月，散帙耿燈火。',120,'全唐诗/poet.song.17000.json','["寒窗明夜月，散帙耿燈火。", "破硯裂冰澌，敗席薦霜笴。", "廢書浩長吟，想子實勞我。", "清篇追曹劉，苦語侔島可。", "酣飲每頹山，談笑工炙輠。", "駕言當有期，歲晚何未果。", "幽夢亂如雲，別愁牢若鎖。", "雪水漸漣漪，春枝將婀娜。", "客心莫遲留，苑葩即紛墮。", "何當迎笑前，相逢嘲飯顆。"]'),
('a3754266-c65d-4ed4-b7f3-d80ae4fbd5ff','劍聯句','歐陽修','宋','宋诗','song-poetry','','[]','聖人作神兵，以定天下厄。',288,'全唐诗/poet.song.17000.json','["聖人作神兵，以定天下厄。", "蚩尤發靈機，干將構雄績。", "橐籥天地開，鑪冶陰陽闢。", "南帝輸火精，西皇降金液。", "炎炎崑岡熒，洶洶洪河擘。", "雷霆助意氣，日月淪精魄。", "神氣不在大，錯落就三尺。", "直淬靈溪泉，橫磨太行石。", "雄雌威並立，晝夜光相射。", "提携風雲生，指顧煙霞寂。", "堅剛正人心，耿介志士跡。", "初疑成夏鼎，魑魅世所適。", "又若引吳刀，犀象謂無隔。", "截波虬尾滑，脫浪鯨牙直。", "頑冰挂陰霤，皎月乘孤隙。", "河角起彗氣，雲罇露秋碧。", "曉鐔星斗爛，夜匣飛龍宅。", "舞酣霰雪回，彈俊球琳擊。", "鮮摇霅水光，膩刮湘山色。", "青蛟渴雨瘦，素虺蟠霜瘠。", "清音鏘以鳴，寒姿堅且澤。", "鬼類喪影響，佞黨摧肝膈。", "一旦會神武，四海屠兇逆。", "周王奉天討，商郊千里赤。"]'),
('096f4126-f1a9-4451-8f40-88bb33d27cb9','鶴聯句','歐陽修','宋','宋诗','song-poetry','','[]','上霄降靈氣，鍾此千年禽。',289,'全唐诗/poet.song.17000.json','["上霄降靈氣，鍾此千年禽。", "幽閑靖節性，孤高伯夷心。", "頡頏紫霄垠，飄颻滄浪潯。", "岳湛有仙姿，鈞韶無俗音。", "毛滋月華淡，頂粹霞光深。", "目流泉客淚，翅垂羽人襟。", "騰漢雪千丈，點溪霜半尋。", "纖喙礪青鐵，脩脛雕碧琳。", "巖棲干溪樹，澤飲卑朱泠。", "鸞皇自塤箎，燕雀徒商參。", "獨翅聳瓊枝，羣舞傾瑶林。", "病餘霞雲段，夢回松吹吟。", "靜嫌鸚鵡言，高笑鴛鴦淫。", "金清泠澄澈，玉玉格寒蕭森。", "潔白不我恃，腥羶非所任。", "稻粱不得已，蟣虱胡爲侵。", "天池憶鵬遊，雲羅傷鳳沈。", "風流超縞素，雅淡絕規箴。", "相親長道情，偶見鎖煩襟。", "西漢惜馮唐，華皓欲投簪。", "南朝仰衛玠，清羸疑不禁。", "端如方直臣，處羣良足欽。", "介如廉退士，驚秋猶在陰。", "幾誚鷹隼鷙，覊韝俄見臨。"]'),
('18e7654f-a0ec-4414-8064-63376d356e38','來燕堂與趙叔平王禹玉王原叔韓子華聯句','歐陽修','宋','宋诗','song-poetry','','[]','賢侯謝郡歸，從游樂吾黨。',240,'全唐诗/poet.song.17000.json','["賢侯謝郡歸，從游樂吾黨。", "林泉富餘地，卜筑疏陳莽。", "是時春正中，來燕音下上。", "若賀大厦成，喜留眾賓賞。", "得名因談笑，揮墨粲題榜。", "所夸賢豪盛，豈止池謝廣。", "人心樂且閑，鳥意頡而頏。", "吟罇敞花軒，酬枕酣風幌。", "輕雲薄藻棟，初日麗珠網。", "紅袂生暗香，清絃泛餘響。", "林深隱飛蓋，岸曲遲去槳。", "波光欄檻明，竹飛衣巾爽。", "虛容凉樾入，景與文漣蕩。", "晨飚轉綠蕙，夕雨滋膏壤。", "嘉辰嘉盍朋，命駕期屢往。", "觴詠陶淑真，世俗豈吾倣。", "得以爲勝游，蕭然散煩想。", "公子固好士，世德復可象。", "今此大基構，不圖專奉養。", "美哉風流存，來葉足師仰。"]'),
('d8d0a353-0c51-4e9b-bcae-05f1e5e432f3','漢宮','歐陽修','宋','宋诗','song-poetry','','[]','桂館神君去，甘泉輦道平。',72,'全唐诗/poet.song.17000.json','["桂館神君去，甘泉輦道平。", "翠華飛蓋下，豹尾屬車迎。", "曉露寒浮掌，光風細轉旌。", "廓回偏費步，珮遠尚聞聲。", "玉樹人間老，珊瑚海底生。", "金波夜夜意，偏照影娥清。"]'),
('1a8078f6-20f4-4aa2-86ff-ed111ee997f9','送劉半千平陽簿','歐陽修','宋','宋诗','song-poetry','','[]','嶺梅歸驛路迢迢，越鳥巢傾木半喬。',64,'全唐诗/poet.song.17000.json','["嶺梅歸驛路迢迢，越鳥巢傾木半喬。", "松徑就荒聊應召，桂叢留隱定相招。", "家庭噪鵲爭喧樹，夜帳驚猿自擁條。", "何處秋風摧客鬢，青絲恐逐物華凋。"]'),
('969e718c-5a1a-4993-90cf-e91fafff34bd','樓頭','歐陽修','宋','宋诗','song-poetry','','[]','百尺樓頭萬疊山，楚江南望隔晴煙。',64,'全唐诗/poet.song.17000.json','["百尺樓頭萬疊山，楚江南望隔晴煙。", "雲藏白道天垂幕，簾捲黄昏月上弦。", "桑落蒲城催熟酒，柳衰章陌感凋年。", "髮光如葆寧禁恨，不待爲郎已颯然。"]'),
('1873d3a0-b42f-49a3-ad03-1015fb6233f7','夕照','歐陽修','宋','宋诗','song-poetry','','[]','夕照留歌扇，餘輝上桂叢。',48,'全唐诗/poet.song.17000.json','["夕照留歌扇，餘輝上桂叢。", "霞光晴散錦，雨氣晚成虹。", "燕下翻池草，烏驚傍井桐。", "無憀照湘水，丹色映秋風。"]'),
('ad069c2f-145a-4da1-af00-b04b47586929','送張學士知郢州','歐陽修','宋','宋诗','song-poetry','','[]','漢郎清曉赤墀趨，楚老西來望集旟。',64,'全唐诗/poet.song.17000.json','["漢郎清曉赤墀趨，楚老西來望集旟。", "侍史護衣薰蕙草，轆轤要劔從驪駒。", "陽春繞雪歌低扇，油幕連運水泛渠。", "千里脩門對涔浦，好尋遺玦弔三閭。"]'),
('6eb4a407-54a1-4026-aead-4d991e920ae6','曉詠','歐陽修','宋','宋诗','song-poetry','','[]','簾外星辰逐斗移，紫河聲轉下雲西。',64,'全唐诗/poet.song.17000.json','["簾外星辰逐斗移，紫河聲轉下雲西。", "九雛烏起城將曙，百尺樓高月易低。", "露裛蘭苕惟有淚，秋荒桃李不成蹊。", "西堂吟思無人助，草滿池塘夢自迷。"]'),
('de79e3c2-ad03-44ee-be86-9e4b0bab70ce','禁火','歐陽修','宋','宋诗','song-poetry','','[]','火禁開何晚，春芳半已凋。',48,'全唐诗/poet.song.17000.json','["火禁開何晚，春芳半已凋。", "柳風兼絮墜，榆雨带錢飄。", "淚翦蘭膏盡，弦虧桂魄消。", "祓蘭流水曲，游禊一相招。"]'),
('f3dae6c8-6415-47b4-99d2-30f5c73bfae7','送趙山人歸舊山','歐陽修','宋','宋诗','song-poetry','','[]','屈賈江山思不休，霜飛翠葆忽驚秋。',64,'全唐诗/poet.song.17000.json','["屈賈江山思不休，霜飛翠葆忽驚秋。", "吟拋楚畹蘭苕老，歸有淮山桂樹留。", "聒耳春池蛙兩部，比封秋塢橘千頭。", "嗔條怒穎真堪愧，莫染衣塵更遠遊。"]'),
('46be2265-ebe7-4ba6-86d5-6772f1a777f9','閑居即事','歐陽修','宋','宋诗','song-poetry','','[]','巷有容車陋，門無載酒過。',48,'全唐诗/poet.song.17000.json','["巷有容車陋，門無載酒過。", "池喧蛙怒雨，客去雀驚羅。", "握臂如枝骨，哀絃繫筯歌。", "無憀漳浦卧，還似詠中阿。"]'),
('5aa49f07-2647-4247-b001-f5e962267204','傷春','歐陽修','宋','宋诗','song-poetry','','[]','蕙蘭蹊徑失芳期，風雨春深怯減衣。',64,'全唐诗/poet.song.17000.json','["蕙蘭蹊徑失芳期，風雨春深怯減衣。", "卷箔高樓驚燕入，揮絃遠目送鴻歸。", "蜂催釀蜜愁花盡，絮撲暄條妬雪飛。", "欲識傷春多少恨，試量衣带忖要圍。"]'),
('defb4323-9d51-466c-bc0d-00c6546ae4f5','公子','歐陽修','宋','宋诗','song-poetry','','[]','黄山開苑獵初回，絳樹分行舞遞來。',64,'全唐诗/poet.song.17000.json','["黄山開苑獵初回，絳樹分行舞遞來。", "下馬春場雞鬭距，鳴弦初日雉驚媒。", "犀投博齒呼成白，橋隔車音聽似雷。", "不問春蠶眠未起，更尋桑陌到秦臺。"]'),
('282cae2f-89ad-41e4-86ca-21380c8fb192','夜意','歐陽修','宋','宋诗','song-poetry','','[]','蕙炷爐薰斷，蘭膏燭艷煎。',48,'全唐诗/poet.song.17000.json','["蕙炷爐薰斷，蘭膏燭艷煎。", "夜風多起籟，曉月漸虧弦。", "鵲去星低漢，烏啼樹暝煙。", "惟應牆外柳，三起復三眠。"]'),
('805f7737-4669-4d91-9a2a-172b246dffdd','寄張至祕校','歐陽修','宋','宋诗','song-poetry','','[]','關山一里一重愁，今遠傷離兩未休。',64,'全唐诗/poet.song.17000.json','["關山一里一重愁，今遠傷離兩未休。", "南陌望窮雲似帳，西樓吟斷月如鈎。", "柳綿飛後春應減，蘭徑荒時客倦游。", "擬寄東流問溝水，亦應溝水更東流。"]'),
('65699e76-c822-497a-a42e-9763f7951697','寄徐巽秀才','歐陽修','宋','宋诗','song-poetry','','[]','瑶花飛雪蕩離愁，鷤鴂驚風下綠疇。',64,'全唐诗/poet.song.17000.json','["瑶花飛雪蕩離愁，鷤鴂驚風下綠疇。", "睢兇樹荒誰共客，楚江楓老獨悲秋。", "千里錦浪翻如箭，萬疊春山翠入樓。", "章陌柳條今在否，定臨溝水拂東流。"]'),
('c811cd2b-b8e8-487f-843c-f0736a2ff174','寄劉昉秀才','歐陽修','宋','宋诗','song-poetry','','[]','絲路縈回細入雲，離懷南陌草初薰。',64,'全唐诗/poet.song.17000.json','["絲路縈回細入雲，離懷南陌草初薰。", "茂林脩竹誰同禊，明月春蘿定勒文。", "燕憶銅鞮來不定，鴻歸碣石信難分。", "東風鸎友應相望，懊惱孤飛不及羣。"]'),
('b204ec41-1235-4ea2-a952-5fb68d3d99b8','送客回馬上作','歐陽修','宋','宋诗','song-poetry','','[]','南浦空波綠，西陂夕照寒。',48,'全唐诗/poet.song.17000.json','["南浦空波綠，西陂夕照寒。", "瑶華傷遠道，芳草送歸鞍。", "翠歛遥山疊，氛收古澤寬。", "衰容畏秋色，不及楚楓丹。"]'),
('59701fde-d644-467b-acce-bd92045f6a23','西征道中送陳舅秀才北歸','歐陽修','宋','宋诗','song-poetry','','[]','棊墅風流謝舅賢，髮光如葆惜窮年。',64,'全唐诗/poet.song.17000.json','["棊墅風流謝舅賢，髮光如葆惜窮年。", "人隨黄鵠飛千里，酒滿棲烏送一絃。", "望驛早梅迎遠使，拂鞍衰柳拗歸鞭。", "越禽胡馬相逢地，南北思歸各黯然。"]'),
('42eac13a-3c3f-47d1-ba56-a71e9ff52c77','送目','歐陽修','宋','宋诗','song-poetry','','[]','送目衡皋望不休，江蘋高下遍汀洲。',64,'全唐诗/poet.song.17000.json','["送目衡皋望不休，江蘋高下遍汀洲。", "長堤柳曲妨回首，小苑花深礙倚樓。", "楚徑蕙風消病渴，洛城花雪蕩春愁。", "流杯三日佳期過，擲度蘭波負勝遊。"]'),
('4d053d69-5079-46d7-8036-e803da92ed47','春曉','歐陽修','宋','宋诗','song-poetry','','[]','小閤回殘夢，開簾轉曉暉。',48,'全唐诗/poet.song.17000.json','["小閤回殘夢，開簾轉曉暉。", "露寒風不定，花落鳥驚飛。", "病渴偏思柘，朝寒怯減衣。", "沈錢將謝雪，持底送春歸。"]'),
('b8f993b6-4fa0-46eb-b945-922131df8e3c','劉秀才宅對弈','歐陽修','宋','宋诗','song-poetry','','[]','烏巷招邀謝墅中，紫囊香珮更臨風。',64,'全唐诗/poet.song.17000.json','["烏巷招邀謝墅中，紫囊香珮更臨風。", "塵驚野火遥知獵，目送雲羅但聽鴻。", "六著比犀鳴博勝，百嬌柘矢捧壺空。", "解衣對子歡何極，玉井移陰下翠桐。"]'),
('91c80c8f-e8b2-4b56-b798-0511365fc4df','送李寔','歐陽修','宋','宋诗','song-poetry','','[]','幾幅歸帆不暫停，吳天遥望斗牛橫。',64,'全唐诗/poet.song.17000.json','["幾幅歸帆不暫停，吳天遥望斗牛橫。", "香薰翠被乘青翰，波暖屏風詠紫莖。", "江水自隨潮上下，月輪閑與蚌虧盈。", "河橋折柳傷離後，更作南雲萬里行。"]'),
('209b7e03-bb69-4c70-afef-586f8be9b2c2','早夏鄭工部園池','歐陽修','宋','宋诗','song-poetry','','[]','夜雨殘芳盡，朝暉宿霧收。',48,'全唐诗/poet.song.17000.json','["夜雨殘芳盡，朝暉宿霧收。", "蘭香纔馥徑，柳暗欲翻溝。", "夏木繁堪結，春蹊翠已稠。", "披襟楚風快，伏檻更臨流。"]'),
('daa69539-0c5d-492b-849c-5ef737bd20ad','舟中寄劉昉秀才','歐陽修','宋','宋诗','song-poetry','','[]','東南天闊漾歸流，西北雲高斷寸眸。',64,'全唐诗/poet.song.17000.json','["東南天闊漾歸流，西北雲高斷寸眸。", "明日隨人來遠浦，青山答鼓送行舟。", "歸心逐夢成魚鳥，夜漢看星識斗牛。", "釅酒開樽誰共醉，清江聊且玩游鯈。"]'),
('09665432-8569-4d74-9e70-040de444d155','月夕','歐陽修','宋','宋诗','song-poetry','','[]','月氣初升海，屏光半隱扉。',48,'全唐诗/poet.song.17000.json','["月氣初升海，屏光半隱扉。", "寒消覺春盡，漏永送籌稀。", "蘭燭風驚燼，煙簾霧濕衣。", "清羸急寬带，頻減故時圍。"]'),
('3a170055-88e3-4b73-999a-8ff84fad6d2b','奉送叔父都官知永州','歐陽修','宋','宋诗','song-poetry','','[]','虎頭盤綬貴垂紳，青組名郎領郡頻。',64,'全唐诗/poet.song.17000.json','["虎頭盤綬貴垂紳，青組名郎領郡頻。", "畫鷁千艘隨下瀨，聽雞五鼓送行人。", "楚波漾楫萍如日，淮月開舲蚌有津。", "千里壺漿民詠溢，檣烏旟隼下汀蘋。"]'),
('5e71c03d-73ca-43ce-8b23-0b6ca1ec9764','柳','歐陽修','宋','宋诗','song-poetry','','[]','綠樹低昂不自持，河橋風雨弄春絲。',64,'全唐诗/poet.song.17000.json','["綠樹低昂不自持，河橋風雨弄春絲。", "殘黄淺約眉雙歛，欲舞先誇手小垂。", "快馬折鞭催遠道，落梅橫笛共餘悲。", "長亭送客兼迎雨，費盡春條贈別離。"]'),
('30fb561c-334e-4171-a6bc-8f92fc0dee9f','舟中望京色','歐陽修','宋','宋诗','song-poetry','','[]','東北歸川决决流，汎艎青渚暫夷猶。',64,'全唐诗/poet.song.17000.json','["東北歸川决决流，汎艎青渚暫夷猶。", "遥登灞岸空回首，不見長安但舉頭。", "揮手嵇琴空墮睫，開樽魯酒不忘憂。", "青門柳色春應遍，猶自留連杜若洲。"]'),
('25d18cbc-bc47-44f3-8ab6-8c7b37f60f93','小圃','歐陽修','宋','宋诗','song-poetry','','[]','桂樹鴛鴦起，蘭苕翡翠翔。',48,'全唐诗/poet.song.17000.json','["桂樹鴛鴦起，蘭苕翡翠翔。", "風高絲引絮，雨罷葉生光。", "蝶粉花霑紫，蜂茸露濕黄。", "愁酲與消渴，容易爲春傷。"]'),
('ba31898e-2e92-413a-9e3d-13e1d1c2f7da','即目','歐陽修','宋','宋诗','song-poetry','','[]','李徑陰森接翠疇，押簾風日澹清秋。',64,'全唐诗/poet.song.17000.json','["李徑陰森接翠疇，押簾風日澹清秋。", "晚烏藏柳棲殘照，遠燕傷風失故樓。", "星漢經年雖可望，雲波千疊不緘愁。", "平居革带頻移孔，誰問無憀沈隱侯。"]'),
('10aad425-aee3-41d4-b1c4-2df4c3115257','南征道寄相送者','歐陽修','宋','宋诗','song-poetry','','[]','楚天風雪犯征裘，誤拂京塵事遠遊。',64,'全唐诗/poet.song.17000.json','["楚天風雪犯征裘，誤拂京塵事遠遊。", "謝墅人歸應作詠，灞陵岸遠尚回頭。", "雲含江樹看迷所，目逐歸鴻送不休。", "欲借高樓望西北，亦應西北有高樓。"]'),
('351b7fc5-0400-43cd-91c9-0ca88b65126e','楚澤','歐陽修','宋','宋诗','song-poetry','','[]','宿莽湘纍怨，幽蘭楚俗謠。',72,'全唐诗/poet.song.17000.json','["宿莽湘纍怨，幽蘭楚俗謠。", "紫屏空自老，翠被豈能招。", "欲就蒼梧訴，愁迷灃浦遥。", "哀猿羌晝晦，悲鴂眾芳凋。", "紅壁丹砂板，瓊鈎翡翠翹。", "如何搴香杜，江上獨無憀。"]'),
('862c9d1a-f23a-49ba-ac49-beaa0858d2af','題金山寺','歐陽修','宋','宋诗','song-poetry','','[]','地接龍宮漲浪賒，鷲峯岑絕倚雲斜。',64,'全唐诗/poet.song.17000.json','["地接龍宮漲浪賒，鷲峯岑絕倚雲斜。", "巖披宿霧三竿日，路引迷人四照花。", "海國盜牙爭起塔，河童施鉢但驚沙。", "春蘿攀倚難成去，山谷踈鍾落暮霞。"]'),
('1229bad3-a42d-4765-bd51-e0a461b5d5bc','送竇秀才','歐陽修','宋','宋诗','song-poetry','','[]','晴原高下細如鱗，樹轉城回路欲分。',64,'全唐诗/poet.song.17000.json','["晴原高下細如鱗，樹轉城回路欲分。", "望月西樓人共遠，躍鞍南陌草初薰。", "短亭山翠偏多疊，送目鴻驚不及羣。", "一驛賦成應援筆，好憑飛翼寄歸雲。"]'),
('ea42fb4e-1389-4d7e-83e1-2aa3318adffb','旅思','歐陽修','宋','宋诗','song-poetry','','[]','調苦歌非樂，岐多淚始零。',48,'全唐诗/poet.song.17000.json','["調苦歌非樂，岐多淚始零。", "羞彈長鋏劔，終戀五侯鯖。", "陌草薰沙綠，江楓照岸青。", "南陔動歸思，蘭葉向春馨。"]'),
('cd332db3-db76-4331-b44d-1202ed12146e','仙意','歐陽修','宋','宋诗','song-poetry','','[]','孤桐百尺拂非煙，鳳去鸞歸夜悄然。',64,'全唐诗/poet.song.17000.json','["孤桐百尺拂非煙，鳳去鸞歸夜悄然。", "滄海風高愁燕遠，扶桑春老記蠶眠。", "槎流千里纔成曲，桂魄經旬始下弦。", "獨有金人寄遺恨，曉盤雲淚冷涓涓。"]'),
('7f631c75-b9d3-43aa-9ab2-26429a675f65','聞朱祠部罷潯州歸闕','歐陽修','宋','宋诗','song-poetry','','[]','漢柱題名墨未乾，南州坐布政條寬。',64,'全唐诗/poet.song.17000.json','["漢柱題名墨未乾，南州坐布政條寬。", "嶺雲路隔梅欹驛，使驛秋歸柳拂鞍。", "建禮侵晨趨冉冉，明光賜對佩珊珊。", "潁川此召行聞拜，冠頍凝塵俟一彈。"]'),
('2d28778e-47ac-4d44-82f7-b8958e6aa767','倦征','歐陽修','宋','宋诗','song-poetry','','[]','沈約傷春思，嵇含倦久游。',48,'全唐诗/poet.song.17000.json','["沈約傷春思，嵇含倦久游。", "帆歸黄鶴浦，人滯白蘋洲。", "乳燕差池遠，江禽格磔浮。", "物華真可玩，黑鬢恐逢秋。"]'),
('aa00e57d-b621-42c3-a098-2eda2c39917f','鄭駕部射圃','歐陽修','宋','宋诗','song-poetry','','[]','夢草西堂射圃連，蘭苕初日露華鮮。',64,'全唐诗/poet.song.17000.json','["夢草西堂射圃連，蘭苕初日露華鮮。", "暈含畫的弦開月，牙算行籌酒滿船。", "鏤管思催吟韻劇，妓簾陰薄舞衣翩。", "當筵獨愧探牛炙，儉府芙蓉客盡賢。"]'),
('7182f5d8-f201-420e-8ea5-ba59ad7e0f2e','甘露寺','歐陽修','宋','宋诗','song-poetry','','[]','雲樹千尋隔翠微，給園金地敞仁祠。',64,'全唐诗/poet.song.17000.json','["雲樹千尋隔翠微，給園金地敞仁祠。", "講花飄雨諸天近，春漏欹連白日遲。", "引鉢當空時取露，殘灰經劫自成池。", "危欄徙倚吟忘下，九子鈴寒塔影移。"]'),
('a6d2b2a3-a74d-4ac9-b307-2f91b09a4dbc','送友人南下','歐陽修','宋','宋诗','song-poetry','','[]','河橋別柳減春條，隔浦挐音聽已遥。',64,'全唐诗/poet.song.17000.json','["河橋別柳減春條，隔浦挐音聽已遥。", "千里羹蓴誇敵酪，滿池滮稻欲鳴蜩。", "東風楚岸神靈雨，殘月吳波上下潮。", "如弔湘纍搴香若，秋江斜日駐蘭橈。"]'),
('6e97af40-9a26-46aa-9d3a-30fc62cc0f6d','高樓','歐陽修','宋','宋诗','song-poetry','','[]','六曲雕欄百尺樓，簾波不定瓦如流。',32,'全唐诗/poet.song.17000.json','["六曲雕欄百尺樓，簾波不定瓦如流。", "浮雲已映樓西北，更向雲西待月鈎。"]'),
('8b919347-41e7-42c7-a03e-fa6ed0a9f3da','榴花','歐陽修','宋','宋诗','song-poetry','','[]','絮亂絲繁不自持，蜂黄蝶紫燕參差。',32,'全唐诗/poet.song.17000.json','["絮亂絲繁不自持，蜂黄蝶紫燕參差。", "榴花最恨來時晚，惆悵春期獨後期。"]'),
('1f908c54-5dee-47f0-bd13-b938c80ac6d0','宿雲夢館','歐陽修','宋','宋诗','song-poetry','','["\u6101\u7eea", "\u601d\u4e61", "\u76f8\u601d"]','北鴈來時歲欲昏，私書歸夢杳難分。',32,'全唐诗/poet.song.17000.json','["北鴈來時歲欲昏，私書歸夢杳難分。", "井桐葉落池荷盡，一夜西窗雨不聞。"]'),
('bc17a739-e9e2-4093-8317-d7356993445c','鷤䳏','歐陽修','宋','宋诗','song-poetry','','[]','花殘如霰落紛紛，紫陌空遺翠幰塵。',32,'全唐诗/poet.song.17000.json','["花殘如霰落紛紛，紫陌空遺翠幰塵。", "鷤䳏枉緣催節物，年華不信有傷春。"]'),
('7bfcbfaf-30a9-4e66-930a-e4d5062a0cfe','簾','歐陽修','宋','宋诗','song-poetry','','[]','銀蒜鈎簾宛地垂，桂叢烏起上朝暉。',32,'全唐诗/poet.song.17000.json','["銀蒜鈎簾宛地垂，桂叢烏起上朝暉。", "枉將玳瑁雕爲押，遮掩春堂礙燕歸。"]'),
('fa77c9e5-f036-4de2-abf6-3b98a215191e','行雪','歐陽修','宋','宋诗','song-poetry','','[]','疊疊煙波隔夢思，離愁幾日減要圍。',32,'全唐诗/poet.song.17000.json','["疊疊煙波隔夢思，離愁幾日減要圍。", "行雲自亦傷無定，莫就行雪託信歸。"]'),
('f6a1f4b1-249a-4010-9f40-db3ed9f7e0bc','琵琶亭上作','歐陽修','宋','宋诗','song-poetry','','[]','九江煙水一登臨，風月清含古恨深。',32,'全唐诗/poet.song.17000.json','["九江煙水一登臨，風月清含古恨深。", "濕盡青衫司馬淚，琵琶還似雍門琴。"]'),
('97ca2960-4ca5-4ca8-bf89-b4529e116fb2','柳','歐陽修','宋','宋诗','song-poetry','','[]','雨闊堤長走畫轅，絮兼梨雪墮春煙。',32,'全唐诗/poet.song.17000.json','["雨闊堤長走畫轅，絮兼梨雪墮春煙。", "東風苑外千絲老，猶伴吳蠶盡日眠。"]'),
('4ff3d0a3-d936-404c-9c98-e6f4ddc51d23','井桐','歐陽修','宋','宋诗','song-poetry','','[]','簷欹碧瓦拂傾梧，玉井聲高轉轆轤。',32,'全唐诗/poet.song.17000.json','["簷欹碧瓦拂傾梧，玉井聲高轉轆轤。", "腸斷西樓驚穩夢，半留殘月照啼烏。"]'),
('68ea30a1-c5c4-4727-b653-ff7c0589e760','雪中寄友人','歐陽修','宋','宋诗','song-poetry','','[]','楚岸梅香半入衣，凍雲銀鑠曉光飛。',32,'全唐诗/poet.song.17000.json','["楚岸梅香半入衣，凍雲銀鑠曉光飛。", "遥應便面逢人處，走馬章街失路歸。"]'),
('03695ba0-cedd-4bdb-9f72-35b280980ef7','與謝三學士唱和八首 和國庠勸講之什','歐陽修','宋','宋诗','song-poetry','','[]','春盡沂風暖，芹生泮水清。',48,'全唐诗/poet.song.17000.json','["春盡沂風暖，芹生泮水清。", "雙旌榮照路，博带儼盈庭。", "函丈師臨席，鏘金壁有經。", "諸生拜玉衮，欣識象丘形。"]'),
('d310a019-0a86-4b5f-9c4b-1dae714d3292','與謝三學士唱和八首 和遊午橋莊','歐陽修','宋','宋诗','song-poetry','','[]','曉壇初畢祀，弭蓋共尋幽。',48,'全唐诗/poet.song.17000.json','["曉壇初畢祀，弭蓋共尋幽。", "鳥哢林中出，泉聲冰下流。", "攀條驚雪盡，翻袂愛風柔。", "好駐城南馬，春桑徧陌頭。"]'),
('8b100266-bcfd-492d-8ea1-ac672ea31f2c','與謝三學士唱和八首 和龍門曉望','歐陽修','宋','宋诗','song-poetry','','[]','霧濛濛曉望平，悠然驅馬獨吟行。',31,'全唐诗/poet.song.17000.json','["霧濛濛曉望平，悠然驅馬獨吟行。", "煙嵐明滅川霞上，凌亂空山百鳥驚。"]'),
('772a6404-241f-4ffb-96b9-fe5e7f21cfbb','與謝三學士唱和八首 除夜偶成拜上學士三丈','歐陽修','宋','宋诗','song-poetry','','[]','萬瓦青煙夕靄生，斗杓迎歲轉東城。',64,'全唐诗/poet.song.17000.json','["萬瓦青煙夕靄生，斗杓迎歲轉東城。", "隋宮守夜沈香燎，楚俗驅神爆竹聲。", "玉樹羅階家宴盛，羽觴稱壽綵衣榮。", "九門朝客思公甚，向曉天風舞雪霙。"]'),
('33e08534-49bf-4cbf-94d4-00ba2106fc45','與謝三學士唱和八首 陪飲上林院後亭見櫻桃花悉已披謝因成七言四韻','歐陽修','宋','宋诗','song-poetry','','[]','尋芳長恨見花遲，豈意看花獨後期。',64,'全唐诗/poet.song.17000.json','["尋芳長恨見花遲，豈意看花獨後期。", "試藉落英聊共醉，爲憐殘萼更攀枝。", "清香肯以無人減，幽艷惟應有蝶知。", "開謝兩城成悵望，傷春不到柳絲時。"]'),
('9099b92c-3744-4c12-b4a9-c6ef6e6a015f','與謝三學士唱和八首 昨日偶陪後騎同適近郊謹成七言四韻兼呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','堤柳纔黄已落梅，尋芳弭蓋共徘徊。',64,'全唐诗/poet.song.17000.json','["堤柳纔黄已落梅，尋芳弭蓋共徘徊。", "桑城日暖蠶催浴，麥垅風和雉應媒。", "別浦人嬉遺翠羽，弋林春廢鎖歌臺。", "歸鞍暮逼宮街鼓，府吏應驚便面回。"]'),
('338cedd9-77ab-4c39-8209-dbd91fee40cc','和八月十五日齋宮對月','歐陽修','宋','宋诗','song-poetry','','[]','皓月三川靜，晴氛萬里鎖。',72,'全唐诗/poet.song.17000.json','["皓月三川靜，晴氛萬里鎖。", "靈光望日滿，寒色入波摇。", "灝氣成山霧，浮雲蔽垅苗。", "廟荒陰燐出，苑廢露螢飄。", "齋館心方寂，秋城夜已遥。", "清談對元亮，瓊彩映蕭蕭。"]'),
('df9f00ec-fa40-4a8a-b974-76c56248a726','送學士三丈','歐陽修','宋','宋诗','song-poetry','','[]','供帳洛城邊，征轅去莫攀。',48,'全唐诗/poet.song.17000.json','["供帳洛城邊，征轅去莫攀。", "人醒風外酒，馬度雪中關。", "故府誰同在，新年獨未還。", "遥應行路者，偏識綵衣斑。"]'),
('715af786-7f19-413f-84c2-3275293f7238','雙桂樓','歐陽修','宋','宋诗','song-poetry','','[]','嘉樹叢生秀，茲樓層漢傍。',72,'全唐诗/poet.song.17000.json','["嘉樹叢生秀，茲樓層漢傍。", "飛甍臨萬井，伏檻出垂楊。", "卷幕晴雲度，披襟夕籟凉。", "山河瞻帝里，風月坐胡牀。", "愛客東阿宴，清歡北海觴。", "淮南多雅詠，歲晚翫幽芳。"]'),
('f2df7bae-9d7a-41aa-bdee-e9e9186a6220','題張應之縣齋','歐陽修','宋','宋诗','song-poetry','','[]','小官歎簿領，夫子卧高齋。',72,'全唐诗/poet.song.17000.json','["小官歎簿領，夫子卧高齋。", "五斗未能去，一丘真所懷。", "綠苔長秋雨，黄葉堆空階。", "縣古仍無柳，池清尚有蛙。", "琴觴開月幌，窗戶對雲崖。", "嵩少亦堪老，行當與子偕。"]'),
('800e7dbe-1fad-440c-8e60-66d59838569d','和梅聖俞杏花','歐陽修','宋','宋诗','song-poetry','','[]','誰道梅花早，殘年豈是春。',24,'全唐诗/poet.song.17000.json','["誰道梅花早，殘年豈是春。", "何如艷風日，獨自占芳辰。"]'),
('b98ddb60-05dc-40c5-b350-4313d34db02b','錢相中伏日池亭宴會分韻','歐陽修','宋','宋诗','song-poetry','','[]','罇俎逢佳節，簪纓奉宴居。',72,'全唐诗/poet.song.17000.json','["罇俎逢佳節，簪纓奉宴居。", "林光拂衣冷，雲影入池虛。", "酒色風前綠，蓮香水上踈。", "飛談交玉麈，聽曲躍文魚。", "粉籜春苞解，紅榴夏實初。", "睢園多美物，能賦謝相如。"]'),
('2cb5fef6-05b2-4c10-b5b0-47d3ff2ac005','送辛判官','歐陽修','宋','宋诗','song-poetry','','[]','被薦方趨召，還鄉仍綵衣。',48,'全唐诗/poet.song.17000.json','["被薦方趨召，還鄉仍綵衣。", "看山向家近，上路逐鴻飛。", "結綬同爲客，登高獨送歸。", "都門足行者，莫訝柳條稀。"]'),
('9587da35-f568-4014-9a68-5f87344f5537','叢翠亭','歐陽修','宋','宋诗','song-poetry','','[]','柳色滿重城，岧岧出翠甍。',48,'全唐诗/poet.song.17000.json','["柳色滿重城，岧岧出翠甍。", "春雲依檻暖，夕照落山明。", "走馬章街曉，翻鴻洛浦晴。", "清罇但留客，桴鼓晝無驚。"]'),
('e739cbd0-53b0-4c1e-88ff-a29bc1a091a2','賀九龍廟祈雪有應','歐陽修','宋','宋诗','song-poetry','','[]','真宰調神化，幽靈應不言。',72,'全唐诗/poet.song.17000.json','["真宰調神化，幽靈應不言。", "朝雲九淵闇，暮霰六花繁。", "朔吹縈歸旆，賓裾載後軒。", "睢園有客賦，郢曲幾人翻。", "槐座方虛位，鋒車佇改轅。", "願移盈尺瑞，爲雨徧羣元。"]'),
('797fc291-643b-40a3-8619-bf4f5c649bcf','早春南征寄洛中諸友','歐陽修','宋','宋诗','song-poetry','','[]','楚色窮千里，行人何苦賒。',48,'全唐诗/poet.song.17000.json','["楚色窮千里，行人何苦賒。", "芳林逢旅鴈，候館噪山鵶。", "春入河邊草，花開水上槎。", "東風一罇酒，新歲獨思家。"]'),
('5209a48e-b096-4d81-9519-52be2be37c6b','花山寒食','歐陽修','宋','宋诗','song-poetry','','[]','客路逢寒食，花山不見花。',24,'全唐诗/poet.song.17000.json','["客路逢寒食，花山不見花。", "歸心隨北鴈，先向洛陽家。"]'),
('10f2742f-5068-4ad9-a233-d2a01107145b','寒食值雨','歐陽修','宋','宋诗','song-poetry','','[]','禁火仍風雨，客心愁復悽。',48,'全唐诗/poet.song.17000.json','["禁火仍風雨，客心愁復悽。", "陰雲花更重，春日水平堤。", "油壁逢南陌，鞦韆出綠蹊。", "尋芳無厭遠，自有錦障泥。"]'),
('47404065-9028-4099-bb3a-bfd456f3876e','寄謝晏尚書二絕  其一','歐陽修','宋','宋诗','song-poetry','','[]','送盡殘春始到家，主人愛客不須嗟。',32,'全唐诗/poet.song.17000.json','["送盡殘春始到家，主人愛客不須嗟。", "紅泥煮酒嘗青杏，猶向臨流藉落花。"]'),
('c835a569-00b3-461b-a189-1b122269db3b','寄謝晏尚書二絕  其二','歐陽修','宋','宋诗','song-poetry','','[]','爛漫殘芳不可收，歸來惆悵失春遊。',32,'全唐诗/poet.song.17000.json','["爛漫殘芳不可收，歸來惆悵失春遊。", "綠陰深處聞啼鳥，猶得追閑果下騮。"]'),
('c33827c2-9610-45d9-8835-69321e09239f','留守相公移鎮漢東','歐陽修','宋','宋诗','song-poetry','','[]','周郊徹楚坰，舊相擁新旌。',48,'全唐诗/poet.song.17000.json','["周郊徹楚坰，舊相擁新旌。", "路識青山在，人今白首行。", "問農穿稻野，候節見梅英。", "腰組人稀識，偏應邸吏驚。"]'),
('f6404598-dde2-4646-83d6-56b04d82ad68','寄聖俞','歐陽修','宋','宋诗','song-poetry','','[]','平沙漫飛雪，行旅斷浮橋。',72,'全唐诗/poet.song.17000.json','["平沙漫飛雪，行旅斷浮橋。", "坐覺山陂阻，空嗟音信遥。", "窮陰變寒律，急節慘驚飚。", "野齋雲猶積，河長冰未銷。", "山陽人半在，洛社客無聊。", "寄問陶彭澤，籃輿誰見邀。"]'),
('989b91a2-1353-402d-b4fb-08cbb665a174','柴舍人金霞閣','歐陽修','宋','宋诗','song-poetry','','[]','簷前洛陽道，下聽走轅聲。',48,'全唐诗/poet.song.17000.json','["簷前洛陽道，下聽走轅聲。", "樹蔭春城綠，山明雪野晴。", "雲藏天外闕，日落柳間營。", "緩步應多樂，壺歌詠太平。"]'),
('4361e8e9-f7b6-4e21-b57a-9d0ec0f8638a','送王公慥判官','歐陽修','宋','宋诗','song-poetry','','[]','久客倦京國，言歸歲已冬。',48,'全唐诗/poet.song.17000.json','["久客倦京國，言歸歲已冬。", "獨過伊水渡，猶聽洛城鍾。", "山色經寒綠，雲陰入暮重。", "臘梅孤館路，疲馬有誰逢。"]'),
('2c668751-8e7c-4569-bc84-d9fb1dfe8b6b','伊川獨遊','歐陽修','宋','宋诗','song-poetry','','[]','綠樹遶伊川，人行亂石間。',48,'全唐诗/poet.song.17000.json','["綠樹遶伊川，人行亂石間。", "寒雲依曉日，白鳥向青山。", "路轉香林出，僧歸野渡閑。", "巖阿誰可訪，興盡復空還。"]'),
('fb9e892f-2095-4ce9-a1ec-4a77d00b203b','遊彭城公白蓮莊','歐陽修','宋','宋诗','song-poetry','','[]','謝墅多幽賞，華軒曾共尋。',48,'全唐诗/poet.song.17000.json','["謝墅多幽賞，華軒曾共尋。", "人閑聊載酒，臺迥獨披襟。", "水落陂光淡，城當山氣陰。", "惟餘桃李樹，日覺翠蹊深。"]'),
('a3fd5f3d-8636-4a0d-a0b2-b3d44ff04112','普明院避暑','歐陽修','宋','宋诗','song-poetry','','[]','選勝避炎鬰，林泉清可佳。',48,'全唐诗/poet.song.17000.json','["選勝避炎鬰，林泉清可佳。", "拂琴驚水鳥，代麈折山花。", "就簡刻筠粉，浮甌烹露芽。", "歸鞍微带雨，不惜角巾斜。"]'),
('233d599d-8ffe-4fbb-90c4-8948094b1cc8','送高君先輩還家','歐陽修','宋','宋诗','song-poetry','','[]','閑居寂寞面重城，過我時欣倒屣迎。',64,'全唐诗/poet.song.17000.json','["閑居寂寞面重城，過我時欣倒屣迎。", "入洛機雲推俊譽，遊梁枚馬得英聲。", "風晴秀野春光變，梅發家林鳥哢輕。", "祗待登高成麗賦，漢庭推轂有公卿。"]'),
('8d731999-4aa3-4b41-a394-99ec375603d4','憶龍門','歐陽修','宋','宋诗','song-poetry','','[]','楚客有歸心，因聲道故岑。',48,'全唐诗/poet.song.17000.json','["楚客有歸心，因聲道故岑。", "依依動春色，藹藹望香林。", "山日巖邊下，溪雲水上霠。", "遥知懷洛社，應復動鄉吟。"]'),
('7df67d72-dd0c-4826-aa23-84203c8af296','贈梅聖俞','歐陽修','宋','宋诗','song-poetry','','[]','黄鵠刷金衣，自言能遠飛。',48,'全唐诗/poet.song.17000.json','["黄鵠刷金衣，自言能遠飛。", "擇侶異棲息，終年脩羽儀。", "朝下玉池飲，暮宿霜桐枝。", "徘徊且垂翼，會有秋風時。"]'),
('b00e543f-6cb8-44df-bd20-48a85382a0bc','郡人獻花','歐陽修','宋','宋诗','song-poetry','','[]','蝶遶蜂遊露滿盤，芳條可惜折來殘。',32,'全唐诗/poet.song.17000.json','["蝶遶蜂遊露滿盤，芳條可惜折來殘。", "我緣多病經春卧，砌下花開不暇看。"]'),
('afb4c1db-6a8b-4b3e-8cc0-833bf344ce24','龍門泛舟晚向香山','歐陽修','宋','宋诗','song-poetry','','[]','暫解塵中紱，來尋物外遊。',72,'全唐诗/poet.song.17000.json','["暫解塵中紱，來尋物外遊。", "搴蘭流水曲，弄桂倚山幽。", "波影巖前綠，灘聲石上流。", "忘機不鷗鳥，至樂翫游鯈。", "梵響雲間出，殘陽樹杪收。", "溪窮興不盡，繫榜且淹留。"]'),
('389be3af-3779-45d8-b4ba-a8fa6c7cde3f','荷葉','歐陽修','宋','宋诗','song-poetry','','[]','採掇本芳陂，移根向玉池。',48,'全唐诗/poet.song.17000.json','["採掇本芳陂，移根向玉池。", "晴香滋白露，翠色弄清漪。", "雨歇涼飚起，煙明夕照移。", "如何江上思，偏動越人悲。"]'),
('ef022392-b5f6-4380-87a0-6436ee31257c','早赴府學釋奠','歐陽修','宋','宋诗','song-poetry','','[]','羽籥興東序，春秋紀上丁。',72,'全唐诗/poet.song.17000.json','["羽籥興東序，春秋紀上丁。", "行祠漢丞相，學禮魯諸生。", "俎豆兼三代，罇罍奠兩楹。", "霧中槐市暗，日出杏壇明。", "昔齒公卿胃，嘗聞絃誦聲。", "何須向闕里，首善本西京。"]'),
('3974821f-167d-497c-af14-eaa213ee9a2c','和晏尚書夏日偶至郊亭','歐陽修','宋','宋诗','song-poetry','','[]','關關啼鳥樹交陰，雨過西城野色侵。',64,'全唐诗/poet.song.17000.json','["關關啼鳥樹交陰，雨過西城野色侵。", "避暑誰能陪劇飲，清歌自可滌煩襟。", "稻花欲秀蟬初嘒，菱蔓初長水正深。", "知有江湖杳然意，扁舟應許共追尋。"]'),
('34783fbd-62a5-4415-a06d-f3c578f54bfa','和晏尚書自嘲','歐陽修','宋','宋诗','song-poetry','','[]','未歸歸即秉鴻鈞，偷醉關亭醉幾春。',32,'全唐诗/poet.song.17000.json','["未歸歸即秉鴻鈞，偷醉關亭醉幾春。", "與物有情寧易得，莫嗔花解久留人。"]'),
('37b1dc29-1fe6-4e23-bcef-dd4b651a1a33','題薦嚴院','歐陽修','宋','宋诗','song-poetry','','[]','那堪多難百憂攻，三十衰容一病翁。',32,'全唐诗/poet.song.17000.json','["那堪多難百憂攻，三十衰容一病翁。", "却把西都看花眼，斷腸來此哭東風。"]'),
('5dead60b-e838-40f1-b750-6d4a35ac76a9','寄題嵩巫亭','歐陽修','宋','宋诗','song-poetry','','[]','平地煙霄向此分，繡楣丹檻照清芬。',32,'全唐诗/poet.song.17000.json','["平地煙霄向此分，繡楣丹檻照清芬。", "風簾暮捲秋空碧，剩見西山數嶺雲。"]'),
('25a60e5e-e5f5-475a-998a-4c45bc258290','題浄慧大師禪齋','歐陽修','宋','宋诗','song-poetry','','[]','巾屨諸方遍，莓苔一室前。',48,'全唐诗/poet.song.17000.json','["巾屨諸方遍，莓苔一室前。", "萎花吟次落，孤月定中圓。", "齋鉢都人施，談機海外傳。", "時應暮鍾響，來度禁城煙。"]'),
('612a66a7-e391-4397-9ea0-5cd0dcb2ee54','琵琶亭','歐陽修','宋','宋诗','song-poetry','','[]','樂天曾謫此江邊，已嘆天涯涕泫然。',32,'全唐诗/poet.song.17000.json','["樂天曾謫此江邊，已嘆天涯涕泫然。", "今日始知予罪大，夷陵此去更三千。"]'),
('d0beecfe-53aa-4d21-83c0-fc6ea7d01ecb','初至虎牙灘見江山類龍門','歐陽修','宋','宋诗','song-poetry','','[]','曉鼓潭潭客夢驚，虎牙灘上作船行。',64,'全唐诗/poet.song.17000.json','["曉鼓潭潭客夢驚，虎牙灘上作船行。", "山形酷似龍門秀，江色不如伊水清。", "平日兩京人少壯，今年三峽歲崢嶸。", "卧聞乳石淙流響，疑是香林八節聲。"]'),
('1af56f24-7654-4de8-af4b-b049366a96cb','題張損之學士蘭皋亭','歐陽修','宋','宋诗','song-poetry','','[]','碕岸接芳蹊，琴觴此自怡。',48,'全唐诗/poet.song.17000.json','["碕岸接芳蹊，琴觴此自怡。", "林花朝落砌，山月夜臨池。", "雨積蛙鳴亂，春歸鳥哢移。", "惟應乘興客，不待主人知。"]'),
('da49a62b-5695-4aa4-ae36-439f1adc35af','霽後看雪走筆呈元珍判官二首','歐陽修','宋','宋诗','song-poetry','','[]','江上寒山祗對門，野花巖草共嶙峋。',64,'全唐诗/poet.song.17000.json','["江上寒山祗對門，野花巖草共嶙峋。", "獨吟羣玉峯前景，閑憶紅蓮幕下人。", "嘉景無人把酒看，縣樓終日獨憑欄。", "山城歲暮驚時節，已作春風料峭寒。"]'),
('48b90b5a-4663-454b-b35d-1d959a5c4ac1','送致政朱郎中','歐陽修','宋','宋诗','song-poetry','','[]','平生不省問田園，白首忘懷道更尊。',64,'全唐诗/poet.song.17000.json','["平生不省問田園，白首忘懷道更尊。", "已上印書辭北闕，稍留冠蓋餞東門。", "馮唐老有爲郎戀，疎廣終無任子恩。", "今日榮歸人所羨，兩兒腰綬擁高軒。"]'),
('af432373-f934-4fa3-98ae-55d8561d857e','留題安州朱氏草堂','歐陽修','宋','宋诗','song-poetry','','[]','俯檻監流蕙徑深，平泉花木繞陰森。',64,'全唐诗/poet.song.17000.json','["俯檻監流蕙徑深，平泉花木繞陰森。", "蛙鳴鼓吹春喧耳，草暖池塘夢費吟。", "賭墅乞甥賓對弈，驚鴻送目手揮琴。", "嗟予遠捧從軍檄，不得披裘五月尋。"]'),
('41028aab-0241-4fe1-a37d-fd3e5589537e','題光化張氏園亭','歐陽修','宋','宋诗','song-poetry','','[]','君家花幾種，來自洛之濱。',72,'全唐诗/poet.song.17000.json','["君家花幾種，來自洛之濱。", "惟我曾遊洛，看花若故人。", "芳菲不改色，開洛幾經春。", "陶令來常醉，山公到最頻。", "曲池涵草樹，啼鳥悅松筠。", "相德今方賴，思歸未有因。"]'),
('c985d76f-a950-4d60-b1e0-b94f0875b77f','和聖俞百花洲二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','野岸溪幾曲，松蹊穿翠陰。',24,'全唐诗/poet.song.17000.json','["野岸溪幾曲，松蹊穿翠陰。", "不知芳渚遠，但愛綠荷深。"]'),
('b18fabfb-9f7d-4823-abf3-f916b0af5715','和聖俞百花洲二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','荷深水風闊，雨過清香發。',24,'全唐诗/poet.song.17000.json','["荷深水風闊，雨過清香發。", "暮角起城頭，歸橈带明月。"]'),
('2094aec4-98d7-4b7a-8198-b17b604962c2','魚','歐陽修','宋','宋诗','song-poetry','','[]','秋水澄清見髮毛，錦鱗行處水紋摇。',32,'全唐诗/poet.song.17000.json','["秋水澄清見髮毛，錦鱗行處水紋摇。", "岸邊人影驚還去，時向綠荷深處跳。"]'),
('3d217b43-1a69-4a07-94d3-4ec531ceabc4','月','歐陽修','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天高月影浸長江，江闊風微水面涼。',32,'全唐诗/poet.song.17000.json','["天高月影浸長江，江闊風微水面涼。", "天水相連爲一色，更無纖靄隔清光。"]'),
('472fd0b8-414a-46c7-b266-fdaf11d91d7a','棖子','歐陽修','宋','宋诗','song-poetry','','[]','嘉樹團團俯可攀，壓枝秋實漸斕斑。',32,'全唐诗/poet.song.17000.json','["嘉樹團團俯可攀，壓枝秋實漸斕斑。", "朱欄碧瓦清霜曉，粲粲繁星綠葉間。"]'),
('00f91e0e-44b8-49a7-888c-712e9c1c8814','初冬歸襄城弊居','歐陽修','宋','宋诗','song-poetry','','[]','日落原野晦，天寒閭市閑。',72,'全唐诗/poet.song.17000.json','["日落原野晦，天寒閭市閑。", "牛斗遠陂去，鳥雀空簷間。", "憑高植藜杖，曠目瞻前山。", "垅麥風際綠，霜鵶村外還。", "禾黍日已熟，杯酒聊開顔。", "酣歌歲云暮，寂寞向柴關。"]'),
('809ee598-740f-49b4-808f-d465d174812b','和晏尚書對雪招飲','歐陽修','宋','宋诗','song-poetry','','[]','瑶林瓊樹影交加，誰伴山翁醉帽斜。',32,'全唐诗/poet.song.17000.json','["瑶林瓊樹影交加，誰伴山翁醉帽斜。", "自把金船浮白蟻，應須紅粉唱梅花。"]'),
('ccdf88ae-61d4-44c4-98b9-f8f2cd4ed42d','滑州歸鴈亭','歐陽修','宋','宋诗','song-poetry','','[]','長河終歲足悲風，亭古臺荒半倚空。',32,'全唐诗/poet.song.17000.json','["長河終歲足悲風，亭古臺荒半倚空。", "惟有鴈歸時最早，柳含微綠杏粘紅。"]'),
('f665cbdb-bfdb-439a-a518-23940df7309a','送黄通之鄖鄉','歐陽修','宋','宋诗','song-poetry','','[]','君子貴從俗，小官能養賢。',48,'全唐诗/poet.song.17000.json','["君子貴從俗，小官能養賢。", "無慚折腰吏，勉食落頭鮮。", "困有亭之理，窮當志益堅。", "惟宜少近禍，親髮況皤然。"]'),
('acc68b79-4a12-4f46-a74a-0831f1d934f8','秋日與諸君馬頭山登高','歐陽修','宋','宋诗','song-poetry','','[]','晴原霜後若榴紅，佳節登臨興未窮。',64,'全唐诗/poet.song.17000.json','["晴原霜後若榴紅，佳節登臨興未窮。", "日泛花光摇露際，酒浮山色入樽中。", "金壺恣灑毫端墨，玉麈交揮席上風。", "惟有淵明偏好飲，籃輿酩酊一衰翁。"]'),
('7dc6e526-4a33-481a-9493-99fba74263c5','送楊君歸漢上','歐陽修','宋','宋诗','song-poetry','','[]','我昔謫窮縣，相逢清漢陰。',48,'全唐诗/poet.song.17000.json','["我昔謫窮縣，相逢清漢陰。", "拂塵時解榻，置酒屢橫琴。", "介節溫如玉，嘉辭擲若金。", "趣當鄉士薦，無滯計車音。"]'),
('b191f779-6bf0-4368-95fc-e88025318b1a','後潭遊船見岸上看者有感','歐陽修','宋','宋诗','song-poetry','','[]','喧喧誰暇聽歌謳，浪遶春潭逐綵舟。',32,'全唐诗/poet.song.17000.json','["喧喧誰暇聽歌謳，浪遶春潭逐綵舟。", "爭得心如汝無事，明年今日更來遊。"]'),
('426d114b-2269-448d-a638-c730e4c1dc3b','春日獨居','歐陽修','宋','宋诗','song-poetry','','[]','眾喧爭去逐春遊，獨靜誰知味最優。',64,'全唐诗/poet.song.17000.json','["眾喧爭去逐春遊，獨靜誰知味最優。", "雨霽日長花爛漫，春深睡美夢飄浮。", "常憂任重才難了，偶得身閑樂暫偷。", "因此益知爲郡趣，乞州仍擬乞山州。"]'),
('48b7d7e0-5c05-4251-892b-69c189013072','得滕岳陽書大誇湖山之美郡署懷物甚野其意有戀著之趣作詩一百四十言爲寄且警激之','歐陽修','宋','宋诗','song-poetry','','[]','峭巘孤城倚，平湖遠浪來。',168,'全唐诗/poet.song.17000.json','["峭巘孤城倚，平湖遠浪來。", "萬尋迷島嶼，百仞起樓臺。", "太守凭軒處，羣賓奉笏陪。", "清霜薦丹橘，積雨過黄梅。", "逸思歌湘曲，遒文繼楚材。", "魚貪河岫樂，雲忘帝鄉回。", "遥信雙鴻下，新緘尺素裁。", "因聞誇野景，自笑擁邊埃。", "龍漠方多孽，旄頭久示災。", "旌旗時映日，鼙鼓或驚雷。", "有志皆嘗膽，何人可鑿壞。", "儒生半投筆，牧豎亦輸財。", "沮澤辭猶慢，蒲萄館未開。", "支離莫攘臂，天子正求才。"]'),
('8ed6f917-4e78-47fa-a233-977b591bf599','幽谷種花洗山','歐陽修','宋','宋诗','song-poetry','','[]','洗出峯巒看臘雪，栽成花木趁新年。',32,'全唐诗/poet.song.17000.json','["洗出峯巒看臘雪，栽成花木趁新年。", "史君功行今將滿，誰肯同來作地仙。"]'),
('33d1536d-c1c1-4e7b-b539-6ca4b0bb875e','鷺鷥','歐陽修','宋','宋诗','song-poetry','','[]','激石灘聲如戰鼓，翻天浪色似銀山。',32,'全唐诗/poet.song.17000.json','["激石灘聲如戰鼓，翻天浪色似銀山。", "灘驚浪打風兼雨，獨立亭亭意愈閑。"]'),
('350e745c-8025-48b2-9d48-3583f32fb8a0','贈歌者','歐陽修','宋','宋诗','song-poetry','','[]','病客多年掩綠罇，今宵爲爾一顔醺。',32,'全唐诗/poet.song.17000.json','["病客多年掩綠罇，今宵爲爾一顔醺。", "可憐玉樹庭花後，又向江都月下聞。"]'),
('f867f312-2b44-4960-83d2-d785f1dfc13e','初春','歐陽修','宋','宋诗','song-poetry','','[]','新年變物華，春意日堪嘉。',48,'全唐诗/poet.song.17000.json','["新年變物華，春意日堪嘉。", "霽色初含柳，餘寒尚勒花。", "風絲飛蕩漾，林鳥哢交加。", "獨有無悰者，誰知老可嗟。"]'),
('93f27b5c-1012-463a-a97d-414c012866fc','送田處士','歐陽修','宋','宋诗','song-poetry','','[]','秦士多豪俠，夫君久遁名。',48,'全唐诗/poet.song.17000.json','["秦士多豪俠，夫君久遁名。", "青山對高卧，白首喜論兵。", "氣古時難合，詩精格入評。", "公車不久召，歸袖夕風生。"]'),
('c179bb51-bfe4-4154-9d69-bec6470ca830','行次壽州寄內','歐陽修','宋','宋诗','song-poetry','','[]','紫金山下水長流，嘗記當年此共遊。',32,'全唐诗/poet.song.17000.json','["紫金山下水長流，嘗記當年此共遊。", "今夜南風吹客夢，清淮明月照孤舟。"]'),
('38b67af6-0637-4c2f-819a-6c7d4c952564','答呂太博賞雙蓮','歐陽修','宋','宋诗','song-poetry','','[]','年來因病不飲酒，老去無悰懶作詩。',64,'全唐诗/poet.song.17000.json','["年來因病不飲酒，老去無悰懶作詩。", "我已負花常自愧，君須屢醉及芳時。", "漢宮姊妹爭新寵，湘浦皇英望所思。", "天下從來無定色，況將鉛黛比天姿。"]'),
('3a4042c2-3447-4528-9159-910b7c6c8e87','酬孫延仲龍圖','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','洛社當年盛莫加，洛陽耆老至今誇。',64,'全唐诗/poet.song.17000.json','["洛社當年盛莫加，洛陽耆老至今誇。", "死生零落餘無幾，齒髮衰殘各可嗟。", "北庫酒醪君舊物，西湖煙水我如家。", "已將二美交相勝，仍枉新篇麗彩霞。"]'),
('309953b3-db3b-4d96-8957-f4b4c8168815','常州張卿養素堂','歐陽修','宋','宋诗','song-poetry','','[]','江左衣冠世有名，幾人今復振家聲。',64,'全唐诗/poet.song.17000.json','["江左衣冠世有名，幾人今復振家聲。", "朝廷獨立清冰節，閭里歸來白首卿。", "志在言談猶慷慨，身閑耳目益聰明。", "長松野水誰爲伴，顧我堪羞戀寵榮。"]'),
('c224e772-0abe-4b2a-a807-3d4f1e860d76','西湖泛舟呈運使學士張掞','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','波光柳色碧溟濛，曲渚斜橋畫舸通。',64,'全唐诗/poet.song.17000.json','["波光柳色碧溟濛，曲渚斜橋畫舸通。", "更遠更佳唯恐盡，漸深漸密似無窮。", "綺羅香裏留佳客，絃管聲來颺晚風。", "半醉迴舟迷向背，樓臺高下夕陽中。"]'),
('6f594452-1b09-49cc-8423-ecab0aedb07f','去思堂會飲得春字','歐陽修','宋','宋诗','song-poetry','','[]','世事紛然百態新，西岡一醉十三春。',64,'全唐诗/poet.song.17000.json','["世事紛然百態新，西岡一醉十三春。", "自慚白髮隨年少，猶把金鍾勸主人。", "黄鳥亂飛深夏木，紅榴初發艷清晨。", "佳時易失閑難得，有酒重來莫厭頻。"]'),
('b3d35aad-e9dc-4e05-933e-c6c064487f44','太傅相公入陪大祀以疾不行聖恩優賢詔書俞允發於感遇紀以嘉篇小子不揆輒亦課成拙惡詩一首','歐陽修','宋','宋诗','song-poetry','','[]','驛騎頻來急詔隨，都人相與竊嗟咨。',64,'全唐诗/poet.song.17000.json','["驛騎頻來急詔隨，都人相與竊嗟咨。", "自非峻節終無改，安得清衷久益思。", "前席蓋將注讜議，在庭非爲乏陪祠。", "尊賢優老朝家美，他日安車召未遲。"]'),
('5fcbfa83-f156-4468-89c7-e12082fd30c5','寄子春發運待制','歐陽修','宋','宋诗','song-poetry','','[]','廣陵花月嘗同醉，睢苑風霜暫破顔。',64,'全唐诗/poet.song.17000.json','["廣陵花月嘗同醉，睢苑風霜暫破顔。", "但喜交情久彌重，休嗟人事老多艱。", "壯心未忍悲華髮，强飲猶能倒玉山。", "留滯江湖應不久，多爲春酒待君還。"]'),
('6fecd5c0-61f9-4ae7-9607-926c77521e95','答許發運見寄','歐陽修','宋','宋诗','song-poetry','','[]','瓊花芍藥世無倫，偶不題詩便怨人。',32,'全唐诗/poet.song.17000.json','["瓊花芍藥世無倫，偶不題詩便怨人。", "曾向無雙亭下醉，自知不負廣陵春。"]'),
('900d2393-fc96-4d64-bd9c-87c662983c27','贈廬山僧居訥','歐陽修','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','方瞳如水衲披肩，邂逅相逢爲灑然。',32,'全唐诗/poet.song.17000.json','["方瞳如水衲披肩，邂逅相逢爲灑然。", "五百僧中得一士，始知林下有遺賢。"]'),
('52d9e0bb-bb1f-4023-bf47-84ee2e340fb4','過塞二首','歐陽修','宋','宋诗','song-poetry','','[]','身驅漢馬踏胡霜，每嘆勞生祗自傷。',32,'全唐诗/poet.song.17000.json','["身驅漢馬踏胡霜，每嘆勞生祗自傷。", "氣候愈寒人愈北，不如征鴈解隨陽。"]'),
('807ba9d8-7d5d-46d1-b1d1-6f2705dccd19','晏元獻公挽辭三首  其一','歐陽修','宋','宋诗','song-poetry','','[]','接物襟懷曠，推賢品藻精。',48,'全唐诗/poet.song.17000.json','["接物襟懷曠，推賢品藻精。", "謀猷存二府，臺閣徧諸生。", "帝念宮臣舊，恩隆衮服榮。", "春風綠野迥，千兩送銘旌。"]'),
('e1132be7-31d4-4b42-b919-106c9b3a40aa','晏元獻公挽辭三首  其二','歐陽修','宋','宋诗','song-poetry','','[]','四鎮名藩忽十春，歸來白首兩朝臣。',64,'全唐诗/poet.song.17000.json','["四鎮名藩忽十春，歸來白首兩朝臣。", "上心方喜親耆德，物論猶期秉國鈞。", "退食圖書盈一室，開罇談笑列嘉賓。", "昔人風采今人少，慟哭何由贖以身。"]'),
('1b5a7bdc-2af5-4fce-9351-32d36f42681d','晏元獻公挽辭三首  其三','歐陽修','宋','宋诗','song-poetry','','[]','富貴優游五十年，始終明哲何身全。',64,'全唐诗/poet.song.17000.json','["富貴優游五十年，始終明哲何身全。", "一時聞望朝廷重，餘事文章海外傳。", "舊館池臺閑水石，悲笳風日慘山川。", "解官制服門生禮，慚負君恩隔九泉。"]'),
('1d149f90-e744-437d-8c7a-8acebc17661e','酬滑州公儀龍圖見寄','歐陽修','宋','宋诗','song-poetry','','[]','畫舫齋前舊菊叢，十年開落任秋風。',32,'全唐诗/poet.song.17000.json','["畫舫齋前舊菊叢，十年開落任秋風。", "知君爲我留紅旆，猶記栽花白髮翁。"]'),
('30944b75-0b62-413b-8a83-97f728ee707b','贈王介甫','歐陽修','宋','宋诗','song-poetry','','[]','翰林風月三千首，吏部文章二百年。',64,'全唐诗/poet.song.17000.json','["翰林風月三千首，吏部文章二百年。", "老去自憐心尚在，後來誰與子爭先。", "朱門歌舞爭新態，綠綺塵埃試拂絃。", "常恨聞名不相識，相逢罇酒盍留連。"]'),
('e60321d4-db04-4928-a892-e4a25fd508db','蘇才翁挽詩二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','握手接歡言，相知二十年。',48,'全唐诗/poet.song.17000.json','["握手接歡言，相知二十年。", "文章家世事，名譽弟兄賢。", "可惜英魂掩，惟餘醉墨傳。", "秋風衰柳岸，撫柩送歸船。"]'),
('e2cec739-6a4d-46f7-9a18-e5cd64829ee5','蘇才翁挽詩二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','雄心壯志兩崢嶸，誰謂中年志不成。',64,'全唐诗/poet.song.17000.json','["雄心壯志兩崢嶸，誰謂中年志不成。", "零落篇章爲世寶，平生風義見交情。", "青松月下泉臺路，白草原頭薤露聲。", "自古英豪皆若此，哭君徒有淚沾纓。"]'),
('c5c3281a-2fd3-475e-9500-9c6e002ff603','送石揚休還蜀','歐陽修','宋','宋诗','song-poetry','','[]','長愛謫仙誇蜀道，送君西望重吟哦。',64,'全唐诗/poet.song.17000.json','["長愛謫仙誇蜀道，送君西望重吟哦。", "路高黄鵠飛不到，花發杜鵑啼更多。", "清禁寒生鳳池水，繡衣榮照錦江波。", "昔年同舍青衿子，夾道歡迎鬢已皤。"]'),
('d059abf9-20c3-47f3-8110-92c36720c29f','和景仁試明經大義多不通有感','歐陽修','宋','宋诗','song-poetry','','[]','庠序制猶闕，鄉閭教不行。',48,'全唐诗/poet.song.17000.json','["庠序制猶闕，鄉閭教不行。", "古於經學政，今也藝虛名。", "來者益可鄙，待之因愈輕。", "無徒誚其陋，講勸在公卿。"]'),
('94b8074d-673b-464c-900b-0c05cde2d5ec','和公儀試進士終場有作','歐陽修','宋','宋诗','song-poetry','','[]','朝家意在取遺才，樂育推仁亦至哉。',64,'全唐诗/poet.song.17000.json','["朝家意在取遺才，樂育推仁亦至哉。", "本欲勵賢敦古學，可嗟趨利競朋來。", "昔人自重身難進，薄俗多端路久開。", "何異鱣魴爭尺水，巨魚先已化風雷。"]'),
('491f67c3-1222-4d7f-a79b-1a486c3bfe0e','久在病告近方赴直偶成拙詩二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','經時移病久端居，玉署新秋獨直廬。',64,'全唐诗/poet.song.17000.json','["經時移病久端居，玉署新秋獨直廬。", "夜靜樓臺落銀漢，人閑鈴索少文書。", "江湖未去年華晚，燈火微涼暑雨初。", "敢向聖朝辭寵祿，多慚禁禦養慷疎。"]'),
('1e6a96db-2750-4236-b771-4fb4f021d6ae','久在病告近方赴直偶成拙詩二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','清晨下直大明宮，馳馬悠然宿露中。',64,'全唐诗/poet.song.17000.json','["清晨下直大明宮，馳馬悠然宿露中。", "金闕雲開滄海日，天街雨後綠槐風。", "歲花忽忽雙流矢，鬢髮蕭蕭一病翁。", "名在玉堂歸未得，西山畫閣興何窮。"]'),
('32234827-dd61-437c-a836-1e2bd293317b','送潤州通判屯田','歐陽修','宋','宋诗','song-poetry','','[]','船頭初轉兩旗開，清曉津亭疊鼓催。',64,'全唐诗/poet.song.17000.json','["船頭初轉兩旗開，清曉津亭疊鼓催。", "自古江山最佳處，況君談笑有餘才。", "雲愁海闊驚濤漲，木落霜清畫角哀。", "善政已成多雅思，寄詩宜逐驛筒來。"]'),
('b95c1281-c8eb-4214-9d30-82ea80e8a236','和劉原甫平山堂見寄','歐陽修','宋','宋诗','song-poetry','','[]','督府繁華久已闌，至今形勝可躋攀。',64,'全唐诗/poet.song.17000.json','["督府繁華久已闌，至今形勝可躋攀。", "山橫天地蒼茫外，花發池臺草莽間。", "萬井笙歌遺俗在，一罇風月屬君閑。", "遥知爲我留真賞，恨不相隨暫解顔。"]'),
('7a3a884c-e5d2-4b03-bb31-9f52410c1c8a','送張吉老赴浙憲','歐陽修','宋','宋诗','song-poetry','','[]','吳越東南富百城，路人應羨繡衣榮。',64,'全唐诗/poet.song.17000.json','["吳越東南富百城，路人應羨繡衣榮。", "昔時結客曾遊處，今見焚香夾道迎。", "治世用刑期止殺，仁心聽獄務求生。", "時豐訟息多餘暇，無惜新篇屢寄聲。"]'),
('7a3a6746-2c14-4bb1-af16-abc0512fe65e','春日詞五首  其一','歐陽修','宋','宋诗','song-poetry','','[]','宮壇青陌賽牛回，玉琯東風逗曉來。',32,'全唐诗/poet.song.17000.json','["宮壇青陌賽牛回，玉琯東風逗曉來。", "不待嶺梅傳遠信，剪刀先放綵花開。"]'),
('eed82554-1669-48b9-bc58-7f2fc0524881','春日詞五首  其二','歐陽修','宋','宋诗','song-poetry','','[]','試粉東窗待曉迴，共尋春柳榜香臺。',32,'全唐诗/poet.song.17000.json','["試粉東窗待曉迴，共尋春柳榜香臺。", "不驚樹裏禽初變，共喜釵頭燕已來。"]'),
('8950a337-494e-4097-bf1b-039e5852ecd4','春日詞五首  其三','歐陽修','宋','宋诗','song-poetry','','[]','紅霧初開上曉霞，共驚風色變年華。',32,'全唐诗/poet.song.17000.json','["紅霧初開上曉霞，共驚風色變年華。", "香車遥認春雷響，庭雪先開玉樹花。"]'),
('f135f9f3-4368-4ff7-94a7-4a50cf54c72c','春日詞五首  其四','歐陽修','宋','宋诗','song-poetry','','[]','玉琯吹灰夜色殘，雞鳴紅日上仙盤。',32,'全唐诗/poet.song.17000.json','["玉琯吹灰夜色殘，雞鳴紅日上仙盤。", "初驚百舌綿蠻語，已覺東風料峭寒。"]'),
('4d0f4d8b-e317-4528-a6c3-abb24047782c','春日詞五首  其五','歐陽修','宋','宋诗','song-poetry','','[]','待曉銅荷剪蠟煤，繡簾春色犯寒來。',32,'全唐诗/poet.song.17000.json','["待曉銅荷剪蠟煤，繡簾春色犯寒來。", "畫眉不待張京兆，自有新粧試落梅。"]'),
('18d26205-61fc-49e6-a66a-37206bd27052','走筆答原甫提刑學士','歐陽修','宋','宋诗','song-poetry','','[]','歲暮山城喜少留，西亭尚欲挽行輈。',32,'全唐诗/poet.song.17000.json','["歲暮山城喜少留，西亭尚欲挽行輈。", "一罇莫惜臨岐別，十載相逢各白頭。"]'),
('af7cb797-74a2-4540-ac24-07e0efb12b45','酬浄照大師說','歐陽修','宋','宋诗','song-poetry','','[]','佛說吾不學，勞師忽欵關。',48,'全唐诗/poet.song.17000.json','["佛說吾不學，勞師忽欵關。", "吾方仁義急，君且水雲閑。", "意淡宜松鶴，詩清叩珮環。", "林泉苟有趣，何必市廛間。"]'),
('f946b563-32af-4144-813a-c9ab2dac8513','和劉原父從幸後苑觀稻呈講筵諸公','歐陽修','宋','宋诗','song-poetry','','[]','禁籞皇居接，香畦鏤檻邊。',120,'全唐诗/poet.song.17000.json','["禁籞皇居接，香畦鏤檻邊。", "分渠自靈沼，種稻滿滮田。", "六穀名居首，三農政所先。", "擢莖蒙德茂，養實以時堅。", "曉謁龍墀罷，行瞻鳳蓋翩。", "粹容知喜色，嘉瑞奏豐年。", "衰病慚經學，陪遊與俊賢。", "安知帝力及，但樂歲功全。", "拜賜秋風裏，分行黼座前。", "自憐臺笠叟，來綴侍臣篇。"]'),
('8c7c7560-f1de-41ac-b1db-370995df32fb','送薛水部通判并州','歐陽修','宋','宋诗','song-poetry','','[]','胸懷磊落逢知己，氣略縱橫負壯心。',64,'全唐诗/poet.song.17000.json','["胸懷磊落逢知己，氣略縱橫負壯心。", "玉麈生風賓滿坐，金鱗照甲士如林。", "牛羊日暖山田美，雨雪春寒土屋深。", "自古幽并重豪俠，祗應行樂費黄金。"]'),
('fb703905-6abe-42cb-8070-c9b11409daaa','鶴','歐陽修','宋','宋诗','song-poetry','','[]','樊籠毛羽日低摧，野水長松眼暫開。',32,'全唐诗/poet.song.17000.json','["樊籠毛羽日低摧，野水長松眼暫開。", "萬里秋風天外意，日斜閑啄岸邊苔。"]'),
('5e8a5b80-4609-4802-a40e-47c20005a6cb','鴈','歐陽修','宋','宋诗','song-poetry','','[]','來時沙磧已冰霜，飛過江南木葉黄。',32,'全唐诗/poet.song.17000.json','["來時沙磧已冰霜，飛過江南木葉黄。", "水闊天低雲暗澹，朔風吹起自成行。"]'),
('2778e950-015f-4932-9694-21c693a44d54','鶻','歐陽修','宋','宋诗','song-poetry','','[]','依倚秋風氣象豪，似欺黄雀在蓬蒿。',32,'全唐诗/poet.song.17000.json','["依倚秋風氣象豪，似欺黄雀在蓬蒿。", "不知羽翼青冥上，腐鼠相隨勢亦高。"]'),
('562b46df-88f4-414b-a297-2eef8d5f4ef6','原甫致齋集禧余亦攝事後廟謹呈拙句兼簡聖俞','歐陽修','宋','宋诗','song-poetry','','[]','受命分行攝上公，紫微人在玉華宮。',64,'全唐诗/poet.song.17000.json','["受命分行攝上公，紫微人在玉華宮。", "樓臺碧瓦輝雲日，蓮芰清香带水風。", "每接少年嗟老病，尚能聯句惱詩翁。", "凌晨已事追佳賞，綠李甘瓜興未窮。"]'),
('a3fa01f1-ebc7-42b9-9b59-275388740f60','同年秘書丞陳動之挽詞二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','場屋當年氣最雄，交游樽酒弟兄同。',64,'全唐诗/poet.song.17000.json','["場屋當年氣最雄，交游樽酒弟兄同。", "文章落筆傳都下，議論生鋒服座中。", "自古聖賢誰不死，況君門戶有清風。", "凋零三十年朋舊，在者多爲白髮翁。"]'),
('8fa18fd0-f3a2-4edf-bcc2-59d86d2169db','同年秘書丞陳動之挽詞二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','富貴聲名豈足論，死生榮辱等埃塵。',64,'全唐诗/poet.song.17000.json','["富貴聲名豈足論，死生榮辱等埃塵。", "青衫照日誇春榜，白首餘年哭故人。", "盛德不忘存誌刻，話言能記有朋親。", "吳江草木春風動，瀝酒誰瞻垅樹新。"]'),
('43f96f46-17cb-42c0-8e12-28eae83109c8','奉和劉舍人初雪','歐陽修','宋','宋诗','song-poetry','','[]','夜雪真空曉更飄，龍墀風冷珮聲高。',64,'全唐诗/poet.song.17000.json','["夜雪真空曉更飄，龍墀風冷珮聲高。", "瓊花落處縈仙仗，玉殿光中認赭袍。", "下直笑談多樂事，平時罇酒屬吾曹。", "羨君年少才無敵，顧我雖衰飲尚豪。"]'),
('072164e0-1a1b-4bab-8221-40cc4f04d6c8','暮春書事呈四舍人','歐陽修','宋','宋诗','song-poetry','','[]','樹陰初合苔生暈，花蕊新成蜜滿脾。',64,'全唐诗/poet.song.17000.json','["樹陰初合苔生暈，花蕊新成蜜滿脾。", "鸎燕各歸巢哺子，蛙魚共樂雨添池。", "少年春物今如此，老病衰翁了不知。", "飽食杜門何所事，日長偏與睡相宜。"]'),
('bc695ec3-515b-4aee-8fc3-955a0ae32b9b','荷葉','歐陽修','宋','宋诗','song-poetry','','[]','池面風來波瀲瀲，波間露下葉田田。',32,'全唐诗/poet.song.17000.json','["池面風來波瀲瀲，波間露下葉田田。", "誰於水上張青蓋，罩却紅粧唱採蓮。"]'),
('eca470d7-76bf-4d96-a364-08443bafde52','小池','歐陽修','宋','宋诗','song-poetry','','[]','深院無人鎖曲池，莓苔繞岸雨生衣。',32,'全唐诗/poet.song.17000.json','["深院無人鎖曲池，莓苔繞岸雨生衣。", "綠萍合處蜻蜓立，紅蓼開時蛺蝶飛。"]'),
('e03e9510-3ae4-4ad0-bcea-8fbde9f52e99','釣者','歐陽修','宋','宋诗','song-poetry','','[]','風牽釣線裊長竿，短笠輕蓑細草間。',32,'全唐诗/poet.song.17000.json','["風牽釣線裊長竿，短笠輕蓑細草間。", "春雨濛濛看不見，水煙埋却面前山。"]'),
('12c18cfe-370a-4885-a7db-9058d92e63ee','霜','歐陽修','宋','宋诗','song-poetry','','["\u5bd3\u4eba", "\u548f\u7269", "\u83ca\u82b1", "\u8a00\u5fd7", "\u548f\u7269\u8bd7", "\u54c1\u683c"]','一夜新霜著瓦輕，芭蕉心折敗荷傾。',32,'全唐诗/poet.song.17000.json','["一夜新霜著瓦輕，芭蕉心折敗荷傾。", "奈寒惟有東籬菊，金蕊繁開曉更清。"]'),
('2964aefa-3aff-4c64-ae13-acaafc5edf9e','牛','歐陽修','宋','宋诗','song-poetry','','[]','日出東籬黄雀驚，雪銷春動草芽生。',32,'全唐诗/poet.song.17000.json','["日出東籬黄雀驚，雪銷春動草芽生。", "土坡平慢陂田闊，橫載童兒带犢行。"]'),
('16bd99ea-20e1-41ec-9a1e-e402427ce583','送劉虛白二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','祕訣誰傳妙若神，能將題品徧朝紳。',32,'全唐诗/poet.song.17000.json','["祕訣誰傳妙若神，能將題品徧朝紳。", "因言禍福兼忠孝，吾愛君平善誨人。"]'),
('d7f7c832-3755-4a32-8746-394a8a390429','送劉虛白二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','我嗟韁鎖若牽拘，久羨南山去結廬。',32,'全唐诗/poet.song.17000.json','["我嗟韁鎖若牽拘，久羨南山去結廬。", "自顧豈勞君借譽，偶然章服裹猿狙。"]'),
('f2cd1d92-d3f2-4ff4-8d40-2c0bd6a02970','劉丞相挽詞二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','南國鄰鄉邑，東都並雋遊。',48,'全唐诗/poet.song.17000.json','["南國鄰鄉邑，東都並雋遊。", "賜袍聯唱第，命相見封侯。", "念昔趨黄閤，相看笑白頭。", "盛衰同俯仰，旌旐送山丘。"]'),
('747eafa0-8d1e-4442-91ef-e916dddeec20','劉丞相挽詞二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','連章相府辭榮寵，擁旆名都出鎮臨。',64,'全唐诗/poet.song.17000.json','["連章相府辭榮寵，擁旆名都出鎮臨。", "年少已推能宰社，鄉人終不見揮金。", "長蛟息浪歸帆穩，喬木生煙蔽日深。", "平昔家庭敦友愛，可憐松檟亦連陰。"]'),
('85713d5a-1511-48d9-bf4d-1eddf357836c','寄大名程資政琳','歐陽修','宋','宋诗','song-poetry','','[]','龍門長恨晚方登，便以忘年接後生。',64,'全唐诗/poet.song.17000.json','["龍門長恨晚方登，便以忘年接後生。", "談劇每容陪玉麈，飲豪常憶困金觥。", "冰開御水春應綠，雲破淮天月自明。", "醉倒離筵聽別曲，醒來猶尚記餘聲。"]'),
('082bba94-ca03-4b4a-a943-b6d6fde499c9','東齋對雪有懷','歐陽修','宋','宋诗','song-poetry','','[]','東齋坐客飲方豪，誰報風簾雪已飄。',64,'全唐诗/poet.song.17000.json','["東齋坐客飲方豪，誰報風簾雪已飄。", "貪聽罇前歌裊裊，不聞窗外響蕭蕭。", "已憐殘臘催梅蕊，更約新春探柳條。", "共憶瀛洲人獨直，神仙清景正寥寥。"]'),
('8ca61147-4ef4-4f68-89d0-92bf1f1044a2','雪後玉堂夜直','歐陽修','宋','宋诗','song-poetry','','[]','雪壓宮牆鎖禁城，沉沉樓殿景尤清。',64,'全唐诗/poet.song.17000.json','["雪壓宮牆鎖禁城，沉沉樓殿景尤清。", "玉堂影亂燈交晃，銀闕光寒夜自明。", "塵暗圖書愁獨直，人閑鈴索久無聲。", "鑾坡地峻誰能到，莫惜宮壺酒屢傾。"]'),
('99d1332c-e895-436f-8a7c-bf2d89e613a8','官舍假日書懷奉呈子華內翰長文原甫景仁舍人聖俞博士','歐陽修','宋','宋诗','song-poetry','','[]','鎖印春風雪入簾，天寒鳥雀聚空簷。',64,'全唐诗/poet.song.17000.json','["鎖印春風雪入簾，天寒鳥雀聚空簷。", "青幡受歲兒童喜，白髮催人老病添。", "艷舞回腰飛玉盞，清吟擁鼻對冰蟾。", "相從一笑兩莫得，簿領區區嘆米鹽。"]'),
('1685e77a-3403-43e5-9a20-47a883f539e0','酬王君玉中秋席上待月值雨','歐陽修','宋','宋诗','song-poetry','','[]','池上雖然無皓魄，罇前殊未減清歡。',64,'全唐诗/poet.song.17000.json','["池上雖然無皓魄，罇前殊未減清歡。", "綠醅自有寒中力，紅粉尤宜燭下看。", "羅綺塵隨歌扇動，管絃聲雜雨荷乾。", "客舟閑卧王夫子，詩陣教誰主將壇。"]'),
('56978998-ec96-48ba-a89b-a7079dbe50b8','中秋不見月問客','歐陽修','宋','宋诗','song-poetry','','[]','試問玉蟾寒皎皎，何如銀燭亂熒熒。',32,'全唐诗/poet.song.17000.json','["試問玉蟾寒皎皎，何如銀燭亂熒熒。", "不知桂魄今何在，應在吾家紫石屏。"]'),
('aafe4ba8-1991-4094-a49b-3f4ab3603eca','張仲通示墨竹嗣以嘉篇豈勝飲玩聊以四韻仰酬厚貺','歐陽修','宋','宋诗','song-poetry','','[]','數竿蒼翠寫生綃，寄我公齋伴寂寥。',64,'全唐诗/poet.song.17000.json','["數竿蒼翠寫生綃，寄我公齋伴寂寥。", "不待雪霜常凜凜，雖無風雨自蕭蕭。", "嗟予心志俱憔悴，羨子文章騁富饒。", "嗣以嘉篇誠厚貺，遠慚爲報乏瓊瑶。"]'),
('916fe4c8-24f8-49ec-b604-7f7a43dfa677','奉寄襄陽張學士兄','歐陽修','宋','宋诗','song-poetry','','[]','東津淥水南山色，夢寐襄陽二十年。',64,'全唐诗/poet.song.17000.json','["東津淥水南山色，夢寐襄陽二十年。", "顧我百憂今白首，羨君千騎若登仙。", "花開漢女游堤上，人看仙翁擁道邊。", "況有玉鍾應不負，夜槽春酒響如泉。"]'),
('29792e1f-0c7a-447b-a59e-b11fa8a62f01','奉答聖俞宿直見寄之作','歐陽修','宋','宋诗','song-poetry','','[]','寒夜分曹直，嚴城隔幾層。',48,'全唐诗/poet.song.17000.json','["寒夜分曹直，嚴城隔幾層。", "予慚批鳳詔，君歎守螢燈。", "病骨羸漳浦，官書蠹羽陵。", "無嫌學舍冷，文字比清冰。"]'),
('9137dc4a-58c3-4633-a222-ad28fbbb3511','和原甫舍人閣下午寢歸有作','歐陽修','宋','宋诗','song-poetry','','[]','遥知好睡紫微郎，枕簟清薰綠蕙芳。',64,'全唐诗/poet.song.17000.json','["遥知好睡紫微郎，枕簟清薰綠蕙芳。", "五色詔成人不到，萬年風動閣生涼。", "平時下直歸宜早，陋巷相過意未忘。", "楊子不煩多載酒，主人猶可具黄粱。"]'),
('b1cdd6fc-e5e9-4a61-ba92-2dd82acdf1e0','聞原甫久在病告有感','歐陽修','宋','宋诗','song-poetry','','[]','東城移疾久離居，安得疑蛇意盡祛。',64,'全唐诗/poet.song.17000.json','["東城移疾久離居，安得疑蛇意盡祛。", "諸老何爲讒賈誼，君王猶未識相如。", "浮沉俗喜隨時態，磊落材多與世踈。", "誰謂文章金馬客，翻同憔悴楚三閭。"]'),
('5dc8b967-ad2c-4939-a431-b6291c020c51','試筆','歐陽修','宋','宋诗','song-poetry','','[]','試筆消長日，躭書遣百憂。',48,'全唐诗/poet.song.17000.json','["試筆消長日，躭書遣百憂。", "餘生得如此，萬事復何求。", "黄犬可爲戒，白雲當自由。", "無將一抔土，欲塞九河流。"]'),
('6a64fb46-acc3-4f28-975f-66bd41416134','齋宮感事寄原甫學士','歐陽修','宋','宋诗','song-poetry','','[]','曾向齋宮詠麥秋，綠陰佳樹覆牆頭。',32,'全唐诗/poet.song.17000.json','["曾向齋宮詠麥秋，綠陰佳樹覆牆頭。", "重來滿地新霜葉，却憶初聞黄栗留。"]'),
('37429624-8693-4500-ae66-73416869971d','戲答仲儀口號','歐陽修','宋','宋诗','song-poetry','','[]','弊居回看如蛙穴，華宇來棲若燕身。',32,'全唐诗/poet.song.17000.json','["弊居回看如蛙穴，華宇來棲若燕身。", "敢望笙歌行樂事，只憂無米過來春。"]'),
('158a7d3e-f316-4758-9dac-01e323eeb984','觀龍圖閣三聖御書應制','歐陽修','宋','宋诗','song-poetry','','[]','層構嚴清禁，披圖爛寶文。',48,'全唐诗/poet.song.17000.json','["層構嚴清禁，披圖爛寶文。", "虹蜺光照物，龍鳳勢騰雲。", "妙極功歸一，真隨體自分。", "孝思遵寶訓，聖業廣惟勤。"]'),
('ab045c91-c429-4359-94bc-f92e2d680e49','題東閣後集','歐陽修','宋','宋诗','song-poetry','','[]','東閤三朝多大事，營丘二載足閑辭。',32,'全唐诗/poet.song.17000.json','["東閤三朝多大事，營丘二載足閑辭。", "近詩留作歸榮集，何日歸田自集詩。"]'),
('127b731b-7ece-4ff9-b551-5827c033db86','日長偶書','歐陽修','宋','宋诗','song-poetry','','[]','日長漸覺逍遥樂，何況終朝無事人。',32,'全唐诗/poet.song.17000.json','["日長漸覺逍遥樂，何況終朝無事人。", "安得遂爲無事者，人間萬慮不關身。"]'),
('57917693-713a-46a4-82d3-cec2d8f65bc5','寄答王仲儀太尉素','歐陽修','宋','宋诗','song-poetry','','[]','豐樂山前一醉翁，餘齡有幾百憂攻。',64,'全唐诗/poet.song.17000.json','["豐樂山前一醉翁，餘齡有幾百憂攻。", "平生自恃心無媿，直道誠知世不容。", "換骨莫求丹九轉，榮名豈在祿千鍾。", "明年今日如尋我，潁水東西問老農。"]'),
('ad33237e-b3dc-4141-910f-b52760c9d0eb','解官後答韓魏公見寄','歐陽修','宋','宋诗','song-poetry','','[]','報國勤勞已蔑聞，終身榮遇最無倫。',64,'全唐诗/poet.song.17000.json','["報國勤勞已蔑聞，終身榮遇最無倫。", "老爲南畝一夫去，猶是東宮二品臣。", "侍從籍通清切禁，笑歌行作太平民。", "欲知念舊君恩厚，二者難兼始兩人。"]'),
('f27c910a-3074-4d1b-8578-e448f2e58de8','余昔留守南都得與杜祁公唱和詩有答公見贈二十韻之卒章云報國如乖願歸耕寧買田期無辱知己肯逐利名遷逮今二十有二年祁公捐館亦十有五年矣而余始蒙恩得遂退休之請追懷平昔不勝感涕輒爲短句置公祠堂','歐陽修','宋','宋诗','song-poetry','','[]','掩涕發陳編，追思二十年。',48,'全唐诗/poet.song.17000.json','["掩涕發陳編，追思二十年。", "門生今白首，墓木已蒼煙。", "報國如乖願，歸耕寧買田。", "此言今始踐，知不愧黄泉。"]'),
('59a64416-fbb2-4040-bacd-ed72c325b4a0','答端明王尚書見寄兼簡景仁文裕二侍郎二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','日久都城車馬喧，豈知風月屬三賢。',64,'全唐诗/poet.song.17000.json','["日久都城車馬喧，豈知風月屬三賢。", "唱高誰敢投詩社，行處人爭看地仙。", "酒面撥醅浮大白，舞腰催拍趁繁絃。", "與公等是休官者，方把鋤犁學事田。"]'),
('833afb11-0a60-4138-aabd-21014a9a602e','答端明王尚書見寄兼簡景仁文裕二侍郎二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','多病新還太守章，歸來白首興何長。',64,'全唐诗/poet.song.17000.json','["多病新還太守章，歸來白首興何長。", "琴書自是千金產，日月閑銷百刻香。", "尚有俸錢酤美酒，自栽花圃趁新陽。", "醉翁生計今如此，一笑何時共一觴。"]'),
('21c2f37b-4107-4d76-8c41-67c1e7752ff9','寄題景純學士藏春塢新居','歐陽修','宋','宋诗','song-poetry','','[]','清才四紀擅時名，晚卜丘林遂解纓。',64,'全唐诗/poet.song.17000.json','["清才四紀擅時名，晚卜丘林遂解纓。", "欲借青春藏向此，須知白首尚多情。", "水浮花出人間去，山近雲從席上生。", "漫說市朝堪大隱，仙家誰信在重城。"]'),
('10fbb2f6-3620-412c-9db7-0cb99609c856','會老堂','歐陽修','宋','宋诗','song-poetry','','[]','古來交道愧難終，此會今時豈易逢。',64,'全唐诗/poet.song.17000.json','["古來交道愧難終，此會今時豈易逢。", "出處三朝俱白首，凋零萬木見青松。", "公能不遠來千里，我病猶堪釂一鍾。", "已勝山陰空興盡，且留歸駕爲從容。"]'),
('716b33ac-dfab-4700-9a22-341cf823502f','叔平少師去後會老堂獨坐偶成','歐陽修','宋','宋诗','song-poetry','','[]','積雨荒庭徧綠苔，西堂瀟灑爲誰開。',64,'全唐诗/poet.song.17000.json','["積雨荒庭徧綠苔，西堂瀟灑爲誰開。", "愛酒少師花落去，彈琴道士月明來。", "雞啼日午衡門靜，鶴淚風清晝夢回。", "野老但欣南畝伴，豈知名籍在蓬萊。"]'),
('943d5a43-b156-4e9c-927d-991504eb3a63','退居述懷寄北京韓侍中二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','悠悠身世比浮雲，白首歸來潁水濆。',64,'全唐诗/poet.song.17000.json','["悠悠身世比浮雲，白首歸來潁水濆。", "曾看元臣調鼎鼐，却尋田叟問耕耘。", "一生勤苦書千卷，萬事銷磨酒百分。", "放浪豈無方外士，尚思親友念離羣。"]'),
('abd67362-5644-4e2e-ada4-4352bf0d14d1','退居述懷寄北京韓侍中二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','書殿宮臣寵並叨，不同憔悴返漁樵。',64,'全唐诗/poet.song.17000.json','["書殿宮臣寵並叨，不同憔悴返漁樵。", "無窮興味閑中得，强半光陰醉裏銷。", "靜愛竹時來野寺，獨尋春偶過溪橋。", "猶須五物稱居士，不及顔回飲一瓢。"]'),
('4c5b1b87-096a-4199-8ee0-a1741b0a0023','贈潘道士','歐陽修','宋','宋诗','song-poetry','','[]','門無車轍紫苔侵，雞犬蕭條陋巷深。',32,'全唐诗/poet.song.17000.json','["門無車轍紫苔侵，雞犬蕭條陋巷深。", "寄語彈琴潘道士，雨中尋得越江吟。"]'),
('506c04e9-b376-4a36-be97-e482314f195e','答樞密吳給事見寄','歐陽修','宋','宋诗','song-poetry','','[]','老得閑來興味長，問將何事送餘光。',64,'全唐诗/poet.song.17000.json','["老得閑來興味長，問將何事送餘光。", "春寒擁被三竿日，宴坐忘言一炷香。", "報國愧無功尺寸，歸田仍值歲豐穰。", "樞庭任重才餘暇，猶有新篇寄草堂。"]'),
('dbd1bff0-c27a-4660-89c0-eb6e81eecbc3','答判班孫待制見寄','歐陽修','宋','宋诗','song-poetry','','[]','三朝竊寵幸逢辰，晚節恩深許乞身。',64,'全唐诗/poet.song.17000.json','["三朝竊寵幸逢辰，晚節恩深許乞身。", "無用物中仍老病，太平時得作閑人。", "鳴琴酌酒留嘉客，引水栽花過一春。", "惟恨江淹才已盡，難酬開府句清新。"]'),
('a3520fb0-f9a0-4164-bc3b-e5d9be36598c','初夏西湖','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','積雨新晴漲碧溪，偶尋行處獨依依。',64,'全唐诗/poet.song.17000.json','["積雨新晴漲碧溪，偶尋行處獨依依。", "綠陰黄鳥春歸後，紅蘤青苔人跡稀。", "萍匝汀洲魚自躍，日長欄檻燕交飛。", "林僧不用相迎送，吾欲臺頭坐釣磯。"]'),
('d59c3038-548d-4aa7-9327-631de680e958','寄河陽王宣徽','歐陽修','宋','宋诗','song-poetry','','[]','誰謂蕭條潁水邊，能令嘉客少留連。',64,'全唐诗/poet.song.17000.json','["誰謂蕭條潁水邊，能令嘉客少留連。", "肥魚美酒偏宜老，明月清風不用錢。", "況值湖園方首夏，正當櫻筍似三川。", "自知不及南都會，勉彊猶須詫短篇。"]'),
('18495352-d054-4a37-9da2-e167a0c78f39','寄韓子華','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人事從來無處定，世塗多故踐言難。',32,'全唐诗/poet.song.17000.json','["人事從來無處定，世塗多故踐言難。", "誰知潁水閑居士，十頃西湖一釣竿。"]'),
('b916c724-09e3-4625-9ce2-ba103aa4d33d','戲劉原甫  其一','歐陽修','宋','宋诗','song-poetry','','[]','平生志業有誰先，落筆文章海內傳。',32,'全唐诗/poet.song.17000.json','["平生志業有誰先，落筆文章海內傳。", "昨日都城應紙貴，開簾却扇見新篇。"]'),
('b4390910-e273-4343-92af-c4909a44f7d2','戲劉原甫  其二','歐陽修','宋','宋诗','song-poetry','','[]','仙家千載一何長，浮世空驚日月忙。',32,'全唐诗/poet.song.17000.json','["仙家千載一何長，浮世空驚日月忙。", "洞裏新花莫相笑，劉郎今是老劉郎。"]'),
('7ff4155a-89c1-48dc-beca-fc043a88ea0b','和子履遊泗上雍家園','歐陽修','宋','宋诗','song-poetry','','[]','長橋南走羣山間，中有雍子之名園。',128,'全唐诗/poet.song.17000.json','["長橋南走羣山間，中有雍子之名園。", "蒼雲蔽天竹色浄，暖日撲地花氣繁。", "飛泉來從遠嶺背，林下曲折寒波翻。", "珍禽不可見毛羽，數聲清絕如哀彈。", "我來據石弄瑟瑟，惟恐日暮登歸軒。", "塵紛解剝耳目異，祗疑夢入神仙村。", "知君襟尚我同好，作詩閎放莫可攀。", "高篇絕景兩不及，久之想像空冥煩。"]'),
('0ef485ec-e370-4ff4-9b29-6e8c27e8fe3b','詔重修太學詩','歐陽修','宋','宋诗','song-poetry','','[]','漢詔崇儒術，虞庠講帝猷。',72,'全唐诗/poet.song.17000.json','["漢詔崇儒術，虞庠講帝猷。", "叢楹新寶構，萬杵逐歡謳。", "照爛雲甍麗，回環璧水流。", "冠童儀盛魯，蒿柱德同周。", "舞翟彌文郁，橫經盛禮脩。", "微生聽昕鼓，願齒夏弦游。"]'),
('155a093b-d3a7-4118-bebb-aac2191c6136','翠旌詩','歐陽修','宋','宋诗','song-poetry','','[]','盛禮郊儀肅，純音帝樂清。',72,'全唐诗/poet.song.17000.json','["盛禮郊儀肅，純音帝樂清。", "葳蕤飄翠羽，赫奕展華旌。", "鳳邸光交覆，鸞旗色共明。", "繽紛拂葩蓋，輝映雜緌纓。", "且異文竿飾，非同翿舞名。", "竹宮歌毖祀，雅曲播遺聲。"]'),
('eed5ede0-f894-4f5f-8e2f-0c011d1da441','秋獮詩','歐陽修','宋','宋诗','song-poetry','','[]','豳籥迎寒至，商飚應節流。',72,'全唐诗/poet.song.17000.json','["豳籥迎寒至，商飚應節流。", "戎容修大獮，殺氣順行秋。", "多稼登方茂，三農隙始休。", "飲歸軍實獻，誓眾黻爲裘。", "索享儀非蠟，圍田禮異蒐。", "國威思遠播，神武暢皇猷。"]'),
('6069a605-17aa-483a-baf5-2901416a0462','博愛無私詩','歐陽修','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.17000.json','["無正文。"]'),
('1754e286-c184-40c3-8aee-e19eff4e5ab7','春帖子詞 皇帝閤六首 其一','歐陽修','宋','宋诗','song-poetry','','[]','萌牙資暖律，養育本仁心。',24,'全唐诗/poet.song.17000.json','["萌牙資暖律，養育本仁心。", "顧彼蒼生意，安知帝力深。"]'),
('02420d75-5e83-4f97-be8b-fe3a77ccdf4d','春帖子詞 皇帝閤六首 其二','歐陽修','宋','宋诗','song-poetry','','[]','陽進升君子，陰消退小人。',24,'全唐诗/poet.song.17000.json','["陽進升君子，陰消退小人。", "聖君南面治，布政法新春。"]'),
('15ba3125-813e-4171-a515-38d103116914','春帖子詞 皇帝閤六首 其三','歐陽修','宋','宋诗','song-poetry','','[]','氣候三陽始，勾萌萬物新。',24,'全唐诗/poet.song.17000.json','["氣候三陽始，勾萌萬物新。", "雷聲初發號，天下已知春。"]'),
('8da59df3-d4e7-4079-9209-d26437f3be6b','春帖子詞 皇帝閤六首 其四','歐陽修','宋','宋诗','song-poetry','','[]','玉琯氣來灰已動，東郊風至曉先迎。',32,'全唐诗/poet.song.17000.json','["玉琯氣來灰已動，東郊風至曉先迎。", "乾坤有信如符契，草木無知但發生。"]'),
('577e1f50-8401-493d-a2e8-42da61e2a262','春帖子詞 皇帝閤六首 其五','歐陽修','宋','宋诗','song-poetry','','[]','朝雲藹藹弄春暉，萬木欣欣暖尚微。',32,'全唐诗/poet.song.17000.json','["朝雲藹藹弄春暉，萬木欣欣暖尚微。", "造化未嘗私一物，各隨妍醜自芳菲。"]'),
('e5a174b5-d1df-40b8-871f-c8361be2756f','春帖子詞 皇帝閤六首 其六','歐陽修','宋','宋诗','song-poetry','','[]','熙熙人物樂春臺，風送春從天上來。',32,'全唐诗/poet.song.17000.json','["熙熙人物樂春臺，風送春從天上來。", "玉輦經年不遊幸，上林花好莫爭開。"]'),
('b995edd6-85cf-499d-ab69-462093ff3c2a','春帖子詞 皇后閤五首 其一','歐陽修','宋','宋诗','song-poetry','','[]','御水冰銷綠，宮梅雪壓香。',24,'全唐诗/poet.song.17000.json','["御水冰銷綠，宮梅雪壓香。", "新年賀交泰，白日漸舒長。"]'),
('ca87c5c0-5cb9-4da7-a2c8-3e571ca400a7','春帖子詞 皇后閤五首 其二','歐陽修','宋','宋诗','song-poetry','','[]','藹藹珠簾日，溶溶碧瓦煙。',24,'全唐诗/poet.song.17000.json','["藹藹珠簾日，溶溶碧瓦煙。", "漪漣采荇水，和暖浴蠶天。"]'),
('5244cd1a-dd48-4cf7-88da-6dfe935f48e0','春帖子詞 皇后閤五首 其三','歐陽修','宋','宋诗','song-poetry','','[]','初欣綵勝迎春早，已覺雞人報漏遲。',32,'全唐诗/poet.song.17000.json','["初欣綵勝迎春早，已覺雞人報漏遲。", "風色結寒猶料峭，天光煦物已融怡。"]'),
('51ab03f2-5469-4610-b150-28e4d1d20a10','春帖子詞 皇后閤五首 其四','歐陽修','宋','宋诗','song-poetry','','[]','鸎寒未報宮花發，風暖還催臘雪銷。',32,'全唐诗/poet.song.17000.json','["鸎寒未報宮花發，風暖還催臘雪銷。", "欲識春來自何處，先從天上斗回杓。"]'),
('620cfcf0-bcb1-48a3-929c-47c54d4ec2b2','春帖子詞 皇后閤五首 其五','歐陽修','宋','宋诗','song-poetry','','[]','三辰明潤琁璣運，四氣均調玉燭光。',32,'全唐诗/poet.song.17000.json','["三辰明潤琁璣運，四氣均調玉燭光。", "共喜新年獻椒酒，惟將萬壽祝君王。"]'),
('ff040cb2-fd15-401c-9688-7ebd0a2bf1a2','春帖子詞 溫成皇后閤四首 其一','歐陽修','宋','宋诗','song-poetry','','[]','璅窗珠戶暖生煙，不覺新春換故年。',32,'全唐诗/poet.song.17000.json','["璅窗珠戶暖生煙，不覺新春換故年。", "眾卉爭妍競時態，却尋遺跡獨依然。"]'),
('2778a2d7-abe9-468f-b87f-56aebcbc8d0f','春帖子詞 溫成皇后閤四首 其二','歐陽修','宋','宋诗','song-poetry','','[]','寶奩香歇掩鉛華，舊閤春歸老監嗟。',32,'全唐诗/poet.song.17000.json','["寶奩香歇掩鉛華，舊閤春歸老監嗟。", "畫棟重來當日燕，玉欄猶發去年花。"]'),
('3963a152-092d-44df-85b2-62ac36570794','春帖子詞 溫成皇后閤四首 其三','歐陽修','宋','宋诗','song-poetry','','[]','椒壁輕寒轉曉暉，珠簾不動暖風微。',32,'全唐诗/poet.song.17000.json','["椒壁輕寒轉曉暉，珠簾不動暖風微。", "可憐春色來依舊，惟有餘香散不歸。"]'),
('3f9d1260-05c9-424a-9922-f9ffe626491e','春帖子詞 溫成皇后閤四首 其四','歐陽修','宋','宋诗','song-poetry','','[]','內助從來上所嘉，新春不忍見新花。',32,'全唐诗/poet.song.17000.json','["內助從來上所嘉，新春不忍見新花。", "君王念舊憐遺族，常使無權保厥家。"]'),
