('70205cca-8dff-459d-bc73-97a1f3875ec6','芙蓉花二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','溪邊野芙蓉，花水相媚好。',24,'全唐诗/poet.song.17000.json','["溪邊野芙蓉，花水相媚好。", "半看池蓮盡，獨伴霜菊槁。"]'),
('6e9f7344-f877-4636-98c3-ad6c4d567f3a','芙蓉花二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','紅芳曉露濃，綠樹秋風冷。',24,'全唐诗/poet.song.17000.json','["紅芳曉露濃，綠樹秋風冷。", "共喜巧回春，不妨閑弄影。"]'),
('fc79b1ec-0fc5-4b7a-9026-2e47dc637890','詩一首','歐陽修','宋','宋诗','song-poetry','','[]','人言清禁紫薇郎，草詔紫薇花影傍。',32,'全唐诗/poet.song.17000.json','["人言清禁紫薇郎，草詔紫薇花影傍。", "山木不知官況味，也隨紅日上東廓。"]'),
('3ee679cb-4269-4d20-b244-66f7f6392bb1','詩一首','歐陽修','宋','宋诗','song-poetry','','[]','文出升平世，禾生大有年。',144,'全唐诗/poet.song.17000.json','["文出升平世，禾生大有年。", "四克今日月，六合古山川。", "反朴次三五，古文丁一千。", "王功因各定，大作不相沿。", "主化布于下，人心孚自天。", "上方求士切，公亦立仁先。", "才行苟并至，位名尤兩全。", "末由弓冶手，安比父兄肩。", "幸及布衣仕，宜希守令先。", "尺刀元並用，丹白具同研。", "去吏多甘老，休兵坐力田。", "干戈包已久，永卜本文延。"]'),
('50ba7995-c474-4c0f-a040-9c6049582612','句  其一','歐陽修','宋','宋诗','song-poetry','','[]','一句坐中得，片心天外來。',12,'全唐诗/poet.song.17000.json','["一句坐中得，片心天外來。"]'),
('a9e444fc-bbd9-4300-a2a7-8bace05b50ec','句  其二','歐陽修','宋','宋诗','song-poetry','','[]','焚香答進士，撤幕待經生。',12,'全唐诗/poet.song.17000.json','["焚香答進士，撤幕待經生。"]'),
('1b05ae47-7e6e-42c1-84a5-780c91906352','句  其三','歐陽修','宋','宋诗','song-poetry','','[]','最好花常最後開。',8,'全唐诗/poet.song.17000.json','["最好花常最後開。"]'),
('5b134ee6-b8b1-4c3a-b149-5b99fe86d89b','句  其四','歐陽修','宋','宋诗','song-poetry','','[]','萬枝黄落風如射，猶自傳聲欲噬人。',16,'全唐诗/poet.song.17000.json','["萬枝黄落風如射，猶自傳聲欲噬人。"]'),
('cf49d519-ccb5-4552-9c1e-8217d0bbac16','句  其五','歐陽修','宋','宋诗','song-poetry','','[]','蚤虱蚊虻罪一倫，未知蚊子重堪嗔。',16,'全唐诗/poet.song.17000.json','["蚤虱蚊虻罪一倫，未知蚊子重堪嗔。"]'),
