('af062a9d-d550-48d9-a3b7-01745bdcdc75','句  其七','歐陽修','宋','宋诗','song-poetry','','[]','奏邸獄冤誰與辨，高橋客死世通悲。',16,'全唐诗/poet.song.17000.json','["奏邸獄冤誰與辨，高橋客死世通悲。"]'),
('f7c063e3-cf01-4dd5-b13f-9049181e11a6','句  其八','歐陽修','宋','宋诗','song-poetry','','[]','尚記梨花村，依依聞暗香。',12,'全唐诗/poet.song.17000.json','["尚記梨花村，依依聞暗香。"]'),
('3c96a58d-e399-401d-8af6-978023e54196','句  其九','歐陽修','宋','宋诗','song-poetry','','[]','湖上野芙容，含思秋脈脈。',36,'全唐诗/poet.song.17000.json','["湖上野芙容，含思秋脈脈。", "娟娟如靜女，不肯傍阡陌。", "詩人杳未來，幽艷冷難宅。"]'),
('bc9c46c8-bb37-4534-972c-58dc5796717b','句  其一○','歐陽修','宋','宋诗','song-poetry','','[]','來時擘繭正探官。',8,'全唐诗/poet.song.17000.json','["來時擘繭正探官。"]'),
('b5f25706-988f-4283-9260-c56886e6cfab','句  其一一','歐陽修','宋','宋诗','song-poetry','','[]','奕奕天河光不斷，有人正在長生殿。',16,'全唐诗/poet.song.17000.json','["奕奕天河光不斷，有人正在長生殿。"]'),
('6b7ef1a1-cf00-4662-b88d-613f88b640fc','句  其一二','歐陽修','宋','宋诗','song-poetry','','[]','文章自古無憑據，唯願朱衣一點頭。',16,'全唐诗/poet.song.17000.json','["文章自古無憑據，唯願朱衣一點頭。"]'),
('73579074-3a3d-443d-bedc-9133904824a1','句  其一三','歐陽修','宋','宋诗','song-poetry','','[]','酒粘衫袖重，花壓帽簷偏。',12,'全唐诗/poet.song.17000.json','["酒粘衫袖重，花壓帽簷偏。"]'),
('add59e8d-80ca-4013-a6c2-80603be6ff27','題真定村寺','王素','宋','宋诗','song-poetry','','[]','寬猛三年無枉理，公私兼濟不欺心。',32,'全唐诗/poet.song.17000.json','["寬猛三年無枉理，公私兼濟不欺心。", "如今受代朝天去，遮路人人淚滿襟。"]'),
('1f21040b-7234-418f-a9b8-063693e89859','述夢','王素','宋','宋诗','song-poetry','','[]','似去華胥國裏來，雲霞深處見樓臺。',32,'全唐诗/poet.song.17000.json','["似去華胥國裏來，雲霞深處見樓臺。", "月光冷射雞窗急，驚覺遊仙夢一迴。"]'),
('8c2fec07-cac8-491c-9c77-3792ee3624b1','詩一首','王素','宋','宋诗','song-poetry','','[]','虛碧中藏白玉京，夢魂飛入黄金城。',32,'全唐诗/poet.song.17000.json','["虛碧中藏白玉京，夢魂飛入黄金城。", "何時再步烟霄外，皓齒仙童已掃廳。"]'),
('b8422a8d-36b5-4fae-8679-b1890e429924','嚴真觀','呂公弼','宋','宋诗','song-poetry','','[]','卜肆垂簾地，依然門徑開。',48,'全唐诗/poet.song.17000.json','["卜肆垂簾地，依然門徑開。", "沈冥時已往，思慕客猶來。", "鳥啄虛簷壞，狐穿古井摧。", "空餘舊磯石，歲歲長春苔。"]'),
('db42660d-8330-434a-bf53-1d91a86e0af5','琴臺','呂公弼','宋','宋诗','song-poetry','','[]','煙樹重城側，琴臺千古餘。',48,'全唐诗/poet.song.17000.json','["煙樹重城側，琴臺千古餘。", "早爲梁苑客，晚向茂陵居。", "賦給尚書筆，歸乘使者車。", "清風覿舊隱，長日聳鄉間。"]'),
('58dd4a48-a2e7-4e02-8cfe-b1053f18e58c','送桂州張田經略遷祠部','呂公弼','宋','宋诗','song-poetry','','[]','拂雲樓觀壯南城，符竹從來選擇精。',64,'全唐诗/poet.song.17000.json','["拂雲樓觀壯南城，符竹從來選擇精。", "地壓坤方諸國重，官遷漢省左曹清。", "霜嚴塞幕論兵略，春滿農效勸火畊。", "王佐才高時望治，歸來持橐上蓬瀛。"]'),
('59577805-198d-44fc-8e7a-f5967fac900f','和孔司封題蓬萊閣','沈立','宋','宋诗','song-poetry','','[]','拂雲高閣擬蓬萊，面向稽山鑑水開。',64,'全唐诗/poet.song.17000.json','["拂雲高閣擬蓬萊，面向稽山鑑水開。", "文舉清尊無限樂，微之佳句不勝才。", "屢嘗雪夜凭朱檻，幾對花天醉綠杯。", "明主未容休退去，會須重乞一麾來。"]'),
('8fe7cc27-92ab-4b48-a64b-c27c591653c9','判官廳新建壽樂堂','沈立','宋','宋诗','song-poetry','','[]','會稽四面是湖山，亭在湖山勝絕間。',64,'全唐诗/poet.song.17000.json','["會稽四面是湖山，亭在湖山勝絕間。", "欄檻旋移芳草種，襟懷長伴白雲閒。", "乍登頓覺詩毫健，縱賞惟憂酒量慳。", "更是人生最榮處，綵雲朝暮奉慈顔。"]'),
('3c22b038-615d-4650-8417-9da5f0541bb0','英韶在前徒矜下里之曲風雅未喪豈繫擊轅之音不圖綴綺靡之亂抑將導敦厚之旨耳海棠雖盛於蜀人不甚貴因暇偶成五言百韻律詩一章四韻詩一章附于卷末知我者無加焉  其一','沈立','宋','宋诗','song-poetry','','[]','岷蜀地千里，海棠花獨妍。',288,'全唐诗/poet.song.17000.json','["岷蜀地千里，海棠花獨妍。", "萬株佳麗國，二月豔陽天。", "叢萼勻如布，修蕤巧似編。", "彤雲輕點綴，赤玉碎雕鎸。", "瑟瑟光輸瑩，猩猩血借鮮。", "淺深相向背，疏密遞勾牽。", "輕蒨重重染，丹砂細細研。", "蕊纖金粟拱，鬚嫩紫絲拳。", "紅蠟隨英滴，明璣著顆穿。", "初莖爭裊娜，翹幹共蹁躚。", "絕代知無價，生香不減𥴈。", "分靈應桂苑，鍾粹定星躔。", "木帝經邦相，花王入室賢。", "祥飚加翦拂，卿靄共陶甄。", "真宰陰推轂，句芒與著鞭。", "不須憂薄命，好爲惜流年。", "贊翼施生柄，扶持煦嫗權。", "主張韶令正，調燮淑威宣。", "和氣高低洽，芳心次第還。", "金釵人十二，珠履客三千。", "雲雨迷巫峽，風波怨洛川。", "娉婷宜住楚，妖冶合居燕。", "繡被通宵展，華燈徹曙燃。", "橫披前檻外，半出假山巔。"]'),
('8c59d8fb-48bd-47b0-a09c-e32b72c10825','英韶在前徒矜下里之曲風雅未喪豈繫擊轅之音不圖綴綺靡之亂抑將導敦厚之旨耳海棠雖盛於蜀人不甚貴因暇偶成五言百韻律詩一章四韻詩一章附于卷末知我者無加焉  其二','沈立','宋','宋诗','song-poetry','','[]','占斷香與色，蜀花徒自開。',48,'全唐诗/poet.song.17000.json','["占斷香與色，蜀花徒自開。", "園要無即俗，蜂蝶落仍來。", "青帝若爲意，東風無限才。", "古今吟不盡，百韻愧空裁。"]'),
('5cde4d75-6abe-4e5d-9d0f-da844e7fb824','耆英會詩','王尚恭','宋','宋诗','song-poetry','','[]','端朝風望兩台星，珪組參差又十人。',96,'全唐诗/poet.song.17000.json','["端朝風望兩台星，珪組參差又十人。", "八百喬年餘總數，一千熙運遇良辰。", "席間韻語皆非俗，圖上形容盡得真。", "勝事主盟開府盛，誤容衰薄混清塵。", "服許便衣更野逸，坐從齒列似天倫。", "二公笑語增和氣，夜久盤花旋發春。"]'),
('b995c6f5-3e4f-4ca8-b22f-09b2a0ce6e9f','和','王尚恭','宋','宋诗','song-poetry','','[]','窩名安樂已詼諧，更賦新詩訟所乖。',64,'全唐诗/poet.song.17000.json','["窩名安樂已詼諧，更賦新詩訟所乖。", "豈以達爲賢事業，自知安是道梯階。", "權門富室先藏跡，好景良朋亦放懷。", "應照先生純粹處，肯揮妙墨記西齋。"]'),
('867dab75-ee8c-4190-92a9-adbcd45d5016','上仁宗皇帝乞還山偈','釋懷璉','宋','宋诗','song-poetry','','[]','千簇雲山萬壑流，閑身歸老此峰頭。',32,'全唐诗/poet.song.17000.json','["千簇雲山萬壑流，閑身歸老此峰頭。", "殷勤願祝如天壽，一炷清香滿石樓。"]'),
('7606b799-d5bf-41d0-9dc9-c5a4aef178ba','頌','釋懷璉','宋','宋诗','song-poetry','','[]','六載皇都唱祖機，兩曾金殿奉天威。',32,'全唐诗/poet.song.17000.json','["六載皇都唱祖機，兩曾金殿奉天威。", "青山隱去欣何得，滿篋惟將御頌歸。"]'),
('ff49f153-bffe-497e-b1d5-b1e9ca1112f6','萬春院  其一','釋懷璉','宋','宋诗','song-poetry','','[]','晚憑又閣望西東，細雨微烟澹碧空。',32,'全唐诗/poet.song.17000.json','["晚憑又閣望西東，細雨微烟澹碧空。", "造物使誰勻畫手，山川平遠有無中。"]'),
('a9624a2c-cc4b-489b-953d-7df7785b20c6','萬春院  其二','釋懷璉','宋','宋诗','song-poetry','','[]','午齋香飯本盂耕，坐向孤庵思愈清。',32,'全唐诗/poet.song.17000.json','["午齋香飯本盂耕，坐向孤庵思愈清。", "下目平原千萬里，稻花風自掌中生。"]'),
('edacc330-e9f3-45a3-afbb-5e0749e99b8d','白雲謠送明教嵩禪師歸山','釋懷璉','宋','宋诗','song-poetry','','[]','白雲人間來，不雜飛埃色。',72,'全唐诗/poet.song.17000.json','["白雲人間來，不雜飛埃色。", "遥爍太陽輝，萬態情何極。", "嗟嗟輕肥子，見擬垂天翼。", "圖南誠有機，去當六月息。", "寧知絪縕采，無心任吾適。", "天宇一何遼，舒卷非留迹。"]'),
('282ab74c-c55d-4379-a68b-7a00091bf249','句','釋懷璉','宋','宋诗','song-poetry','','[]','堯仁況是如天闊，乞與孤雲自在飛。',16,'全唐诗/poet.song.17000.json','["堯仁況是如天闊，乞與孤雲自在飛。"]'),
('b4bdbb32-65e8-4aed-813e-0389e806190a','偈','釋顯殊','宋','宋诗','song-poetry','','[]','黄梅席上數如麻，句裏呈機事可嗟。',32,'全唐诗/poet.song.17000.json','["黄梅席上數如麻，句裏呈機事可嗟。", "直是本來無一物，青天白日被雲遮。"]'),
('583212e3-96b8-4bac-bb47-92ec3a06dd28','偈','釋守億','宋','宋诗','song-poetry','','[]','馬祖纔陞堂，雄峰便卷席。',24,'全唐诗/poet.song.17000.json','["馬祖纔陞堂，雄峰便卷席。", "春風一陳來，滿地花狼藉。"]'),
('87c06eec-84dd-4ae5-bd28-fff55dea9d12','六快活詩','王揆','宋','宋诗','song-poetry','','[]','湖外風物奇，長沙信難續。',156,'全唐诗/poet.song.17000.json','["湖外風物奇，長沙信難續。", "衡峰排古青，湘水湛寒綠。", "舟檝通大江，車輪會平陸。", "昔賢官是邦，仁澤流豐沃。", "今賢官是邦，刳啗人脂肉。", "懷昔甘棠化，傷今猛虎毒。", "然此一邦內，所樂人纔六。", "漕與二憲僚，守連兩通屬。", "高堂日成會，深夜繼以燭。", "幃幕皆綺紈，器皿盡金玉。", "歌喉若珠纍，舞腰如素束。", "千態與萬狀，六官懽不足。", "因成快活詩，薦之堯舜目。"]'),
('36ee6c6b-dc62-47a0-b579-191aba963327','題江州琵琶亭','史沆','宋','宋诗','song-poetry','','[]','坐上騷人雖有詠，江邊寡婦不難欺。',32,'全唐诗/poet.song.17000.json','["坐上騷人雖有詠，江邊寡婦不難欺。", "若使王涯聞此曲，織羅應過賞花詩。"]');
